INSERT INTO diagnosis_quizzes (question, choice_1, choice_2, choice_3, choice_4, correct_answer) VALUES
  ('トレードで退場する人のほとんどの原因は何ですか？', '手法が悪かったから', '1回の負けが大きすぎたから', '運が悪かったから', '証券会社が悪いから', 2),
  ('1回のトレードで失っていい金額は総資金の何%までですか？', '10%', '5%', '2%', '1%', 3),
  ('損切り後に最初にやるべきことは何ですか？', 'すぐに次のトレードに入る', '少なくとも30分チャートから離れる', 'SNSで愚痴を書く', 'ロットを上げて取り返す', 2),
  ('STRADAとは何を意味する言葉ですか？', '日本語で「勝利」', 'イタリア語で「道」', '英語で「戦略」', 'ドイツ語で「分析」', 2),
  ('相場の7割はどんな状態ですか？', '上昇トレンド', '下降トレンド', 'レンジ', 'ブレイクアウト', 3);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(1, '個人投資家の退場理由として、統計的に最も多い原因はどれですか？', '1回の損失が大きすぎて資金を失うこと', '分析手法の知識が不足していること', '取引手数料やスプレッドの負担が大きいこと', '市場の変動が予想より激しすぎること', 1, '個人投資家の退場原因は「下手だから」ではなく「1回の負けが大きすぎたから」です。分析力や知識以前に、損失のコントロールができていないことが最大の要因です。', false, 1),
(1, '100万円の資金で50万円の損失を出した後、元の100万円に戻すために必要なリターン率はいくらですか？', '約50%', '100%', '約67%', '約150%', 2, '残った50万円を100万円に戻すには、残資金を2倍にする必要があります。損失が大きくなるほど回復に必要なリターンは非対称的に跳ね上がります。', false, 2),
(1, 'トレードで「利益が出たら早く確定し、損失が出たら先延ばしする」パターンを引き起こす認知バイアスはどれですか？', 'サンクコスト効果', '確証バイアス', '損失回避バイアス', 'バンドワゴン効果', 3, '損失回避バイアスにより、人間は損失の痛みを利益の喜びより強く感じます。そのため利益は早く確定して安心し、損失は先延ばしして痛みを避けようとします。', false, 3),
(1, 'プロスペクト理論が説明する人間の意思決定の特徴として正しいものはどれですか？', '人間は利益場面でも損失場面でも同じようにリスクを回避する', '人間は利益場面ではリスクを好み、損失場面ではリスクを回避する', '人間は期待値がプラスなら常に合理的な判断を下す', '人間は利益場面ではリスクを回避し、損失場面ではリスクを好むようになる', 4, 'プロスペクト理論によれば、人は利益が確定している場面では確実な利益を優先（リスク回避）し、損失が発生している場面では逆転を狙ってリスクを取る（リスク追求）傾向があります。これがトレードにおける「利小損大」を生み出します。', false, 4),
(1, 'トレードにおける「退場」とは、具体的にどのような状態を指しますか？', '資金が減りすぎて実質的にトレードを継続できなくなった状態', '証券会社の口座を解約して投資をやめること', '一度負けて精神的ショックで二度と相場を見なくなること', '利益が出せずに他の投資先へ資金を移すこと', 1, '退場とは、資金が減少しすぎてトレードを継続できなくなった状態です。口座を解約するかどうかに関わらず、実質的に取引を続けられなくなった時点で退場です。', false, 5),
(1, '退場パターンのうち、最も多いとされるのはどれですか？', '一発退場型 — レバレッジ等で一度の暴落で資金の大半を失う', 'ジリ貧型 — 毎回少しずつ負けて気づいたら資金が大きく減っている', '休眠型 — 大きな負けを経験して精神的に相場から遠ざかる', '情報不足型 — 投資知識が足りずに根拠のないトレードを繰り返す', 2, '最も多い退場パターンはジリ貧型です。一回の損失は小さくても利益より損失の方が常に大きい状態が続き、気づいた時には資金が大きく減っているため、発見が遅れがちです。', false, 6),
(1, 'トレードにおいて「メンタルが強い」とは、どういう状態を指しますか？', '損失を全く感情的に感じない状態', '負けてもすぐに次のトレードで大きなリスクを取れる状態', '利益確定や損切りのルールを感情に左右されずに実行できる状態', 'どんなに連敗しても自分の手法を一切疑わない状態', 3, 'メンタルの強さとは感情の有無ではなく、感情があってもルール通りに実行できる状態です。メンタルは強い弱いではなく「理解しているかどうか」の問題であり、仕組みを理解した上で行動できることが重要です。', false, 7),
(1, 'トレードで「知識はあるのに勝てない」状態を引き起こす2つの主な原因はどれですか？', '(1) メンタルが弱すぎる (2) テクニカル分析が不足している', '(1) 資金管理を学んでいない (2) ファンダメンタルズの知識が足りない', '(1) 取引回数が多すぎる (2) 利益目標が高すぎる', '(1) 学ぶ順番が間違っている (2) 知識が体験と結びついていない', 4, '知識と実行のギャップは「学ぶ順番が間違っていること」と「知識が実際の体験と結びついていないこと」の2つが原因です。「わかっている」と「できる」は別ものであり、実践と振り返りのサイクルを通じて初めて定着します。', false, 8),
(1, '現状維持バイアスがトレードに与える影響として最も当てはまるものはどれですか？', '含み損を抱えたポジションをそのまま保有し続け、損切りの判断を先延ばしする', '新しい分析方法を試そうとせず、同じ手法を使い続けてしまう', '利益が出ているポジションを持ち続けてしまい、利益を伸ばしすぎる', '常に新しい銘柄に乗り換えてしまい、一つの銘柄を持ち続けられない', 1, '現状維持バイアスにより、人は現在の状態（保有しているポジション）を維持しようとする傾向があります。これが損切りを先延ばしする行動につながり、小さな損失を大きな損失に育ててしまいます。', false, 9),
(1, 'トレードにおける「利小損大」のパターンが起きるメカニズムとして正しい説明はどれですか？', '利益が小さい銘柄を選んでしまう傾向があるため', '利益を早く確定し損失を先延ばしする行動が、結果として小さな利益と大きな損失を生むため', '手数料やスプレッドの影響で利益が削られ損失が膨らむため', 'エントリータイミングが遅すぎて利益区間が短くなるため', 2, '人間の脳の仕組みにより利益は早く確定して安心したい（利小）、損失は先延ばしして痛みを避けたい（損大）という行動をとりやすく、これが繰り返されるとトータルで損失が膨らみます。', false, 10),
(1, 'トレードの成長プロセスとして正しい順番はどれですか？', '勝てるトレーダー → 負けないトレーダー → 負けトレーダー', '負けトレーダー → 勝てるトレーダー → 負けないトレーダー', '負けトレーダー → 負けないトレーダー → 勝てるトレーダー', '負けないトレーダー → 負けトレーダー → 勝てるトレーダー', 3, '成長は「負けトレーダー → 負けないトレーダー → 勝てるトレーダー」の順です。まず大きな損失を防ぐ「負けないトレーダー」を目指し、その土台の上に「勝ち方」を積み上げていくのが正しい成長プロセスです。', false, 11),
(1, '投資で「負けないトレーダー」になるために最優先で学ぶべきことはどれですか？', '高い勝率を誇るエントリーポイントの見つけ方', 'チャートパターンの正確な読み取り方', 'ファンダメンタルズ分析による銘柄選び', '負け方 — 損失を小さく抑える方法', 4, '「勝ち方」より先に「負け方」を学ぶことが最優先です。大きな損失を防ぎ、小さな負けだけで済ませる技術が、トレードの土台として最初に身につけるべきスキルです。', false, 12),
(1, '100万円の資金で2万円の損失を出した場合、元に戻すために必要なリターン率は約何%ですか？', '約2%', '約0.5%', '約4%', '約1%', 1, '98万円を100万円に戻すには約2.04%のリターンで済みます。損失を小さく抑えることで回復のハードルを低く保つことができます。', false, 13),
(1, '30%の損失を取り戻すために必要なリターン率は約何%ですか？', '約30%', '約42.9%', '約35%', '約38%', 2, '30%の損失を回復するには約42.9%のリターンが必要です。損失率が増えるにつれて回復率は非対称的に増加し、30%を超えると回復のハードルが急激に高くなります。', false, 14),
(1, '「一発退場型」の退場パターンを防ぐために最も有効な対策はどれですか？', '常に複数の銘柄に分散投資する', '下落局面では買いポジションを持たない', '1回のトレードで投入する資金の割合を制限する', '経験を積んでからレバレッジを使う', 3, '一発退場は1回のトレードで資金の大部分を失うことで起きます。1回あたりの取引サイズを資金の数%以内に制限することで、単一のトレードで退場するリスクを防ぐことができます。', false, 15),
(1, 'トレードで「負けること自体は悪くない。負け方が問題」という言葉が意味する内容はどれですか？', '負けた理由を分析すれば勝率は上がるので、負けは学習材料として有益である', 'トレードでは負けることが前提なので、負けを恐れずに積極的にエントリーすべきである', '小さな負けを繰り返すのは問題なく、大きな利益でまとめて取り戻せばよい', '1回の負けで口座に与えるダメージを小さく抑えれば、負けは致命傷にならない', 4, 'トレードで負けること自体は避けられません。重要なのは1回の負けが口座に与えるダメージを小さく抑えることで、負けが致命傷にならなければ継続してトレードできます。', false, 16),
(1, '70%の損失を出した場合、元の資金額に戻すために必要なリターン率は約何%ですか？', '約233%', '約70%', '約150%', '約100%', 1, '70%損失した残資金を元に戻すには約233%のリターンが必要です。損失が50%を超えると回復は現実的に極めて困難になり、退場の可能性が非常に高くなります。', false, 17),
(1, 'ドローダウンと回復の非対称性において、20%の損失を取り戻すために必要なリターン率は約何%ですか？', '約20%', '約25%', '約22%', '約30%', 2, '20%損失した資金を回復するには25%のリターンが必要です。損失率と回復率は1対1ではなく、損失が大きくなるほど回復に必要な率は加速度的に増えます。', false, 18),
(1, 'ドローダウン5%の損失を回復するために必要なリターン率は約何%ですか？', '約5%', '約6%', '約5.3%', '約7%', 3, '5%の損失を回復するには約5.3%のリターンが必要です。損失率が小さいうちは回復率との差も小さく抑えられますが、損失が大きくなるにつれてその差は拡大します。', false, 19),
(1, 'トレードで「学ぶ順番が間違っている」とは、具体的にどのような状況を指しますか？', '基礎的なチャート分析より、高度なアルゴリズム取引から学び始めること', '外国の投資書籍より、国内の投資情報を優先して学んでいること', '過去の投資名著より、最新の投資ツールの使い方を先に学んでいること', 'テクニカル指標やエントリ手法を先に学び、資金管理や損切りの仕組みを後回しにしていること', 4, '多くの投資家は「勝つための手法」を先に学び、「負けないための資金管理」を後回しにします。土台となる損失コントロールを学ぶ前に手法に手を出すと、結果的に大きな損失を抱える原因になります。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(2, 'プロスペクト理論によれば、人間は利益の喜びと損失の痛みをどのように感じますか？', '損失の痛みを利益の喜びより約2倍強く感じる', '金額が大きくなるほど利益の喜びが損失の痛みを上回る', '利益の喜びを損失の痛みより約2倍強く感じる', '利益の喜びも損失の痛みもほぼ同じ強さで感じる', 1, 'プロスペクト理論によれば、人間は損失から受ける痛みを同等額の利益から得る喜びの約2倍強く感じます。これが損失を先延ばしする行動の根本原因です。', false, 1),
(2, '含み損を抱えたトレーダーが「損切りしたいが、まだ戻るかもしれない」と損切りを先延ばしする心理的メカニズムとして最も適切なものはどれですか？', '確証バイアス — 都合の良い情報だけを集めて判断が歪む', '保有効果 — 持っているものを過大評価して手放せなくなる', 'サンクコスト — すでに使ったコストを無駄にしたくない心理', '損失回避 — 損失の痛みを確定させたくない心理', 4, '含み損を確定させる＝損失の痛みを確定させるため、脳はその痛みを先送りしようとします。これが「まだ戻るかも」という損切り先延ばしにつながります。', false, 2),
(2, '「1万円もらった嬉しさ」を「50」とした場合、「1万円失った痛み」はプロスペクト理論に基づくとどの程度に相当しますか？', '約200', '約25', '約100', '約50', 3, '損失の痛みは利益の喜びの約2倍強く感じるため、嬉しさが「50」なら痛みは「100」に相当します。この非対称性がトレード行動を大きく歪めます。', false, 3),
(2, '含み益が出ているポジションで「利益を失いたくない」と早すぎる利確をしてしまう原因は何ですか？', '損失回避性によって利益を失う痛みを恐れ、確定させて安心を得ようとするため', '確証バイアスによって利益確定の根拠ばかりが目に入るため', 'サンクコスト効果によってすでに得た利益を無駄にしたくないため', '保有効果によってポジションの価値を過小評価してしまうため', 1, '含み益はまだ確定していない利益ですが、脳はすでに「自分のもの」と感じ、それを失う痛みを恐れます。その結果、本来の利確ポイントに達する前に利益を確定させたくなります。', false, 4),
(2, '損失回避性により「利小損大」のパターンが完成する理由として正しいものはどれですか？', '含み損では損切りを先延ばし、含み益では早く利確したくなるため、結果的に利益より損失が大きくなるため', 'テクニカル分析の精度が不足しており、エントリーポイントが悪くなるため', '利益を最大化しようとする欲求と損失を最小化しようとする理性が競合するため', '人間が本能的に高リスク・高リターンを好むため、利確を急いで大きな賭けに向かうため', 1, '含み損では「まだ戻るかも」と損切りを先延ばし、含み益では「失いたくない」と早めに利確する傾向が組み合わさることで、結果的に小さな利益と大きな損失が繰り返されるパターンが完成します。', false, 5),
(2, '「この銘柄は上がる」と決めてからチャートを分析すると、上がる根拠ばかりが目に入ってしまう現象を何と呼びますか？', '保有効果', '確証バイアス', 'サンクコストの罠', '損失回避性', 2, '確証バイアスとは、自分が信じていることを裏付ける情報ばかりを集め、反する情報を無視してしまう認知バイアスです。先に結論を決めてから分析すると、その結論を支持する情報だけが目に入ります。', false, 6),
(2, '確証バイアスに対する有効な対策として正しいものはどれですか？', '複数のテクニカル指標を組み合わせて分析の精度を上げる', '自分の分析に反対する意見を持つトレーダーと議論する', '過去のトレード履歴を振り返ってパターンを見つける', '分析は「チャートが何を語っているか」から始める', 4, '「買いたい」から分析するのではなく、「チャートが何を語っているか」から分析を始めることで、結論ありきの見方を避け、より客観的な判断ができるようになります。', false, 7),
(2, '「もうここまで耐えたのだから、ここで損切りしたらこれまでの我慢が無駄になる」という思考は、どの心理的罠に分類されますか？', 'サンクコストの罠', '確証バイアス', 'プロスペクト理論', '保有効果', 1, 'サンクコストの罠とは、すでに失ったお金や時間に引きずられて判断が歪む現象です。過去に使ったコストとこれからの判断は本来無関係ですが、「これまでの我慢を無駄にしたくない」という感情が損切りを先延ばしさせます。', false, 8),
(2, 'サンクコストの罠について正しい説明はどれですか？', '他人の投資行動に影響されて、自分の判断を見失う現象', '過去に投じたコストとこれからの判断は本来無関係であるにもかかわらず、過去のコストに引きずられて判断が歪む現象', '将来のリターンを過大評価して、現在の損失を軽く見てしまう現象', '短期的な利益に目がくらんで、長期的なリスクを見落とす現象', 2, 'サンクコスト（埋没費用）はすでに失われたものであり、これからの判断には関係ありません。しかし人間は「ここまで費やしたのだから」と過去のコストに縛られ、損切りを先延ばししてしまいます。', false, 9),
(2, 'ある大学で行われたマグカップの実験で、マグカップを与えられたグループは、与えられなかったグループと比べてどのような結果になりましたか？', 'マグカップの価値を約半分と評価した', 'マグカップの価値をほぼ変わりなく評価した', 'マグカップの価値を約2.5倍の値段と評価した', 'マグカップの価値を約1.5倍の値段と評価した', 3, 'マグカップの実験では、持っているグループは持っていないグループの約2.5倍の値段をつけました。自分が所有しているものを実際より高く評価する傾向を保有効果と呼びます。', false, 10),
(2, '保有効果がトレードにおいて危険な理由として最も適切なものはどれですか？', 'ポジションを持つと分析能力が物理的に低下するため', 'ポジションを持つと「手放す＝価値を失う」と感じ、損切りできなくなるため', '保有効果があるとエントリーのタイミングが遅くなるため', '保有効果によって利益目標が低すぎる値に設定されてしまうため', 2, 'ポジションを持った瞬間に保有効果が働き、そのポジションを実際の価値より高く評価してしまいます。その結果、「手放す＝価値を失う」と感じて損切りができなくなります。', false, 11),
(2, '含み損を抱えた状態から損失が拡大していく「破滅パターンの連鎖」として正しい流れはどれですか？', '含み損 → サンクコスト → 保有効果 → 損失拡大 → リベンジ心理 → 暴走', '含み損 → 保有効果 → 確証バイアス → 損失拡大 → 諦め', '含み損 → リベンジ心理 → サンクコスト → 損失拡大 → 保有効果 → 暴走', '含み損 → 損失拡大 → 確証バイアス → サンクコスト → 保有効果 → 冷静化', 1, '含み損を抱えると「これまで耐えたのだから」とサンクコストに縛られ、保有効果でポジションを過大評価し、損失が拡大するとリベンジ心理が生じて暴走に至るという連鎖が起きます。', false, 12),
(2, 'トレードにおける4つの暴走感情の組み合わせとして正しいものはどれですか？', '恐怖・怒り・焦り（FOMO）・嫉妬', '恐怖・欲望・焦り（FOMO）・後悔', '不安・欲望・焦り（FOMO）・後悔', '恐怖・欲望・退屈・後悔', 2, 'トレードにおける4つの暴走感情は「恐怖」「欲望」「焦り（FOMO）」「後悔」です。これらは冷静な判断を奪い、ルールを無視した行動を引き起こします。', false, 13),
(2, '「メタ認知」とは何をすることですか？', '過去のトレード結果を統計的に分析して弱点を見つけること', '市場の参加者の心理を予測して先手を取る分析手法', '自分が今何を感じているかを一歩引いて観察する技術', '瞑想や深呼吸で感情を完全に消し去る訓練', 3, 'メタ認知とは、自分自身の感情や思考を一歩引いて客観的に観察する技術です。「今、焦りを感じているな」と気づくこと自体がメタ認知の働きです。', false, 14),
(2, 'メタ認知を使って暴走感情に対処する3ステップとして正しい順序はどれですか？', '(1)距離を置く (2)気づく (3)ルールに戻る', '(1)ルールに戻る (2)気づく (3)距離を置く', '(1)気づく (2)距離を置く (3)ルールに戻る', '(1)感情を抑え込む (2)深呼吸する (3)エントリーする', 3, 'メタ認知の3ステップは「(1)気づく」「(2)距離を置く」「(3)ルールに戻る」の順です。まず自分の感情に気づき、その感情と距離を置いてから、自分のトレードルールに沿った行動に戻ります。', false, 15),
(2, '含み損を抱えているトレーダーが「もうここまで損が拡大したのだから、さらにポジションを追加して平均単価を下げよう」と考える場合、作用している心理的罠の組み合わせとして最も適切なものはどれですか？', '保有効果と確証バイアス', '損失回避性と保有効果', 'サンクコストと損失回避性', '確証バイアスとサンクコスト', 3, '「ここまで損が拡大した」と過去の損失（サンクコスト）に縛られつつ、損失を確定させる痛みから逃れるために（損失回避性）ポジションを追加する行動は、2つの罠が同時に作用しています。', false, 16),
(2, 'ポジションを持っているかどうかにかかわらず、自分が下すべき判断を客観的に見極めるための問いかけとして最も有効なものはどれですか？', '「このポジションの含み損はどこまで耐えられるか？」', '「この銘柄の今後の見通しは強気か弱気か？」', '「過去に同じパターンでどうなったか？」', '「もし今、ポジションを持っていなかったら、このレートでエントリーするか？」', 4, '「もし今、ポジションを持っていなかったら、このレートでエントリーするか？」と問うことで、保有効果やサンクコストの影響を排除し、純粋にチャートの現状から判断を下すことができます。', false, 17),
(2, '「もし今ポジションを持っていなかったら、このレートでエントリーするか？」という問いに対して答えが「いいえ」だった場合、取るべき行動として正しいものはどれですか？', '含み損が小さいうちに損切りする', '損切りラインを少しだけ下方に修正する', '新たな根拠が見つかるまで待機する', 'ポジションを手放す', 4, '答えが「いいえ」なら、現在そのレートで新規にエントリーする根拠はありません。保有しているポジションであっても、同じ基準で判断すれば手放すべきです。', false, 18),
(2, 'FOMO（Fear Of Missing Out）に駆られてエントリーしたトレーダーの典型的なパターンとして最もよくあるものはどれですか？', '相場が停滞している時にエントリーし、長期間膠着状態になる', '相場が大きく動いた後にエントリーし、反落で含み損を抱える', '相場の天井でショートを入れ、さらに上昇して含み損が拡大する', '相場が反転した直後にエントリーし、トレンドに乗って利益が出る', 2, 'FOMOは「乗り遅れる恐怖」から、すでに大きく動いた後の相場に飛び乗ってしまう行動です。タイミングが遅いため、その後の反落で含み損を抱えるケースが典型的です。', false, 19),
(2, 'チャート分析を行う際に「この銘柄を買いたい」という先入観を持った状態で分析を始めると、どのような結果になりやすいですか？', '買いの根拠と売りの根拠を同等に見つけ、判断に迷う', 'チャートパターンの認識精度が向上し、エントリーポイントが良くなる', '売りの根拠に敏感になり、エントリーを見送る可能性が高まる', '買いの根拠ばかりが目に入り、リスクを見落とした判断をする', 4, '先に「買いたい」という結論を持つと確証バイアスが働き、買いを支持する情報ばかりに注目し、売りを示唆する情報を無視してしまいます。これがリスクを見落とす原因になります。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(3, '2%ルールが示す内容として正しいものはどれですか？', '1回のトレードで得る利益は総資金の2%以上にする', '総資金のうち2%以上を常に現金で保有しておく', '1日の取引回数を総資金の2%に相当する回数までに制限する', '1回のトレードで失っていい金額は、総資金の2%まで', 4, '2%ルールは、1回のトレードで許容できる最大損失額を総資金の2%までに抑えるという資金管理の基本ルールです。これにより、1回の負けで口座に壊滅的なダメージが及ぶのを防ぎます。', false, 1),
(3, '2%ルールで運用した場合、10連敗した後に残っている資金の割合は約何%ですか？', '約82%', '約67%', '約90%', '約72%', 1, '2%ルールでは1回の負けで資金の98%が残るため、10連敗後は0.98の10乗で約81.7%が残ります。10連敗しても資金の約82%が残るため、トレードを継続する力が保たれます。', false, 2),
(3, 'リスク率5%で20連敗を喫した場合、残る資金の割合は約何%ですか？', '約12%', '約36%', '約50%', '約67%', 2, 'リスク率5%で1回の負けごとに資金の95%が残るため、20連敗後は0.95の20乗で約35.8%が残ります。リスク率が少し上がるだけで、連敗時のダメージは劇的に増大します。', false, 3),
(3, '資金100万円で2%ルールを適用した場合、1回のトレードで許容できる最大損失額はいくらですか？', '1万円', '5万円', '2万円', '10万円', 3, '最大リスク額＝総資金×2%で計算します。100万円×2%＝2万円が1回のトレードで失っていい上限です。この金額を超えるリスクは取らないことが資金管理の鉄則です。', false, 4),
(3, 'ロット計算の正しい手順として正しいものはどれですか？', '総資金÷株価でロット数を出してから損切り幅を決める', '希望するロット数に合わせて損切り幅を調整する', '直近の平均利益額から逆算してロット数を決める', '最大リスク額を算出し、それを損切り幅で割ってロット数を出す', 4, 'ロット計算は「最大リスク額＝総資金×2%」を求め、「ロット＝最大リスク額÷損切り幅」で導きます。損切り幅はエントリーの根拠に基づいて先に決まるものであり、ロットに合わせて調整するべきではありません。', false, 5),
(3, '資金100万円で損切り幅が500円の銘柄を取引する場合、2%ルールに基づく適正ロット数は何株ですか？', '10株', '20株', '40株', '80株', 3, '最大リスク額は100万円×2%＝2万円。ロット＝2万円÷500円＝40株です。損切りに引っかかっても2万円の損失で済むロット数が40株になります。', false, 6),
(3, '資金100万円で損切り幅が1,000円の銘柄を取引する場合、2%ルールでの適正ロット数は何株ですか？', '10株', '20株', '40株', '50株', 2, '最大リスク額は2万円。ロット＝2万円÷1,000円＝20株です。損切り幅が大きい銘柄ほどロット数を減らす必要があり、同じ資金でも銘柄ごとに適正ロットは変わります。', false, 7),
(3, 'トレード中に「心臓がバクバクする」「仕事が手につかない」「夜スマホでチャートを見てしまう」ような状態になった場合、最も考えられる原因はどれですか？', 'ロットが大きすぎる', '分析手法が間違っている', 'メンタルが弱い', '銘柄選びが悪い', 1, 'トレード中に強い不安やストレスを感じるのは、分析やメンタルの問題ではなく、単にロットが大きすぎることが原因です。適正ロットであれば感情的な動揺は大幅に軽減されます。', false, 8),
(3, '「夜、ぐっすり眠れるロット数」が意味するものとして正しいものはどれですか？', '寝ている間にシステムトレードで利益を出せるロット数', '資金効率を最大化するための最小ロット数', '初心者が最初に設定すべき固定ロット数', '自分にとっての現在の適正ロットの基準', 4, '「夜ぐっすり眠れるかどうか」は、そのロットが自分のリスク許容度に合っているかのシグナルです。ポジションを持ったまま不安で眠れない場合、それは適正ロットを超えている証拠です。', false, 9),
(3, 'リスク率別の連敗耐性として、1%ルールで20連敗した後に残る資金の割合は約何%ですか？', '約67%', '約90%', '約82%', '約95%', 3, '1%ルールでは1回の負けで資金の99%が残るため、20連敗後は0.99の20乗で約81.8%が残ります。リスク率を低く抑えるほど、連敗に対する耐性は劇的に向上します。', false, 10),
(3, '資金管理を自動車保険に例える理由として最も適切な説明はどれですか？', '資金管理をすれば事故に遭わなくなるから', '小さなコスト（保険料）を払って、壊滅的な損失を防ぐ仕組みだから', '資金管理は義務であり、加入しないと罰則があるから', '資金管理の費用は証券会社が負担してくれるから', 2, '資金管理は自動車保険と同じ発想で、毎回のトレードで小さなリスク（保険料）を限定することで、口座破綻という壊滅的な事態を防ぐ仕組みです。安心を買っているという意味で保険と同じ役割を果たします。', false, 11),
(3, '勝率60%のトレーダーが5連敗する確率は約何%ですか？', '約0.1%', '約1%', '約5%', '約10%', 2, '勝率60%であっても5連敗する確率は0.4の5乗で約1.02%です。100回トレードすれば約1回は5連敗が起きる計算であり、連敗は異常ではなく統計的に十分起こり得る正常な現象です。', false, 12),
(3, '連敗中に取るべき行動として正しいものはどれですか？', 'ロットを下げて、流れが変わった可能性に備える', '連敗を早く終わらせるためにロットを上げる', '手法が間違っている可能性があるため、直ちに別の手法に切り替える', '連敗中はエントリーせず、勝てる確率が高い設定だけを厳選する', 1, '連敗中は市場の流れが変わっている可能性があるため、ロットを下げて慎重に対応することが推奨されます。ロットを上げて取り返そうとするのは最も危険な行動であり、連敗をさらに拡大させる原因になります。', false, 13),
(3, 'リスク率10%で20連敗した場合、残る資金の割合は約何%ですか？', '約36%', '約50%', '約24%', '約12%', 4, 'リスク率10%では1回の負けで資金の90%が残るため、20連敗後は0.9の20乗で約12.2%しか残りません。20連敗で資金の約88%を失うことになり、トレードの継続が極めて困難になります。', false, 14),
(3, '2%ルールの「2%」という数値を決めている根拠として正しいものはどれですか？', '証券会社の法律で定められた基準値であるため', '有名なトレーダーが提唱した経験則であるため', '連敗耐性と資金効率のバランスを取った数学的に最も合理的な水準であるため', '2%以上のリスクを取ると人間の脳が判断力を失うという研究結果があるため', 3, '2%は「我慢」の数値ではなく、連敗に対する耐性と資金の成長効率を両立させる数学的に最も合理的な水準です。低すぎると利益が小さくなりすぎ、高すぎると連敗で退場のリスクが増えるバランス点が2%付近にあります。', false, 15),
(3, '資金100万円で損切り幅2,000円の銘柄を2%ルールで取引する場合、適正ロット数は何株ですか？', '10株', '5株', '20株', '40株', 1, '最大リスク額は100万円×2%＝2万円。ロット＝2万円÷2,000円＝10株です。損切り幅が大きい銘柄はロット数が少なくなり、同じ2%ルールでも銘柄のボラティリティに応じてポジションサイズが変わります。', false, 16),
(3, 'トレードで連敗したとき「手法が悪いのかもしれない」と不安になるのは自然な反応ですが、その不安に対して最初に確認すべきことはどれですか？', '最新の投資書籍で新しい手法を学び直す', '連敗を取り返すためにロットを増やすべきか検討する', '直近の勝率を計算して、手法を別のものに変えるか決める', '連敗は統計的に正常な範囲内かどうかを確認する', 4, '勝率60%のトレーダーでも5連敗する確率は約1%あり、連敗は統計的に正常な範囲で起こり得ます。連敗中こそ冷静に統計的な観点から「今の連敗は異常かどうか」を確認し、感情的に手法を変えたりロットを調整したりしないことが重要です。', false, 17),
(3, '2%ルールで運用した場合、20連敗した後に残っている資金の割合は約何%ですか？', '約50%', '約57%', '約67%', '約82%', 3, '2%ルールでは1回の負けで資金の98%が残るため、20連敗後は0.98の20乗で約66.8%が残ります。20連敗という極端な状況でも資金の3分の2以上が残るため、トレードを続ける土台が保たれます。', false, 18),
(3, '「分析が下手でもメンタルが弱いわけでもない」という言葉が指している内容として正しいものはどれですか？', 'トレードで苦しい思いをする原因は、多くの場合ロットが大きすぎることにある', '分析力やメンタルの強さはトレードの結果にほとんど影響しない', '初心者は分析もメンタルも未熟なので、まずロットを最小にすべきである', 'どんなに分析が上手でもメンタルが弱ければ勝てないのが現実である', 1, 'トレードで精神的な苦痛を感じるのは分析やメンタルの問題ではなく、単にロットが大きすぎることが原因であるケースがほとんどです。適正ロットに戻すだけで、多くの悩みは解消されます。', false, 19),
(3, '連敗中に「ルールを守れるかどうか」が分かれ目になる理由として最も適切な説明はどれですか？', '連敗中は冷静に分析できるため、ここでルールを見直す最大のチャンスだから', '連敗中こそ感情的になりやすく、ルールを破ってロットを上げたくなる衝動が強まるから', '連敗中は市場のルールが変わるため、自分のルールも適応させる必要があるから', '連敗中は勝率が上がる直前のサインであり、ルールを守れば必ず反転するから', 2, '連敗が続くと「取り返したい」という感情が強まり、ロットを上げたりルールを無視したエントリーをしがちです。この感情的な圧力に抗えるかどうかが、生き残るトレーダーと退場するトレーダーの分かれ目になります。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(4, '損切りを「保険料」と考える理由として最も適切な説明はどれですか？', '小さな損失を意図的に受け入れることで、資金を全失するリスクを防ぐ仕組みだから', '損切りは証券会社の手数料を支払う行為だから', '損失を確定することで税金の控除が受けられるから', '損切りを繰り返すと損失に慣れて精神的ダメージがなくなるから', 1, '損切りは小さな損失（保険料）を払うことで、大きな損失による口座破綻を防ぐ仕組みです。保険と同じく、支払う金額は限定的ですが防げるリスクは壊滅的です。', false, 1),
(4, '損切りができなくなっていく心理状態の変化を、正しい順番で並べたものはどれですか？', '期待 → 否認 → 麻痺', '麻痺 → 否認 → 期待', '否認 → 麻痺 → 期待', '否認 → 期待 → 麻痺', 4, '損切りできない心理は「まだ余裕がある」と問題を認めない否認、「ここまで耐えたのだから報われるはず」というサンクコストの期待、そして最後に損切りボタンを押す気力すら失う麻痺の3段階で進行します。', false, 2),
(4, '含み損が拡大しているとき「ここまで耐えたのだから報われるはず」と考える心理現象を何と呼びますか？', '確証バイアス', 'サンクコスト効果', 'バンドワゴン効果', 'ダニング＝クルーガー効果', 2, 'サンクコスト効果は、すでに投入した時間や金銭を取り返したいという心理から、合理的でない選択を続けてしまう現象です。トレードでは「ここまで耐えた」という執着が損切りを遅らせます。', false, 3),
(4, '損切りラインをエントリー後に動かしてはいけない理由として間違っているものはどれですか？', '損切りラインは市場の変動に合わせて柔軟に調整すべきだから', 'エントリー後は含み損のストレスで冷静な判断ができなくなるため', 'ラインを動かすと根拠のないトレードに変わるため', '損切りラインを広げると2%ルールが崩壊するため', 1, '損切りラインはエントリー前の冷静な自分が決めた判断であり、エントリー後に動かすべきではありません。ラインを動かすと根拠のない「祈りのトレード」に変わり、リスク管理が崩壊します。', false, 4),
(4, '「計画的ナンピン」と「感情的ナンピン」を見分ける基準として最も重要なものはどれですか？', '追加エントリーの回数が3回以内かどうか', 'ナンピンした時の含み損が資金の5%以内かどうか', 'エントリーする前に「ここで追加する」と決めていたかどうか', '追加エントリーの間隔が1時間以上あいているかどうか', 3, '計画的か感情的かの違いは「エントリー前に追加ポイントを決めていたか」で判断します。事前にシナリオとして組み込んでいれば戦略、含み損が出てから衝動的に追加すれば祈りです。', false, 5),
(4, '正しいトレードのエントリー手順として適切な順番はどれですか？', 'エントリー → 根拠の確認 → 損切りライン設定 → ロット計算', 'ロット計算 → エントリー → 損切りライン設定 → 根拠の確認', '損切りライン特定 → 根拠を見つける → エントリー → ロット計算', '根拠を見つける → 損切りライン特定 → 2%ルールでロット計算 → エントリー', 4, '正しい順番は「根拠 → 損切りライン → ロット計算 → エントリー」です。まずエントリーの根拠を確認し、その根拠が崩れる場所に損切りを置き、リスク額からロットを計算してからエントリーします。', false, 6),
(4, '損切りラインを置くべき正しい場所はどこですか？', '直近の高値・安値から一定の距離を空けた場所', 'エントリー価格から逆方向に1%下がった場所', '全体資金の2%に相当する価格', 'エントリーの根拠が崩れる価格帯', 4, '損切りラインは「エントリー根拠が崩れる場所」に置くのが正解です。根拠が通用しなくなった地点で撤退するのが論理的な損切りであり、パーセンテージや距離だけで機械的に決めるべきではありません。', false, 7),
(4, '損切りの心理3段階のうち、「まだ余裕がある段階で問題に気づけない」状態を指すのはどれですか？', '期待', '否認', '麻痺', 'パニック', 2, '否認は「大丈夫、すぐ戻る」と自分に言い聞かせる段階です。まだ含み損が小さく余裕があるため、問題の深刻さに気づけず、結果的に損切りのタイミングを逃してしまいます。', false, 8),
(4, '損切りができなくなる心理3段階の最終段階「麻痺」の特徴として正しいものはどれですか？', '損切りラインをさらに広げて、より大きな含み損に耐えようとする状態', 'チャートを激しく分析して損切りすべきかどうかを延々と迷い続ける状態', '損切りボタンを押す気力すらなくなり、「もうどうにでもなれ」と投げやりになる状態', '過去の類似チャートパターンを検証して、反転の確率を計算し続ける状態', 3, '麻痺は心理的な限界点であり、損切りボタンを押す気力すら残っていない状態です。「もうどうにでもなれ」と投げやりになり、ここまで来ると自力での損切りはほぼ不可能です。', false, 9),
(4, '「計画的ナンピン」が戦略として成立するための条件として、不要なものはどれですか？', 'エントリー前に追加ポイントをシナリオとして組み込んでいること', '各追加ポイントにそれぞれ根拠があること', '追加エントリーのたびにロットを倍にして平均単価を下げること', 'ナンピンを含めた全体のリスク額が2%ルールの範囲内であること', 3, '計画的ナンピンは事前のシナリオ、各ポイントの根拠、全体リスクの管理が前提です。ロットを倍にして平均単価を下げるのは典型的なマーチンゲール手法であり、リスクを指数関数的に増大させるため推奨されません。', false, 10),
(4, '感情的ナンピンをしてしまう人の根拠として、実際に動いている心理として最も近いものはどれですか？', '「ここが底値だから反転する可能性が高い」という分析的判断', '「平均単価を下げれば小さな反発で損益が戻る」という計算', '「過去のチャートで同じパターンは反転している」という統計的根拠', '「今の含み損をどうにかして減らしたい、助かりたい」という切迫感', 4, '感情的ナンピンの根拠は「助かりたい」という切迫感のみです。分析や計算に基づくものではなく、含み損のストレスから逃れたいという感情が衝動的な追加エントリーを引き起こします。', false, 11),
(4, 'よくある負けパターンのうち、「損切りできない病」に対する具体的な対策として正しいものはどれですか？', '損切り幅を広めに設定して、含み損に耐えられる余裕を持たせる', '小さなロットで取引すれば損切りしなくても被害が小さい', '損切りラインに近づいたらチャートを見ないようにする', 'エントリー前に逆指値注文（ストップロス）を入れておく', 4, '逆指値注文をエントリーと同時に設定しておけば、迷いや感情が介在する前に自動的に損切りが執行されます。人間の意志に頼らずシステムで損切りを確実に実行するのが最も効果的な対策です。', false, 12),
(4, '負けた直後にやりがちな「リベンジトレード」の対策として正しいものはどれですか？', '負けを取り返すために、次は勝率の高い設定だけを選ぶ', '負けた後は最低30分間チャートから離れる', '負けた方向と逆のエントリーをして、トレンドに乗り直す', '連続して負けた場合はロットを倍にして一発逆転を狙う', 2, '負けた直後は感情的になっており、冷静な判断ができません。最低30分チャートから離れて感情を落ち着かせることが、リベンジトレードという負の連鎖を断ち切る最も確実な方法です。', false, 13),
(4, '連勝が続いた後にやってしまいがちな負けパターンと、その対策の正しい組み合わせはどれですか？', 'パターン：リベンジトレード — 対策：連勝中はロットを段階的に下げる', 'パターン：連勝後のロット上げ — 対策：ロットは感覚でなく計算で決める', 'パターン：感情エントリー — 対策：連勝中はエントリー間隔を空ける', 'パターン：「今日だけ特別」症候群 — 対策：連勝数を記録して目に見える化する', 2, '連勝が続くと「調子がいいから」と感覚的にロットを上げがちですが、これは破滅的なリスクにつながります。ロットは常に2%ルールなどの計算に基づいて決め、感情や勢いで調整してはいけません。', false, 14),
(4, '「今日だけは特別だ」と思ったときに取るべき行動として正しいものはどれですか？', '「今日だけ」と思った時点でそのトレードは見送る', 'その日の市場環境を改めて分析し、特別な根拠があるか検証する', '直感が合っていることが多いので、小さなロットで試してみる', 'いつもより損切り幅を広げて、特別な値動きに対応できるようにする', 1, '「今日だけ特別」症候群は、ルールを破る言い訳を自分に許してしまう危険な心理状態です。「今日だけ」と思った時点で感情が判断を支配しているサインであり、そのトレードは見送るのが正解です。', false, 15),
(4, 'エントリー前に「この判断は計画か感情か」と自問するのは、どの負けパターンの対策ですか？', '損切りできない病', '感情エントリー', '「今日だけ特別」症候群', 'リベンジトレード', 2, '感情エントリーはチャートを見た瞬間の衝動で飛び乗ってしまうパターンです。「この判断は計画に基づくものか、それとも感情か」と自問することで、衝動的なエントリーを事前に防ぐことができます。', false, 16),
(4, '損切りを正しく実行した後にやるべきこととして、間違っているものはどれですか？', 'すぐに次のトレードを見つけてエントリーする', '最低30分〜1時間はチャートから離れる', 'ルール通りに損切りできた自分を褒める', '感情をリセットしてから次のトレードに備える', 1, '損切り直後はまだ感情的な揺れがあり、冷静な判断ができていません。すぐに次のトレードに入ると「損失を取り戻そう」という心理が働きやすく、リベンジトレードにつながるため避けるべきです。', false, 17),
(4, 'ルール通りに損切りができたとき、自分を褒めるべき理由として最も適切なものはどれですか？', '損切りで失った資金は税金控除の対象になるから', '損切りを褒めると次のトレードの勝率が上がるというデータがあるから', '損切りは「損した」ではなく「次のチャンスのために資金を守る行為」だから', '損切りを習慣にすれば、将来的に損切りが不要になるから', 3, '損切りは損失を確定する行為ではなく、次のトレードチャンスに向けて資金を守る行為です。ルール通りに実行できたことを褒めることで、損切りに対するネガティブな感情を徐々に軽減できます。', false, 18),
(4, 'エントリー前に損切りラインを決めるべき理由として最も重要なものはどれですか？', '含み損を抱えた状態では冷静な判断ができず、損切りの必要性が見えなくなるため', '証券会社の規定で損切りラインの設定が義務付けられているため', '損切りラインを決めないと注文が約定しない仕組みになっているため', '損切りラインを決めておけば、その価格に到達する確率が下がるため', 1, 'エントリー前は冷静に市場を分析できますが、ポジションを持った後は含み損のストレスで判断が歪みます。冷静な自分が決めた損切りラインに従うことが、感情に左右されないトレードの基本です。', false, 19),
(4, 'Week 1〜4の内容を踏まえた場合、トレードで「負けない」ために最初に確立すべきものとして最も重要なものはどれですか？', '高い勝率を誇るエントリーシグナルの見つけ方', '複数のテクニカル指標を組み合わせた分析手法', '損切りルールを含めた資金管理の仕組み', '市場の方向性を予測するファンダメンタル分析', 3, 'Week 1〜4を通じて一貫しているのは、勝ち方より先に「負け方」を学ぶことの重要性です。高い勝率のシグナルを見つけるよりも、損切りルールと資金管理を確立することが、口座を守り長く生き残るための最優先事項です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(5, 'トレードで含み損を抱えた際、「損失を確定させたくない」という心理を引き起こす4つの暴走感情のうちどれに該当しますか？', '焦り', '恐怖', '欲', '後悔', 2, '恐怖は「損を認めたくない」という心理から損切りの実行を阻害します。脳が「失うこと」を極端に嫌うため、損失の確定を避けようとしてポジションを持ち続けてしまいます。', false, 1),
(5, 'トレードにおける「欲」の暴走として典型的な行動はどれですか？', '利確目標に達しても「もっと伸びるかも」と持ち続けること', '含み損が出た瞬間に損切りすること', 'チャートが動き始めた瞬間に飛び乗ること', '損切り直後の反転を気にして次の損切りを遅らせること', 1, '欲の暴走は「もっと欲しい」という心理で、利確目標に達しても利益を伸ばそうとして持ち続ける行動に現れます。事前に決めた目標を超えても満足できず、結果的に利益を取りこぼす原因になります。', false, 2),
(5, 'FOMO（Fear Of Missing Out）がトレードに与える影響として最も典型的なものはどれですか？', '利確を早めすぎて利益を伸ばせないこと', '損切りラインを必要以上に広げてしまうこと', 'チャートが動き始めた瞬間に飛び乗り、高値掴みになること', '連勝後にロットを下げて保守的になりすぎること', 3, 'FOMOは「乗り遅れたくない」という焦りから、チャートが動き始めた瞬間にエントリーしてしまう心理です。エントリーの根拠がないタイミングで飛び乗るため、高値掴みになりやすい特徴があります。', false, 3),
(5, '損切り直後にレートが反転したのを見て「切らなければよかった」と思い、次の損切りを遅らせる原因となる感情はどれですか？', '恐怖', '焦り', '欲', '後悔', 4, '後悔は「あのとき、ああしていれば」と過去の行動を悔やむ感情です。損切り直後の反転を見ると「損切りしなければよかった」と後悔し、その体験が次の損切りを躊躇させる原因になります。', false, 4),
(5, '感情の暴走を防ぐための「メタ認知の3ステップ」として正しい順番はどれですか？', 'ルールに戻る → 気づく → 距離を置く', '距離を置く → ルールに戻る → 気づく', '気づく → 距離を置く → ルールに戻る', '距離を置く → 気づく → ルールに戻る', 3, 'メタ認知のステップは、まず「今、自分は何を感じているか」に気づき、次に「感情は一時的な脳の反応」と距離を置き、最後に「感情ではなくルールで動く」ように戻る、の順番です。', false, 5),
(5, '含み益が出ているにもかかわらず「逆行したらどうしよう」と利確を早めてしまう心理の背景にある感情はどれですか？', '恐怖', '欲', '焦り', '後悔', 1, '含み益がある場面でも「せっかくの利益が消えてしまうかもしれない」という恐怖が働き、計画通りの利確ポイントを待てずに早めに確定させてしまいます。恐怖は含み損だけでなく含み益の場面でも損失回避を引き起こします。', false, 6),
(5, '連勝後に「今がチャンスだ」とロットを上げたくなる心理を、4つの暴走感情のどれで説明できますか？', '恐怖', '焦り', '後悔', '欲', 4, '連勝による高揚感が「もっと稼げるかもしれない」という欲を刺激します。調子がいいときほど「今がチャンス」とロットを上げたくなりますが、これが欲の暴走による危険なサインです。', false, 7),
(5, '4つの暴走感情が連鎖して大損に至る典型的なパターンとして正しいものはどれですか？', '焦りで飛び乗る → 含み損 → 後悔 → 欲が暴走 → 恐怖で損切りできない', '焦りで飛び乗る → 含み損 → 恐怖で損切りできない → 損失拡大 → 後悔 → 欲が暴走 → リベンジトレード', '恐怖で損切りできない → 後悔 → 焦りで飛び乗る → 欲が暴走 → 大損', '欲が暴走 → 高値掴み → 焦り → 恐怖で利確 → 後悔 → ナンピン', 2, '感情の連鎖は「焦り（FOMO）で根拠なく飛び乗る」ことを起点に、含み損→恐怖で損切りできず→損失拡大→後悔→「取り返したい」欲が暴走→リベンジトレード→さらに負ける、という悪循環に陥ります。', false, 8),
(5, 'トレード前の「10秒チェック」で行うべきことは何ですか？', '「今、冷静か？」と自問し、Noならその日はトレードしない', '直近の経済指標発表のスケジュールを確認する', '過去の類似チャートパターンを確認する', '今の資金残高と許容損失額を計算する', 1, 'トレード前の10秒チェックは「今、冷静か？」と自分に問いかける行動です。答えがNoであれば、その日はトレードを見送ることが大きな損失を防ぐ最も確実な方法です。', false, 9),
(5, 'SNSで他者の「爆益」投稿を見て「自分も乗らなければ」と焦ってエントリーする行動の根本にある感情はどれですか？', '焦り', '恐怖', '欲', '後悔', 1, '他人の成果を見て「自分だけ取り残されている」と感じるのは焦りの典型的なパターンです。SNSの情報は結果の一部だけを切り取ったものであり、それに反応してエントリーするのは根拠のない感情トレードになります。', false, 10),
(5, '「今回だけ」と思ったときの心理状態について正しい説明はどれですか？', '「今回だけ」と思ったとき、それは欲が暴走しているサインである', '「今回だけ」は損切りタイミングを見極めた慎重な行動の表れである', '「今回だけ」は過去の検証に基づく例外的なエントリーの合図である', '「今回だけ」は冷静にリスクを評価した上での合理的な判断である', 1, '「今回だけ特別」「今回だけはルールを逸脱してもいい」という思考は、欲が理性を上回っている状態です。ルールを破る言い訳を自分に許している時点で、すでに感情が判断を支配しています。', false, 11),
(5, '恐怖に対する有効な対処法として提示されている問いかけはどれですか？', '「このポジションの含み損は資金の何%にあたるか？」', '「もし今ポジションを持っていなかったら、このレートでエントリーするか？」', '「過去に同じチャートパターンで勝ったことはあるか？」', '「損切りした後にレートが反転する確率は何%か？」', 2, '「もし今ポジションを持っていなかったら、このレートで新規にエントリーするか？」と自問し、答えがNoであれば即座に損切りするのが恐怖への対処法です。保有している事実から離れて純粋に相場を評価することで、恐怖による判断の歪みを修正できます。', false, 12),
(5, '焦り（FOMO）に対する対処法として提示されている問いかけと、その答えの正しい組み合わせはどれですか？', '「このエントリーの根拠は何か？」→「チャートの勢い」', '「このトレードを見送ったら何を失うか？」→「大きな利益を失う」', '「このトレードを見送ったら何を失うか？」→「何も失わない」', '「今エントリーしないとどうなるか？」→「二度とチャンスが来ない」', 3, '焦りへの対処は「このトレードを見送ったら何を失うか？」と自問することです。答えは「何も失わない」であり、1回のトレードを見送っても口座の資金は減りません。この事実を思い出すことで焦りを冷静に処理できます。', false, 13),
(5, '後悔の感情に対する正しい対処法はどれですか？', '次は損切りしないという方針に切り替える', '「結果」ではなく「プロセス」で評価し、ルール通りなら正しい行動とみなす', '過去のトレードを詳細に振り返り、最適なタイミングを探る', '反転の確率が高い場面では損切りを見送る戦略に変更する', 2, '後悔への対処は、結果ではなくプロセスで自分を評価することです。ルール通りに損切りを実行したのであれば、その後レートがどう動いたかにかかわらず正しい行動でしたと評価すべきです。', false, 14),
(5, '欲の暴走を防ぐための対処法として正しいものはどれですか？', '利確目標に達したら、さらに上値を狙えるか1分だけ検討する', '連勝時はロットを段階的に上げて勢いに乗る', '利確目標とロットを事前に決め、機械的に実行する', '利確目標は相場の動きに合わせて毎回柔軟に変更する', 3, '欲への対処は、利確目標とロットをトレード前に決めておき、機械的に実行することです。トレード中の判断は感情に左右されるため、事前の冷静な状態で決めた数値に忠実に従うことが重要です。', false, 15),
(5, 'トレードにおける「感情」について正しい考え方はどれですか？', '感情はトレードの敵であり、感情を完全に排除して初めて勝てるようになる', '感情をゼロにする必要はない。大切なのは「自分が感情的になっている」と気づくことである', '感情は無視すべきで、気づく必要もなくただルールに従えばよい', '感情は初心者だけの問題であり、経験を積めば自然に消えるものである', 2, '感情は敵ではなく「気づくべきシグナル」です。怖くてもいい、悔しくてもいい。感情をゼロにする必要はなく、大切なのは「今、自分が感情的になっている」と自覚し、感情にコントロールされないことです。', false, 16),
(5, 'メタ認知の3ステップのうち、「感情は一時的な脳の反応である」と認識するステップはどれですか？', '気づく', '振り返る', 'ルールに戻る', '距離を置く', 4, '「距離を置く」ステップでは、自分の感情を客観視し、「これは一時的な脳の反応にすぎない」と認識します。感情そのものを否定せず、感情と自分を切り離して俯瞰することで冷静さを取り戻します。', false, 17),
(5, '「今、自分は何を感じているか？」と自問するのは、メタ認知の3ステップのうちどれに該当しますか？', '距離を置く', 'ルールに戻る', '気づく', '振り返る', 3, '「今、自分は何を感じているか？」に気づくことがメタ認知の最初のステップです。自分の感情状態を言語化することで、感情に飲まれるのではなく感情を客体として認識できるようになります。', false, 18),
(5, '損切りした後にレートが反転した経験が、次のトレード行動に与える悪影響として最も典型的なものはどれですか？', '次のトレードで利確を早めすぎて利益を取りこぼすこと', '次のトレードで過剰にロットを上げて一発逆転を狙うこと', '次のエントリーを見送り続けてトレード機会を失うこと', '次の損切りを遅らせて、結果的に大損すること', 4, '損切り直後の反転を見ると「切らなければよかった」と後悔し、その経験から次の損切りを躊躇するようになります。損切りのタイミングを遅らせることで小さな損失が大きな損失に育つのが最も典型的な悪影響です。', false, 19),
(5, '感情の連鎖パターンにおいて、大損後に「取り返したい」という欲が暴走して起こる行動はどれですか？', '損切りラインを厳しくしてリスクを減らすこと', 'しばらくトレードを休んで冷静になること', 'ロットを下げて慎重に取り戻そうとすること', 'リベンジトレードをしてさらに負けること', 4, '感情の連鎖では、大損による後悔が「取り返したい」という欲を暴走させ、リベンジトレードを引き起こします。感情的な状態でのエントリーは根拠が乏しく、さらに負ける確率が高くなる悪循環を生みます。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(6, 'リベンジトレードの典型的な流れとして正しい順序はどれですか？', '根拠のないエントリー → 負ける → ロットを上げる → さらに負ける → 「取り返したい」思考が支配', '「取り返したい」思考が支配 → 負ける → ロットを上げる → 根拠のないエントリー → さらに負ける', '負ける → 「取り返したい」思考が支配 → 根拠のないエントリー → ロットを上げる → さらに負ける', 'ロットを上げる → 負ける → 「取り返したい」思考が支配 → さらに負ける → 根拠のないエントリー', 3, 'リベンジトレードは「負ける」ことを起点に、「取り返したい」感情が思考を支配し、根拠のないエントリーやロット増加へつながり、悪循環が繰り返されます。', false, 1),
(6, 'リベンジトレードに陥るプロセスの最終的な帰結として最も適切なものはどれですか？', '一時的な含み損を抱えるが、相場が戻れば回復できる状態', '悪循環を繰り返し、退場への片道切符となる状態', '精神的な疲労は増すが、資金管理さえ守れば退場は免れる状態', 'メンタルが鍛えられ、結果的に冷静なトレードができるようになる状態', 2, 'リベンジトレードは負け→感情→無謀な行動→さらに負けるのサイクルが繰り返され、最終的には退場に直結します。', false, 2),
(6, '「あの3万円を取り戻さないと」という思考を引き起こす心理的要因の名称は何ですか？', 'サンクコスト効果', '保有効果', '確証バイアス', 'アンカリング効果', 1, 'サンクコストとは、すでに失ったもの（埋没費用）を取り戻そうとしてさらに損失を拡大してしまう心理的バイアスです。', false, 3),
(6, '損失が出ているポジションをどうしても手放せない心理的要因の名称は何ですか？', '現状維持バイアス', '保有効果', 'サンクコスト効果', '確証バイアス', 2, '保有効果とは、自分が所有しているものを過大評価し、手放すことをためらってしまう心理的傾向です。損失ポジションを持ち続ける原因の一つです。', false, 4),
(6, '損切り後に「不快感を早く解消したい」と衝動的にエントリーしてしまう原因として、脳のどの系の反応が関係していますか？', '記憶系 — 過去の失敗を忘れようとする防衛反応', '報酬系 — 不快感を即座に解消する行動を促す反応', '免疫系 — ストレスホルモンによって判断力が低下する', '運動系 — 身体的なストレス反応として手が動いてしまう', 2, '負けた不快感を早く消したいという衝動は、脳の報酬系による反応です。怒りと結びついて、即座の行動を促してしまいます。', false, 5),
(6, 'リベンジトレードを引き起こす3つの心理的原因として正しい組み合わせはどれですか？', '確証バイアス・現状維持バイアス・後悔回避', 'アンカリング効果・バンドワゴン効果・損失回避', '沉没コスト・過剰自信・恐怖', 'サンクコスト・保有効果・怒り', 4, 'リベンジトレードの3つの心理的原因は「サンクコスト」「保有効果」「怒り」です。それぞれ「取り戻したい」「手放せない」「不快感を解消したい」という行動を引き起こします。', false, 6),
(6, 'サンクコストの考え方がトレードにおいて危険な理由として最も適切なものはどれですか？', '過去の利益に固執して利益確定が遅くなるため', '取引手数料が増えてコストパフォーマンスが悪化するため', '失った金額を取り戻そうと、本来見送るべきエントリーをしてしまうため', '過去の成功体験に縛られて新しい手法を試せなくなるため', 3, 'サンクコストは「すでに失った金額」に執着し、その回収を目的とした根拠のないトレードをしてしまう点が危険です。過去の損失は現在の判断には無関係であるべきです。', false, 7),
(6, '保有効果がトレードに与える悪影響として最も典型的なものはどれですか？', '損失が拡大しているポジションを損切りできず、含み損が膨らむ', '利益確定を急ぎすぎて、本来得られたはずの利益を取りこぼす', 'エントリータイミングが遅くなり、良い価格で入れない', '他の銘柄に目移りして、ポジションを頻繁に乗り換えてしまう', 1, '保有効果によって「自分の持っているポジション」に愛着が生まれ、損切りの判断が遅れて含み損が拡大してしまいます。', false, 8),
(6, '損切り後に怒りが生じるメカニズムとして最も正しい説明はどれですか？', '自己評価が下がったことに対する防衛機制として怒りが生まれる', '市場の不公平さに対する正当な怒りであり、合理的な感情反応である', '脳が損失を物理的な脅威として認識し、闘争反応を引き起こす', '損切りそのものが間違いだったと無意識に認識している証拠である', 3, '脳は損失を物理的な脅威と同様に処理し、不快感を素早く解消しようとする報酬系の反応が怒りとして表れます。これが衝動的なリベンジエントリーを引き起こします。', false, 9),
(6, '【30分ルール】の目的として最も重要なものはどれですか？', '相場の変動が落ち着くのを待つため', '次のトレードチャンスを冷静に探すための時間を確保するため', '他のトレーダーの動きを観察してからエントリーするため', '感情の高ぶりが自然に収まる物理的なクーリングタイムを設けるため', 4, '30分ルールは、損切り後の感情的な高ぶりが収まるまで物理的にチャートから離れることで、衝動的なリベンジトレードを防ぐことが目的です。', false, 10),
(6, '1日の損失上限ルールの内容として正しいものはどれですか？', '連敗2回で終了 / 1日の損失が総資金の2%で終了 / 1連敗でロット半分', '連敗5回で終了 / 1日の損失が総資金の5%で終了 / 3連敗でロット半分', '連敗3回で終了 / 1日の損失が総資金の5%で終了 / 1連敗でロット半分', '連敗3回で終了 / 1日の損失が総資金の3%で終了 / 2連敗でロット半分', 4, '損失上限ルールは「連敗3回で終了」「1日の損失が総資金の3%で終了」「2連敗でロットを半分にする」の3本柱で構成され、損失の拡大を体系的に防ぎます。', false, 11),
(6, '損切り後に感情メモを書く意義として最も重要なものはどれですか？', '自分の感情を客観視することで、リベンジトレードの衝動を弱めるため', 'トレード日記として後から振り返る記録を残すため', '他のトレーダーと感情を共有して共感を得るため', '感情のパターンを分析して、負けやすい時間帯を特定するため', 1, '「悔しい」「焦っている」「取り返したい」など感情を一言書き出すことで、自分の状態を客観視でき、衝動的な行動へのブレーキがかかりやすくなります。', false, 12),
(6, '損失上限ルールにおいて「2連敗でロットを半分にする」理由として最も適切なものはどれですか？', '連敗中は判断力が低下しており、3連敗目以降の損失を小さく抑えるため', '2連敗した時点で市場の環境が悪化している可能性が高いため', 'ロットを半分にすることで利益幅が広がり、損失を早く回復できるため', '資金の3%ルールと連動しており、自動的にロットを調整するため', 1, '連敗中は感情が乱れており、さらなる判断ミスのリスクが高い状態です。事前にロットを減らすことで、仮に3連敗目が来ても被害を最小限に抑えられます。', false, 13),
(6, '100万円の資金でトレードしている人が1日の損失上限ルール（総資金の3%）を設定した場合、その日の損失限度額はいくらですか？', '1万円', '3万円', '2万円', '5万円', 2, '総資金100万円の3%は3万円です。この額に達した時点でその日のトレードを終了することで、1日で致命的な損失を防ぎます。', false, 14),
(6, '損切りをした直後に取るべき行動として最も適切なものはどれですか？', 'すぐにチャートを分析して、同じ銘柄の再エントリーポイントを探す', '損失を取り戻すため、ロットを上げて別のエントリーチャンスを探す', '損切りの判断が正しかったか検証するため、すぐにトレード履歴を見直す', '30分間チャートを閉じて物理的に離れ、感情メモを書く', 4, '損切り直後は感情が高ぶっているため、30分ルールで物理的に離れ、感情メモを書くことで冷静さを取り戻すことが最適な行動です。', false, 15),
(6, '次のトレードで「まったく別の判断としてゼロから組み直す」とはどういうことですか？', '前回と同じ銘柄には絶対にエントリーしないという意味', '前回使用したテクニカル指標をすべて変更して、新しい分析方法を使うという意味', '前回のトレード結果（勝敗・損益）を一切引きずらず、独立的にエントリー根拠を組み立てるという意味', '前回の損失を考慮して、今回の目標利益を大きく設定し直すという意味', 3, '前回の損失を取り戻すという目的ではなく、市場の現在の状況だけを見て独立した根拠でエントリーを組み立てることが「ゼロから組み直す」ことの本来の意味です。', false, 16),
(6, 'あるトレーダーが1回目のトレードで2万円の損失を出しました。すぐに「取り返すぞ」と2回目のエントリーをして、ロットを1.5倍に増やしました。この行動に当てはまる心理的原因の組み合わせとして最も適切なものはどれですか？', '保有効果 + 損失回避', '確証バイアス + アンカリング効果', '現状維持バイアス + 後悔回避', 'サンクコスト + 怒り', 4, '「取り返すぞ」という思考はサンクコスト（失った2万円への執着）、ロットを増やす行動は怒り（不快感を早く解消したい）によるものです。両方が同時に作用しています。', false, 17),
(6, '30分ルールを実践する際、最も効果的な具体的な行動はどれですか？', 'スマホのアプリも含めてすべての取引ツールを閉じ、別の部屋に行く', 'チャート画面は開いたままにして、別の銘柄の分析だけをする', 'デモトレードで練習してから、本番に戻る', '取引履歴を確認しながら、次の作戦を頭のなかで組み立てる', 1, '30分ルールの効果は「物理的にチャートから離れる」ことにあります。アプリも含めてツールを閉じ、別の部屋に行くなど、視覚的な刺激を完全に遮断することが最も効果的です。', false, 18),
(6, '次のうち、リベンジトレードを予防するルールとして機能しないものはどれですか？', '連敗3回でその日のトレードを終了する', '損失を出した直後に、損失分を回復できる銘柄をすぐに探す', '1日の損失が総資金の3%に達したらトレードを終了する', '2連敗した時点でロットを半分にする', 2, '損失直後に「回復できる銘柄を探す」行為は、まさにリベンジトレードそのものです。感情的なエントリーを促すだけで予防になりません。', false, 19),
(6, '連敗中に「今は調子が悪い」と自覚しながらもエントリーを止められないトレーダーに対して、最も有効な対策はどれですか？', 'メンタルを強化するために、あえて連敗を続けて耐性をつける', 'エントリー前に自分に「本当に根拠があるか」を問いかける習慣をつける', '連敗の原因をテクニカル分析の不足だと割り切り、勉強時間を増やす', 'あらかじめ損失上限ルールを自動的に执行できる仕組みを用意しておく', 4, '連敗中は感情が理性を上回り、自力でのコントロールが困難です。損失上限ルールを事前に決めておき、ルール通りの行動を仕組み化することが最も確実な予防策です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(7, 'エントリーボタンを押した瞬間に脳内で放出される神経伝達物質は何ですか？', 'ドーパミン', 'セロトニン', 'コルチゾール', 'ノルアドレナリン', 1, 'エントリーの瞬間にドーパミンが放出され、報酬を得たときと同じ快感が生じます。この快感が根拠のないトレードを繰り返させる駆動力になります。', false, 1),
(7, 'ポジポジ病とは具体的にどのような状態を指しますか？', '損失を確定することが怖くて含み損ポジションを持ち続ける状態', '同じ銘柄に何度もエントリーと損切りを繰り返す状態', '常に何かのポジションを持っていないと落ち着かない状態', '利益が出ているポジションをすぐに手放してしまう状態', 3, 'ポジポジ病とは常にポジションを持っていないと不安になる状態で、FOMOとドーパミン報酬系の働きによって根拠のないトレードを繰り返す原因になります。', false, 2),
(7, '月20回トレードして勝率50%、リスクリワード比1:1の場合、手数料を含めた最終的な損益はどうなりますか？', '勝率50%なのでプラマイゼロで終わる', 'トレード回数が多いほどスプレッドが優遇されてプラスになる', '手数料は利益からのみ引かれるので、損失は増えない', '勝敗が同数でも手数料分だけマイナスになる', 4, '勝率50%・RR1:1では利益と損失が相殺され、全取引にかかる手数料だけが確実に差し引かれます。回数が多いほど手数料負担が膨らみ、結果的にマイナスになります。', false, 3),
(7, 'ポジポジ病のメカニズムはどの依存症と同じ脳の働きによりますか？', 'アルコール依存症', 'ギャンブル依存症', 'ショッピング依存症', 'ゲーム依存症', 2, 'ポジポジ病はギャンブル依存と同じメカニズムで機能します。不確実な結果に対してドーパミンが放出される仕組みが共通しており、トレード自体がギャンブル的な快感を生み出します。', false, 4),
(7, '月5回・勝率60%・RR1:2のトレードが月20回・勝率50%・RR1:1より成績が良い最大の理由は何ですか？', 'トレード回数が少ないほどブローカーのスプレッドが狭くなるから', 'エントリー基準を厳しくすることで低確率のトレードを排除できるから', '勝率60%を維持すれば回数に関係なく常にプラスになるから', '月5回以下なら手数料が無料になる仕組みがあるから', 2, '回数を絞ることで「本当に良いセットアップ」だけを厳選するようになり、勝率とリスクリワード比が同時に向上します。質の低いトレードを削り切ることが成績向上の鍵です。', false, 5),
(7, '「待つこと」に経済的価値がある理由として正しいものはどれですか？', 'トレードしない期間が長いほどブローカーから特別なレートが提供されるから', '待てば待つほどエントリーポイントの精度が上がるから', '余計な損失を防ぎ、次のチャンスにフルの資金で臨める状態を保てるから', '待っている間に相場のトレンドが自動的に予測できるようになるから', 3, '無駄なトレードで資金を削らずに済むことで、本当に良いチャンスが来たときに最大限のポジションサイズで臨めます。資金を温存すること自体が戦略的な行動です。', false, 6),
(7, 'ポジポジ病の背景にあるFOMOとは何の略ですか？', 'Focus On Maximum Opportunity — 最大の機会への注力', 'Fear Of Missing Out — 見逃しへの恐怖', 'Fear Of Market Oscillation — 市場の変動への恐怖', 'Force Of Momentum Order — モメンタム注文の力', 2, 'FOMOはFear Of Missing Outの略で、チャンスを見逃すことへの恐怖です。この恐怖がエントリーの衝動を駆り立て、ポジポジ病を悪化させます。', false, 7),
(7, '重要な経済指標の発表前にトレードを見送るべき理由として正しいものはどれですか？', 'ボラティリティが急拡大し、予測不能な値動きになるため', '指標発表前はブローカーが注文を制限するため', '指標発表前にエントリーするとスプレッドが3倍になるため', '指標の結果がすでに価格に織り込まれており動きがないため', 1, '重要指標の発表前後はボラティリティが急拡大し、スプレッドも広がりやすくなります。予測不能な値動きの中では技術的な根拠が通用しないため、見送るのが安全です。', false, 8),
(7, '連敗3回した状態でさらにトレードを続けると陥りやすい危険な行動はどれですか？', 'トレードルールを厳格にしてエントリー基準を高くする', 'ポジションサイズを半分にして慎重にトレードする', 'エントリーする銘柄を変えて気分を切り替える', '損失を取り返そうとルールを無視したエントリーに走る', 4, '連敗が続くと損失を取り返そうとする心理が強く働き、冷静さを失ってルールを無視したトレードに走りやすくなります。この「傾斜」に気づいて手を引くことが重要です。', false, 9),
(7, '損切り直後30分以内にトレードすべきではない理由は何ですか？', '損切りの執行に手数料が二重にかかるため', '損切りの痛みから「すぐ取り返したい」という衝動に駆られやすいため', 'ブローカーのシステムが30分間注文を制限するため', '損切りした銘柄は30分以内に必ず反発するため、二度負ける確率が高い', 2, '損切りの直後は損失の痛みが最も強く、「すぐに取り返したい」という衝動に駆られます。この感情は冷静な判断を奪うため、最低30分は距離を置くことが推奨されます。', false, 10),
(7, '「取り返したい」と感じている状態でトレードすると、どのような結果になりやすいですか？', '過去の損失に執着した根拠のないエントリーになり、さらに損失が膨らむ', '怒りが原動力になるため、かえって集中力が上がって良い結果が出る', '損失を取り返す目的があるため、自然的に慎重なトレードになる', '無意識に損切りラインが厳しくなり、小さな負けで済む', 1, '「取り返したい」という感情はサンクコスト効果の表れで、過去の損失に執着した根拠のないトレードを誘発します。冷静な判断が失われ、損失がさらに拡大しやすくなります。', false, 11),
(7, '体調不良や寝不足の日にトレードを見送るべき本質的な理由は何ですか？', '体調が悪いとチャートの色が見分けにくくなるから', 'ブローカーが体調不良時の取引を推奨していないから', '寝不足だとエントリーのタイミングが遅れて約定価格がずれるから', '認知機能と感情制御が低下し、冷静な判断とルールの遵守が難しくなるから', 4, '体調不良や寝不足は認知機能と感情制御を低下させます。トレードに必要な冷静な判断力とルール遵守が難しくなることが、見送るべき本質的な理由です。', false, 12),
(7, 'SNSで他のトレーダーの利益画像を見て焦りを感じたとき、最も適切な対応はどれですか？', '自分もすぐにエントリーして同じように利益を出す', 'そのトレーダーの銘柄をコピーして同じポジションを取る', 'トレードを見送り、SNSから離れて冷静になる', '小額のポジションで気分を落ち着かせてから本番に戻る', 3, 'SNSでの焦りはFOMOの典型的な引き金です。他人の結果は自分のトレードとは無関係であり、焦ってエントリーすると根拠のないトレードになるため、まずは画面から離れるべきです。', false, 13),
(7, '「やらない日」の過ごし方として最も効果的なものはどれですか？', 'デモトレードでエントリーの感覚を維持する', '小額のリアルトレードで感覚を衰えさせない', '過去トレードの振り返りやパターン観察の練習をする', 'SNSでトレーダーの意見を収集して次の戦略を練る', 3, 'トレードしない日は過去の振り返り、パターン観察、日誌の見返し、来週の計画などに使うのが最も効果的です。相場から離れつつも学習を深める有意義な時間になります。', false, 14),
(7, '自分のトレードルールに合うセットアップが見つからない日があります。このとき取るべき行動はどれですか？', 'エントリーせず、ルールに合うセットアップが現れるのを待つ', 'チャートの形が良さそうならルール外でもエントリーする', 'ルールをその場で少し緩めてエントリーの機会を作る', '新しいテクニカル指標を試すために小額でエントリーする', 1, '自分のルールに合うセットアップがない日は堂々とトレードしない日です。ルールを妥協してまでエントリーすることが、長期的な成績を悪化させる最大の要因になります。', false, 15),
(7, 'あるトレーダーが1ヶ月間で20回トレードしました。勝率50%、RR1:1で、1回あたりの往復手数料が500円の場合、1ヶ月間の手数料合計はいくらですか？', '5,000円', '20,000円', '500円', '10,000円', 4, '20回のトレードで往復手数料500円 × 20回 ＝ 10,000円です。勝率50%・RR1:1では利益と損失が相殺されるため、この手数料がそのまま口座からのマイナスになります。', false, 16),
(7, '「待つこと」の経済的価値のうち、「感情がニュートラルな状態で判断できる」とはどういう意味ですか？', '前のトレードの勝敗に影響されず、冷静に次のエントリー根拠を組み立てられるということ', '待っている間に感情的な記憶が消去されるということ', 'トレードしない期間が長いほど感情が麻痺して何も感じなくなるということ', '待つことで相場に対する恐怖心が完全に消滅するということ', 1, '前回のトレードで勝っても負けても感情が揺さぶられます。適切に待つことで感情がリセットされ、次のトレードを独立した冷静な判断で臨めるようになります。', false, 17),
(7, '次のトレード見送り基準のうち、チェックリストに含まれないものはどれですか？', '方向感がない', '利確直後の高揚感', '連敗3回', '体調不良・寝不足', 2, 'トレードを見送るべき基準には、方向感がない、連敗3回、体調不良・寝不足などが含まれますが、利確直後の高揚感はチェックリストの項目ではありません。', false, 18),
(7, 'あなたが損切りした直後、SNSで他のトレーダーの利益画像を見て焦りを感じました。この状況で取るべき最善の判断はどれですか？', '損切りの直後なので30分待ってから、SNSの銘柄を参考にエントリーする', 'SNSの利益画像は信用できないので、自分の分析ですぐに別の銘柄を探す', '焦りを感じているうちはエントリーせず、翌日までトレードを休む', '損切り後の30分ルールを守りつつSNSから離れ、感情が落ち着くまで待つ', 4, '損切り直後は「取り返したい」衝動、SNSはFOMOの引き金という二重の感情リスクがあります。30分ルールを守りSNSから離れることで、両方の感情に対応できます。', false, 19),
(7, 'トレード回数を月20回から月5回に減らしたトレーダーが、勝率50%から60%に向上しました。この変化が起きた理由として最も説明できるものはどれですか？', '手数料が減った分が利益に反映され、勝率の計算結果が上がっただけだから', '月5回しかエントリーできないという制約がプレッシャーになり、集中力が上がるから', '厳しい基準を満たすセットアップだけに絞ることで、低確率の見送り案件を排除できたから', 'トレード回数が少ないほど運が良くなる傾向があるから', 3, '回数を絞ることで「本当に良いセットアップ」だけを厳選するようになり、根拠の薄いトレードを排除できます。選択と集中によって勝率が向上するのが本質的な理由です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(8, '「上がっているのを見て飛び乗ったら天井だった」という経験に最も当てはまる負けパターンの名称はどれですか？', '追いかけエントリー', 'トリガーなしエントリー', '感情エントリー', '逆張り病', 1, '追いかけエントリーは、すでに大きく動いた後についていき、天井で掴まされる典型パターンです。対策は「待つべき場所で待つ」ことです。', false, 1),
(8, '逆張り病の本質的な問題として正しいものはどれですか？', 'トレンドの転換点を正確に予測することが技術的に不可能だから', '逆張りは常にトレンド追随よりもリスクが高いと数学的に証明されているから', '逆張りエントリーはブローカーの約定システムに不利なスリッページが発生するから', 'トレンドは想像よりも長く続くため、「そろそろ反転するだろう」という予想が外れやすいから', 4, '逆張り病は「そろそろ反転するだろう」という主観的な予想に基づきますが、トレンドは想像より長く続くのが相場の性質であり、逆張りは損失を膨らませやすい手法です。', false, 2),
(8, '「価格がラインに到達したから」という理由だけで確認なく飛び込む負けパターンを何と呼びますか？', '感情エントリー', '追いかけエントリー', 'トリガーなしエントリー', '分析麻痺', 3, 'トリガーなしエントリーは、価格が目標地点に到達したことだけで飛び込み、ローソク足の確定や追加の確認条件を待たない失敗パターンです。', false, 3),
(8, '感情エントリーの対策として提示されている「5秒ルール」とは具体的にどのような方法ですか？', 'エントリー後に5秒待って損失が拡大しないか確認する', '5秒間チャートを見つめ続けてエントリー根拠を探す', 'エントリーボタンを押す前に5秒止まり、「今、冷静か？」と自分に問う', '5秒以内にエントリーを完了させないとチャンスが消えるという認識を持つ', 3, '5秒ルールはエントリー前に5秒止まって冷静さを確認する方法です。「ワクワクする」だけで飛び込む感情エントリーを防止する具体的な歯止めです。', false, 4),
(8, '「情報を集めすぎて結局何もできない」状態を表す負けパターンの名称はどれですか？', '確証バイアス', 'ルーティン無視', '感情エントリー', '分析麻痺', 4, '分析麻痺は情報を集めすぎて判断できなくなる状態です。「わからない」と判断できるなら見送りが正解であり、無理にエントリーしないことが重要です。', false, 5),
(8, '損切りできない病の背景にある心理的効果として、「サンクコスト」と「保有効果」が挙げられています。このうちサンクコスト効果とはどのような心理ですか？', 'ポジションを保有している期間が長いほど愛着が湧いて手放せなくなる心理', 'すでに投入した資金や時間を回収しようとして、損失を手放せない心理', '過去に大きな利益を出した銘柄に何度もエントリーしてしまう心理', '損切りした瞬間に相場が反転するのではないかと恐れる心理', 2, 'サンクコスト効果は、すでに投入したコスト（時間・資金）を無駄にしたくない心理で、損失を抱えたポジションを手放せない原因になります。', false, 6),
(8, '損切りできない病に対する対策として提示されている「今ノーポジなら入るか？」という問いかけが効果的な理由はどれですか？', '現在のポジションを一旦決済してエントリーし直すことで心理がリセットされるから', '含み損のサンクコスト感情を排除し、純粋にエントリー根拠だけを客観的に評価できるから', 'ノーポジ状態で考えると常にエントリーしない方がよいという結論になるから', '問いかけることで時間が経過し、自然と相場が好転する確率が上がるから', 2, '「今ノーポジなら入るか？」と問うことで、含み損のサンクコスト感情を排除し、純粋にエントリー根拠の有無だけを客観的に評価できます。', false, 7),
(8, '22種の負けパターンのうち「最も破壊力がある」とされているものはどれですか？', '追いかけエントリー', '連勝後のロット上げ', '経済指標無視', 'リベンジトレード', 4, 'リベンジトレードは「最も破壊力がある」とされる負けパターンです。損失を取り返そうとする感情が全てのルールを吹き飛ばし、連鎖的な大損を招きます。対策は30分間チャートを閉じることです。', false, 8),
(8, 'エントリー後にシナリオを変更する行為について、「エントリー後の変更はほぼ100%何に基づく」と説明されていますか？', '新しいテクニカル根拠', '相場環境の変化', '感情', '経済指標の発表結果', 3, 'エントリー後のシナリオ変更はほぼ100%感情に基づきます。含み損を避けたい、利益を伸ばしたいなどの感情が、事前に立てた計画を書き換える原因になります。', false, 9),
(8, '連勝後のロット上げが危険な理由として最も的確なものはどれですか？', '連勝後はブローカーが約定レートを不利に操作する仕組みになっているため', '連勝中は相場の環境が良いだけで技術が向上しているわけではないため、次の1敗でそれまでの利益を全て消し去る可能性がある', 'ロットを上げると強制決済のリスクが高まる仕組みになっているため', '連勝後のエントリーは勝率が統計的に下がることが証明されているため', 2, '連勝中は「ついてる！」と勢いに乗りやすく、ロットを上げた状態で1回負けるとそれまでの利益を全て消し去るリスクがあります。ロットは事前計画で固定すべきです。', false, 10),
(8, '連敗後のロット上げはどの負けパターンの変形とされていますか？', '感情エントリー', 'シナリオ変更病', '追いかけエントリー', 'リベンジトレード', 4, '連敗後のロット上げはリベンジトレードの変形です。損失を取り返すためにロットを増やす行為は、リベンジ心理そのものです。連敗後は逆にロットを半分にするのが推奨されています。', false, 11),
(8, '5分足で「上昇トレンド」と判断して買いエントリーしたが、日足では下降トレンドだったという失敗は、どの負けパターンに当てはまりますか？', '下位足だけ見る病', '確証バイアス', 'フェイクブレイク', '分析麻痺', 1, '下位足だけ見る病は、短い時間足の局部的な動きに反応してエントリーし、上位足の大局的なトレンドと矛盾していることに気づかない失敗パターンです。', false, 12),
(8, '確証バイアスのトレードにおける典型的な現れ方として正しいものはどれですか？', '自分のポジション方向に有利な情報だけを集め、不利な情報を無視する', '複数の時間足を確認せずに一つのチャートだけで判断する', 'エントリー後に損切りラインを何度も下方修正する', '他人のトレード結果を見て自分の判断を変える', 1, '確証バイアスは「自分が信じたいこと」を裏付ける情報だけを集め、矛盾する情報を無視する認知バイアスです。買いポジションを持っていれば上昇の根拠ばかり探してしまいます。', false, 13),
(8, 'フェイクブレイクに引っかかるトレーダーの典型的な行動として正しいものはどれですか？', '一瞬だけラインを抜けたのを見て飛び込むが、すぐに戻されて損切りになる', 'レンジ相場ではエントリーせず、明確にブレイクした後だけエントリーする', 'ブレイクした後に数本ローソク足を待ってからエントリーする', '複数の時間足でブレイクを確認してから慎重にエントリーする', 1, 'フェイクブレイクは一瞬だけラインを抜ける現象で、これに飛び込むとすぐに戻されて損切りになります。ブレイクの確認にはローソク足の確定や再テストを待つことが重要です。', false, 14),
(8, '利確早すぎ病の対策として提示されているものはどれですか？', '利確後にすぐ次のエントリーをして利益を積み重ねる', '含み益が減る不安をなくすために常に両建てにする', '利確目標を事前に設定し、そこに到達するまでポジションを維持する', '利確のタイミングは直感に頼り、含み益が出たらすぐに手放す', 3, '利確早すぎ病は少しの含み益で焦えて確定してしまう癖です。対策は利確目標を事前に設定し、目標に到達するまでポジションを維持するルールを守ることです。', false, 15),
(8, '「今日だけ特別」症候群について、「今日だけ」と思った瞬間に何が最も危険だと言われていますか？', 'その瞬間がその日の最もエントリーに適したタイミングである可能性が高いから', '「今日だけ」と思った瞬間こそが最も危険な状態であり、ルールを破る入口だから', '「今日だけ」と考えたトレードは勝率が統計的に低いことが分かっているから', '特別な日は相場のボラティリティが高くなり予測不能になるから', 2, '「今日だけルールを少し緩めてもいい」「今日だけロットを上げてもいい」と思った瞬間が最も危険です。この思考がルール崩壊の入口であり、一度崩すと戻りにくくなります。', false, 16),
(8, '22種の負けパターンのうち「最も地味で最も根深い」とされているものはどれですか？', 'ルーティン無視', '損切りできない病', '記録しない', '確証バイアス', 3, '「記録しない」は最も地味で最も根深い負けパターンです。記録がないと自分の失敗パターンに気づけず、同じ過ちを無限に繰り返すことになります。対策は1トレード3行でも構わないので書くことです。', false, 17),
(8, '事前分析なしにエントリーしてしまう負けパターンの名称はどれですか？', 'ルーティン無視', '経済指標無視', 'トリガーなしエントリー', '記録しない', 1, 'ルーティン無視は事前の分析手順を飛ばしてエントリーする習慣です。毎日のルーティンを守ることが、感情に流されないトレードの土台になります。', false, 18),
(8, 'トレンド終盤に参入したトレーダーが巻き込まれやすい現象はどれですか？', 'スプレッドが極端に狭くなり利益が出にくくなる', '大口の売り抜けに巻き込まれて天井で掴まされる', '相場のボラティリティが低下してポジションが膠着する', 'ブローカーのシステムトラブルで決済できなくなる', 2, 'トレンド終盤への参入は、すでに利益を確保した大口投資家の売り抜けに巻き込まれるリスクが高いです。長く続いたトレンドの最後に飛び乗るのは典型的な負けパターンです。', false, 19),
(8, '「追いかけエントリー＋損切りできない＋リベンジ」の複合パターンが引き起こす結果として最も正しいものはどれですか？', '手数料負けしてコツコツ損失が積み重なる', '一つのトレードで大きな損失を出すが、そこで止まる', '感情的なエントリーになるが、損切りで最小限の損失に抑えられる', '連鎖的な大損に繋がる', 4, '追いかけエントリーで天井を掴み、損切りできずに含み損を抱え、最後にリベンジトレードでさらに損失を拡大する連鎖は、最も破壊的な負けパターンの組み合わせです。一つの失敗が次の失敗を呼ぶ連鎖的大損に繋がります。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(9, 'メタ認知を最も正確に説明している記述はどれですか？', '自分の感情を完全に消し去り、無の状態でトレードに臨む技術', '自分の思考を客観的に観察する「もう一人の自分」を持つ技術', '過去のトレード結果を分析して次のエントリー根拠を見つける分析手法', 'チャートのテクニカル指標を複数組み合わせて精度を高める分析方法', 2, 'メタ認知とは「自分の思考を見ている、もう一人の自分」を持つことです。感情をなくすのではなく、感情に気づくことが核心です。', false, 1),
(9, 'メタ認知の核心として正しい考え方はどれですか？', '感情をなくすことで冷静なトレードができるようになる', 'ポジティブな感情だけを残し、ネガティブな感情を抑え込む', '感情そのものではなく「感情を感じている自分」に気づくこと', '感情を一切感じない超人になることを目指す', 3, 'メタ認知の核心は「感情をなくす」ことではなく「感情に気づく」ことです。感情を感じている自分を客観視できるかが重要です。', false, 2),
(9, 'お腹が空いている状態でスーパーに買い物に行くと、必要のないものまで買ってしまいがちです。この日常例が示すメタ認知の効果として最も適切なものはどれですか？', '「今お腹が空いているから判断が狂っている」と気づけば、カゴの中を見直すことができる', 'お腹が空いている時はスーパーに行ってはいけないという絶対ルールを示している', '買い物リストを事前に作っていれば空腹の影響は完全に防げる', '空腹時の買い物は精神的に問題がある行動で、自己制御力の欠如を示している', 1, '「今お腹が空いているから判断が狂っているな」と気づくことがメタ認知です。気づきがあれば行動を修正でき、トレードでも同じ原理が働きます。', false, 3),
(9, '「5秒ルール」の具体的な手順として正しいものはどれですか？', 'エントリーボタンを押す前に5秒止まり、声に出して「今、冷静か？」と自分に問う', 'チャートを開いてから5秒以内にエントリー方向を決定する訓練法', '5秒ごとにチャートを更新して最新の価格変動を確認する習慣', 'エントリー後に5秒待ち、損失が拡大しないか確認してから決済する', 1, '5秒ルールはエントリーボタンを押す前に5秒止まり、声に出して「今、冷静か？」と自分に問う方法です。答えがNoならその日はトレードしません。', false, 4),
(9, '5秒ルールを実践した結果、「今、冷静か？」という問いに対する答えがNoだった場合、取るべき行動として正しいものはどれですか？', '深呼吸を3回行った後、必ずエントリーする', 'エントリーサイズを半分にして冷静さを取り戻してから実行する', 'その日はトレードしない', 'デモトレードに切り替えてエントリーの感覚を確かめる', 3, '「今、冷静か？」への答えがNoなら、その日はトレードしません。無理にトレードする必要はなく、感情が高ぶっている時のトレードはリスクが高くなります。', false, 5),
(9, '「5秒で逃すチャンスは、そもそもあなたのチャンスではない」という言葉が意味する内容として最も適切なものはどれですか？', '5秒以上考えるとチャンスは確実に消えるので、早い判断が求められる', 'プロのトレーダーは5秒以内に全ての判断を完了させている', 'スキャルピングなどの短期トレードでは5秒ルールは適用できない', '急いでエントリーしないと逃すような機会は、本来自分の戦略に合わないトレードである', 4, '冷静に5秒考えるだけで逃してしまうようなチャンスは、そもそも自分の計画や戦略に基づくトレードではない可能性が高いです。焦りからのエントリーを防ぐ意味があります。', false, 6),
(9, 'メタ認知の3ステップを正しい順序で並べたものはどれですか？', '名前をつける → 気づく → 記録する', '記録する → 気づく → 名前をつける', '気づく → 名前をつける → 記録する', '気づく → 記録する → 名前をつける', 3, 'メタ認知の3ステップは「①気づく → ②名前をつける（ラベリング） → ③記録する」の順です。まず感情に気づき、具体的に名前をつけ、最後に書き残します。', false, 7),
(9, 'メタ認知の3ステップのうち、最初のステップ「気づく」について、初心者にとって現実的な目標として正しいものはどれですか？', 'トレード後に振り返った時点で感情に気づくだけで十分な第一歩である', '1週間以内に全ての感情をリアルタイムで把握できるようになること', '感情に気づくだけでなく、同時に感情をコントロールできるようになること', 'エントリーの瞬間にリアルタイムで感情に気づけるようになること', 1, '最初はトレード後に気づくだけでOKです。リアルタイムで気づけるようになるには練習が必要で、事後の振り返りから始めるのが現実的です。', false, 8),
(9, 'メタ認知の第2ステップ「ラベリング」の効果として、脳科学的に証明されているものはどれですか？', '前頭葉の論理的思考能力が一時的に低下する副作用がある', '扁桃体の活動が抑制され、感情の暴走を和らげる効果がある', '海馬の記憶形成機能が向上し、過去のトレードを鮮明に思い出せる', '扁桃体の活動が活性化し、感情をより強く感じられるようになる', 2, '感情に具体的な名前をつける（ラベリング）ことで、脳の扁桃体の活動が抑制されることが脳科学で証明されています。「イライラ」を「損切りが悔しくて取り返したい」と具体的に表現することで効果が高まります。', false, 9),
(9, '「イライラしている」という感情をラベリングする際、より効果的な表現として適切なものはどれですか？', '「ネガティブな感情がある」と抽象的に表現する', '「感情スコア3」と数値だけを記録して感情の内容は書かない', '「損切りが悔しくて取り返したいと思っている」と具体的な原因まで含めて表現する', '「イライラしている」とだけ一言で表現する', 3, 'ラベリングは具体的に行うほど効果的です。「イライラ」だけでなく「何に対して」「どうしたいのか」まで言葉にすることで、扁桃体の抑制効果が高まります。', false, 10),
(9, 'メタ認知の第3ステップ「記録する」について、書く行為がもたらす効果として最も適切なものはどれですか？', '書くことで感情が完全に消滅し、次のトレードに影響しなくなる', '記録した内容を他者に共有することで客観的なアドバイスが得られる', '過去のトレードとの比較データが蓄積され、統計分析に活用できる', '書く行為自体が客観性を生み、自分の状態を外から見る効果がある', 4, 'トレード前に感情を一言メモするなど、書く行為自体が客観性を生みます。頭の中だけで考えるより、文字にすることで自分を外から見る視点が得られます。', false, 11),
(9, '感情日記で各トレードごとに記録すべき3つの項目として正しい組み合わせはどれですか？', '①エントリー根拠 ②決済理由 ③トレード結果の損益', '①その日の市場環境 ②使用したテクニカル指標 ③利益率の目標達成度', '①トレード前の感情 ②トレード中に感じた変化 ③トレード後の感情と感情スコア', '①エントリー時の勇気の度合い ②ポジション保有中の期待感 ③決済後の満足度', 3, '感情日記は「①トレード前の感情（一言）②トレード中に感じた変化 ③トレード後の感情と感情スコア（1〜5）」の3つを記録します。感情の変化を追うことで自分のパターンが見えてきます。', false, 12),
(9, '感情日記の感情スコアについて、スコア「1」が表す状態として正しいものはどれですか？', '感情が高ぶっており、興奮状態でトレードしたことを示す', '完全に冷静な状態でトレードできたことを示す', '感情を全く感じなかったことを示す異常な状態である', 'トレードに集中しすぎて周囲が見えなくなっていた状態を示す', 2, '感情スコアは1〜5で評価し、1は「完全に冷静」、5は「感情的だった」を意味します。自分の感情状態を数値化することで、傾向や改善点を見つけやすくなります。', false, 13),
(9, 'メタ認知が最も難しくなる瞬間について、適切な説明はどれですか？', '感情が暴走している最中にメタ認知を発動するのが最も難しい', '大きな利益が出て自信に満ちている時にメタ認知が最も難しくなる', 'トレードを始めたばかりの初心者期間だけメタ認知が難しい', 'トレードをしていない休場日にメタ認知が最も難しくなる', 1, '感情が暴走している最中は、メタ認知を発動する余裕がなく最も難しい瞬間です。だからこそ、感情が暴走する「前」に物理的な歯止めを作っておくことが重要です。', false, 14),
(9, '感情が暴走する「前」に物理的な歯止めを作るという方針について、最も象徴的な具体例はどれですか？', '「連敗3回で終了」「損切り後30分はチャート閉じる」などの事前ルールを設定する', '感情が高ぶった時にだけ1ロットサイズでエントリーする例外ルールを設ける', 'トレード前に30分間瞑想して精神統一する', '損失が一定額を超えたら自動でロット数を増やす設定にする', 1, '「連敗3回で終了」「損切り後30分はチャート閉じる」などの事前ルールは、冷静な自分が暴走する自分のために用意するセーフティネットです。感情が暴走してからではルールを守れないため、事前の設定が不可欠です。', false, 15),
(9, '「冷静な自分が暴走する自分のためにセーフティネットを用意する」という考え方について、この前提となっている認識として正しいものはどれですか？', '感情をコントロールできる人はセーフティネットを必要としない', '感情の暴走は誰にでも起こり得るため、事前の仕組みで防ぐ必要がある', 'セーフティネットがあると安心して大胆なトレードができるようになる', 'メンタルが弱い人だけが暴走するので、精神鍛錬が先である', 2, '感情の暴走は意志の強さに関わらず誰にでも起こり得ます。だからこそ、冷静に判断できる時にルールを仕組みとして用意しておくことが大切です。', false, 16),
(9, '連敗が続いている日のトレードに対する適切な対応として、メタ認知の観点から最も望ましいものはどれですか？', '連敗を取り返すために次のエントリーでロットを増やす', '連敗3回を超えた時点でその日のトレードを終了する事前ルールを守る', '連敗中は時間足を短くしてエントリー回数を増やし確率を上げる', '連敗は運が悪いだけと考えて、同じやり方でエントリーを続ける', 2, '「連敗3回で終了」という事前ルールは、連敗による焦りや取り返し心理が暴走する前に物理的にストップをかけるセーフティネットです。ルールを守ることが長期的な生存につながります。', false, 17),
(9, '損切り直後に最も起こりやすい心理状態と、それに対する適切な対応の組み合わせとして正しいものはどれですか？', '好奇心 → 損切りの原因をすぐに分析して次のトレードに活かす', '悔しさと取り返し心理 → 30分間チャートを閉じて冷静さを取り戻す', '安心感 → すぐに次のエントリーをして流れに乗る', '無関心 → 感情がないのでそのままエントリーを続けて問題ない', 2, '損切り直後は「悔しさ」や「取り返したい」という心理が強く働きやすく、この状態でのエントリーは更なる損失の原因になります。30分間チャートを閉じるなど物理的な距離を取ることが有効です。', false, 18),
(9, 'あるトレーダーが「損切り後すぐにエントリーして更に損失を拡大させてしまった」という経験をしています。次回から同じ過ちを繰り返さないために、メタ認知の3ステップを踏まえて最も効果的な対策はどれですか？', '損切りのたびにトレード日記に反省文を3行以上書く', '損切りの上限額を1日あたりの利益目標額と同じ額に設定する', '損切りをした時だけエントリーのロット数を減らす運用ルールを追加する', '「損切り後は取り返したくなる」と気づき、「焦り」とラベリングし、「損切り後30分はチャートを見ない」と記録して徹底する', 4, 'メタ認知の3ステップ（気づく→名前をつける→記録する）を適用すれば、「損切り後の焦り」というパターンに気づき、それを言葉にし、具体的な行動ルールとして記録することで再発防止につながります。', false, 19),
(9, 'トレード前に「早くエントリーしないとチャンスを逃す」と焦りを感じている時、メタ認知を活用した対応として最も適切なものはどれですか？', '焦りは行動の原動力になるので、そのままエントリーして勢いに乗る', '焦りを感じたら必ず1時間待ってからエントリーを判断する', '焦りを感じた時は逆張りエントリーが有効なので、皆と逆の方向にエントリーする', '「今、焦っている。これはFOMO（見逃し恐怖）だ」とラベリングし、5秒ルールで冷静さを確認する', 4, '焦りに気づいて「これはFOMOだ」とラベリングし、5秒ルールで冷静かどうかを確認するのがメタ認知を活用した対応です。感情に名前をつけることで客観視でき、5秒止まることで衝動的なエントリーを防げます。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(10, '人間がトレード結果を振り返る際、最も起こしやすい認知の偏りとして当てはまるものはどれですか？', '勝った時は「実力」、負けた時は「運が悪い」と処理してしまう', '勝った時も負けた時も等しく「運」のせいにしてしまう', '勝った時は「たまたま」、負けた時は「自分の実力不足」と分析してしまう', '勝敗に関わらず常に自分の判断プロセスを正確に記憶できる', 1, '人間は勝った時は「自分の実力」、負けた時は「運が悪い」と正当化する傾向があります。この自己肯定的な記憶の偏りがあるため、日誌による客観的な記録が必要です。', false, 1),
(10, 'トレード日誌が果たす最も重要な役割はどれですか？', '他のトレーダーと結果を比較して競争心を養うこと', '勝率を高めるための新しいテクニカル指標を開発すること', '毎日の損益を正確に税務申告用に記録すること', '「感覚」ではなく「データ」で自分を見るツールになること', 4, '人間の記憶は不正確であるため、日誌は「感覚」ではなく「データ」で自分を客観視するためのツールです。感情や思い込みを排除した事実ベースの振り返りが可能になります。', false, 2),
(10, 'トレード日誌を続けられない理由として「面倒」と感じる人への対策として提示されている、最小限の記録項目はどれですか？', 'エントリー価格・決済価格・損益額の3項目', '根拠・結果・感情の3項目', '使用したテクニカル指標・チャートパターン・時間足の3項目', '市場環境・経済指標・ニュースの3項目', 2, '「面倒」と感じる人には、根拠・結果・感情の3項目だけを書く方法が提案されています。最低限の項目でも継続することで、データが蓄積し自己認識が深まります。', false, 3),
(10, 'トレード日誌を始めたばかりの人が「何を書けばいいかわからない」という悩みに対する解決策として適切なものはどれですか？', 'プロのトレーダーの日誌をそのままコピーして使う', '毎回異なるフォーマットを試して最適なものを探す', '書く内容を毎日の気分で自由に決める', 'テンプレートに従って書く', 4, '「何を書けばいいかわからない」という悩みには、テンプレートに従って書くことが対策として提示されています。決まった枠組みがあれば迷わず記録できます。', false, 4),
(10, 'トレード日誌をつける際の「完璧主義」を克服する考え方として正しいものはどれですか？', '毎回必ず5行以上書かないと意味がない', '1行でもいいから書くことが大切', '週に1回まとめて書く方が効率的である', '項目を全て埋められなかった日は記録しない', 2, '完璧主義による挫折を防ぐため、「1行でもいい」という考え方が提示されています。書かない日を作るより、短くても継続することに価値があります。', false, 5),
(10, 'トレード日誌の効果が現れるタイミングとして、提示されている目安はどれですか？', '1か月で変化が現れ、3か月で確実に変わる', '1週間で効果を実感できなければ方法を変えるべき', '半年続けなければ一切効果が現れない', '書いたその日から即座にトレード成績が改善する', 1, '効果がすぐ見えないことが挫折の理由の一つですが、1か月で変化が現れ、3か月で確実に変わるとされています。長期的な視点で継続することが重要です。', false, 6),
(10, 'トレードの評価を「勝ち負け」ではなく「ルール遵守度」で行う理由として最も適切なものはどれですか？', 'ルールを守っていれば必ず毎回利益が出るから', '勝率を気にすると精神的に負担がかかるから', '結果ではなく過程を評価することで、長期的に安定したトレードができるから', 'プロのトレーダーは全員ルール遵守度で評価しているから', 3, 'トレードの結果（勝ち負け）は短期的には運の要素も含みますが、ルールを守る過程を評価することで、長期的に利益を出す確率を高めることができます。', false, 7),
(10, 'ルール通りに損切りをして損失が出たトレードについて、正しい評価はどれですか？', '損失が出たのだから「悪いトレード」である', 'ルールを守れなかった証拠であり、損切りルール自体を見直すべきである', 'ルール通りに損切りできたのだから「良いトレード」である', '損切りのタイミングが遅かった可能性が高く、改善が必要である', 3, 'ルール通りに損切りできた場合は、結果が損失であっても「良いトレード」と評価します。ルールを守ること自体が長期的な生存に直結するからです。', false, 8),
(10, 'ルールを破って利益が出たトレードについて、なぜ「悪いトレード」と評価すべきですか？', '利益が出ても手数料で消えてしまうから', 'ルールを破った利益は税金が高くなるから', '一度ルールを破ると二度とルールに戻れなくなるから', '間違った成功体験を脳に刻み、次回もルールを破る原因になるから', 4, 'ルールを破って利益が出た場合、「ルールを破っても勝てた」という間違った成功体験が脳に刻まれます。これが次回以降もルール違反を繰り返す原因になります。', false, 9),
(10, 'ルール遵守度と長期的なトレード成績の関係について、正しい記述はどれですか？', 'ルール遵守度50%以下では、どんな手法でも資金を減らす可能性が高い', 'ルール遵守度80%以上ならどんな手法でも利益が出る', 'ルール遵守度が低くても、勝率が高ければ長期的に利益を出せる', 'ルール遵守度は最初の1か月だけ意識すれば、あとは自然に維持できる', 1, 'ルール遵守度が50%以下の場合、どんな手法を使っていても資金を減らすとされています。一貫性のない実行は、手法の良し悪しに関わらず成績を悪化させます。', false, 10),
(10, '週次振り返りのステップとして正しい順序で並べたものはどれですか？', '来週の改善点を1つ決める → ルールを守れなかった場面を探す → トレードを数える → 最良と最悪のトレードを比べる', 'ルールを守れなかった場面を探す → 最良と最悪のトレードを比べる → トレードを数える → 来週の改善点を1つ決める', 'トレードを数える → ルールを守れなかった場面を探す → 最良と最悪のトレードを比べる → 来週の改善点を1つ決める', '最良と最悪のトレードを比べる → 来週の改善点を1つ決める → ルールを守れなかった場面を探す → トレードを数える', 3, '週次振り返りの正しい順序は「①トレードを数える → ②ルールを守れなかった場面を探す → ③最良と最悪のトレードを比べる → ④来週の改善点を1つ決める」です。', false, 11),
(10, '週次振り返りの最初のステップ「今週のトレードを数える」の目的として最も適切なものはどれですか？', '週間の損益合計を正確に計算するため', '最も利益が出たトレードを表彰するため', 'トレード回数が多すぎないか、自分の適正ペースか確認するため', '他のトレーダーと回数を比較するため', 3, 'トレード数を数える目的は、回数が多すぎないかを確認することです。トレードが増えすぎている場合は、焦りや暇つぶしでのエントリーが混ざっている可能性があります。', false, 12),
(10, '週次振り返りの第2ステップ「ルールを守れなかった場面を探す」で重要なのは、守れなかった「理由」を探ることです。その理由として最も多い典型的なパターンはどれですか？', 'ルール自体が複雑すぎて理解できていなかった', '感情的な衝動（焦り・過信・取り返し心理）が原因だった', 'チャートのテクニカル指標が誤っていた', '市場が想定外の動きをしてルールが適用できなかった', 2, 'ルールを守れなかった場面の多くは、感情的な要因（焦り・過信・取り返し心理など）が原因です。「なぜ守れなかったか」を突き詰めると、感情のパターンが見えてきます。', false, 13),
(10, '週次振り返りで「最良と最悪のトレードを比べる」目的として正しいものはどれですか？', '自分なりのパターンを発見するため', '最良のトレードの利益で最悪のトレードの損失を相殺できるか確認するため', '最悪のトレードをした日の市場環境を二度と同じ条件でトレードしないため', '最良のトレードの手法を他の銘柄にも応用するため', 1, '最良のトレードと最悪のトレードを比較することで、自分の勝ちパターンと負けパターンが見つかります。このパターン発見が今後のトレード改善に直結します。', false, 14),
(10, '週次振り返りの最終ステップで「来週の改善点を1つだけ決める」理由として最も適切なものはどれですか？', '1つしか改善できないほどトレードのスキルが低いから', '毎週異なる改善点に取り組むことで、全ての課題をローテーションで克服できるから', '1つの改善点をクリアすれば他の問題は自動的に解決するから', '複数の改善点に取り組むと焦点がぼやけて結局何も変わらないから', 4, '改善点を1つに絞るのは、複数同時に取り組むと焦点がぼやけて挫折しやすくなるからです。1つずつ確実に改善していく方が結果的に大きな変化につながります。', false, 15),
(10, 'トレード日誌のデータ分析から「金曜午後は負けやすい」という傾向が見つかりました。この傾向の原因として最も可能性が高いものはどれですか？', '金曜午後は経済指標の発表が集中しているから', '週末の疲れが蓄積している、または値動きが荒れやすいため', '金曜は流動性が最も高すぎて約定がうまくいかないから', '金曜午後はプロのトレーダーだけが参加しているから', 2, '「金曜午後は負けやすい」というデータは、週末の疲れの蓄積や、金曜午後特有の値動きの荒さが原因の可能性があります。このパターンに気づけば、金曜午後のトレードを避けるなどの対策が取れます。', false, 16),
(10, 'トレード日誌のデータから「連勝翌日にロットを上げて大負けしている」というパターンが見つかりました。この根本的な心理的原因はどれですか？', '連勝後は市場の方向性が読みやすくなるという錯覚', '連勝後は必ず反落するという市場の法則が働いている', '連勝による過信でリスク管理が疎かになっている', '連勝翌日の流動性が低下してスプレッドが広がっている', 3, '連勝翌日の大負けは「過信」が原因です。連勝で自信が高まった状態ではロットを上げたくなり、リスク管理がおろそかになります。データがこの危険なパターンを教えてくれます。', false, 17),
(10, 'トレード日誌の記録から「焦りの日は全て負けている」という傾向が判明しました。このデータに基づく最も合理的な対策はどれですか？', '焦りを感じた日はエントリーしないというルールを追加する', '焦りを感じた時はエントリー方向を反転させる', '焦りを感じたらロットサイズを半分にする', '焦りを感じなくなるまでエントリーを10分遅らせる', 1, '「焦りの日は全部負け」というデータがあるなら、焦りを感じた日はエントリーしないという明確なルールが最も合理的な対策です。データに基づくルール作りこそが日誌の最大の価値です。', false, 18),
(10, 'あるトレーダーの1週間の記録が以下の通りです。月曜：ルール通りエントリーして+15pips、火曜：ルールを無視してエントリーして+30pips、水曜：ルール通りエントリーして-10pips、木曜：ルール通りエントリーして-8pips。この週のルール遵守度は何％ですか？', '25%', '50%', '75%', '100%', 3, '4回のトレードのうちルールを守ったのは月・水・木の3回です。ルール遵守度は3/4＝75%となります。火曜は利益が出ていますが、ルールを破っているため「悪いトレード」と評価されます。', false, 19),
(10, 'トレード日誌を3か月続けた結果、自分のデータから以下の傾向が見つかりました。（1）午前中のトレードは勝率65%、午後は勝率38%、（2）連敗後のエントリーは平均損失が2倍、（3）ルール遵守度90%の週は全て黒字。このデータに基づいて最優先で実施すべき改善策はどれですか？', '午後のトレード手法を新しく開発する', '勝率の低い午後の時間を勉強時間にあてて新しい指標を学ぶ', '午後のトレードのロットサイズを午前の半分にして継続する', '連敗後のエントリー制限ルールを作り、午後のトレードを縮小または中止する', 4, 'データは明確です。午後の低勝率と連敗後の損失拡大が最大の課題です。連敗後のエントリー制限と午後のトレード縮小は、データに基づく最も効果的な改善策です。ルール遵守度90%の週が黒字であることも、ルールを守ることの重要性を裏付けています。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(11, 'ルールブックが「冷静な自分から暴走中の自分への手紙」である理由として最も適切なものはどれですか？', '暴走中は感情的になり、その場で正しい判断を下す力を失っているから', 'ルールブックは他人に見せるものではなく、自分だけの秘密の文書だから', '暴走中の自分は他人のアドバイスしか受け付けない状態になっているから', '冷静な自分と暴走中の自分では好むトレード手法が変わるから', 1, 'トレード中に感情が暴走している最中は、自力で正しい判断を下すことができません。だからこそ、冷静な状態の自分が事前にルールを書き残しておく必要があります。', false, 1),
(11, 'ルールブック7項目のうち、「トレードする市場と時間軸」を1つに絞る理由は何ですか？', '複数の市場を同時に監視すると手数料が増えるから', '焦点を絞ることでその市場のクセや特徴を深く理解できるから', '証券会社の口座が1つの市場しか対応していない場合が多いから', '複数市場のトレードは法律で制限されているから', 2, '市場と時間軸を1つに絞ることで、その環境特有の値動きのパターンやリズムを体感として蓄積でき、判断の精度が向上します。', false, 2),
(11, 'エントリー条件を「具体的に」書くべき理由として正しいものはどれですか？', '曖昧な条件は感情に「今回だけは特別」という言い訳を与えてしまうから', '具体的であれば他のトレーダーと条件を共有しやすくなるから', '証券会社の注文画面には数値で入力する必要があるから', 'エントリー条件は過去データと照合するために数式化が必要だから', 1, 'エントリー条件に曖昧さが残っていると、感情が「これも条件を満たしている」と勝手に解釈し、ルールを曲げる言い訳を生んでしまいます。', false, 3),
(11, '損切りルールの正しい位置として最も適切な記述はどれですか？', '含み損が資金の5%に達した時点で損切りする', 'エントリーの根拠が崩れる場所で、最大でも資金の2%以内に設定する', 'チャートのサポートラインより少し下で、余裕を持って幅広く設定する', '損切り幅は利益目標の3分の1以内に収まるように設定する', 2, '損切りは「根拠が崩れる場所」に設定し、1回の損失を資金の2%以内に抑えます。損切りラインは一度決めたら動かしてはいけません。', false, 4),
(11, '資金管理において、1回のトレードで許容すべきリスクの目安は資金の何%ですか？', '0.1%〜0.5%', '1%〜2%', '5%〜10%', '10%〜20%', 2, '1回のトレードで失う金額を資金の1〜2%に抑えることで、連敗が続いても口座を壊滅させることなく続けられます。', false, 5),
(11, 'ルールブックの6項目目「トレードしない条件」を客観的な数字で区切る理由は何ですか？', '主観的な判断では、手が震えているときでもエントリーしてしまう可能性が高いから', '数字で区切ることで自動売買システムにルールを組み込みやすくなるから', 'トレードしない条件は法律で数値基準を定めることが義務付けられているから', '数字で区切ると他のトレーダーのトレード頻度と比較しやすくなるから', 1, '「今日は調子が悪いからやめておこう」という感覚頼りの判断は、感情に左右されます。「過去10トレードの勝率が〇%以下ならエントリーしない」のように数字で客観的に線を引くことで、感情の介入を防ぎます。', false, 6),
(11, '振り返りルールで「曜日と時間を決める」ことが重要な理由はどれですか？', '市場が開いている時間帯に振り返るとリアルタイムのデータが使えるから', '週末はチャートデータが更新されないため、平日に振り返る必要があるから', 'トレード日記を書くために最低2時間の連続した時間が必要だから', '曜日と時間を固定することで、振り返りを習慣化しサボれなくなるから', 4, '振り返りは「気が向いたときにやる」では続きません。「毎週日曜の朝10時」のように日時を決めることで、振り返りがルーティンになり継続できます。', false, 7),
(11, 'トレード中に「今回だけは特別だ」という考えが浮かんだとき、何が起きていると考えるべきですか？', '直感が研ぎ澄まされており、例外的なチャンスを見つけた状態', 'ほぼ確実に感情が判断を歪めているサイン', 'ルールが不完全で、この状況に対応する条件が抜けている証拠', '市場がいつもと違う動きをしており、柔軟な対応が求められている合図', 2, '「今回だけは特別」という考えが浮かんだ時点で、感情が理性を上回っています。この言葉が出たときは原則としてルールを守るべき警告シグナルです。', false, 8),
(11, '含み損を抱えている最中に「この状況はルールに当てはまらない」と考えたときの正しい対応はどれですか？', '自分の判断を信じて、状況に応じて臨機応変に対応する', 'ルールを一時的に見直して、現在の状況に合った新しい基準を適用する', '含み損の中の自分を信用せず、事前に決めたルール通りに損切りを実行する', '少し待って含み損が縮まるのを見てから、改めて判断し直す', 3, '含み損を抱えているときの自分は「まだ大丈夫」と根拠なく信じ込みやすくなります。損失を抱えている状態での判断は信用せず、冷静な自分が決めたルールに従います。', false, 9),
(11, '「ルールを破って勝つ」ことと「ルールに従って負ける」ことのうち、なぜ後者の方が価値があると言われるのですか？', 'ルールを守って負ければ、損失の金額が必ず小さくなるから', 'ルールを破って勝つと税金が高くなり、結果的に利益が減るから', 'ルールに従って負ける経験は再現性のあるプロセスを示しており、改善できるから', 'ルールを破って勝つと、次のトレードで必ず大きな損失が出る統計があるから', 3, 'ルールを破って勝ってもそれは運であり再現性がありません。ルールに従って負けた場合は「プロセスは正しかったか」を検証でき、改善の材料になります。', false, 10),
(11, 'ルールブックの見直しは何ヶ月ごとに行うことが推奨されていますか？', '1ヶ月ごと', '3ヶ月ごと', '6ヶ月ごと', '1年ごと', 2, '3ヶ月に一度の頻度で見直しを行います。短すぎるとデータが足らず、長すぎると悪い癖が定着してしまうため、3ヶ月が適切な間隔です。', false, 11),
(11, 'ルールの見直し手順として正しい順番はどれですか？', '修正を3つ加える → 検証する → 共通パターンを探す', 'ルール通りのトレードで勝ったものを集める → 勝因を分析する → 新しいルールを追加する', 'ルール通りにやって負けたトレードを集める → 共通パターンを探す → 修正を1つだけ加える', '全トレードの損益を計算する → 利益の大きいトレードを再現する → エントリー条件を増やす', 3, '見直しでは「ルールを守って負けたトレード」に焦点を当て、共通の負けパターンを見つけ、修正は一度に1つだけ加えます。複数同時に変えると何が効果あったか分からなくなります。', false, 12),
(11, 'トレーダーAは「1回の損失を資金の5%まで許容」し、トレーダーBは「1回の損失を資金の1%に制限」しています。両者が5連敗した場合、資金への影響として正しいものはどれですか？', 'トレーダーAは約22%減、トレーダーBは約5%減になる', 'トレーダーAは25%減、トレーダーBは5%減になる', 'トレーダーAは約35%減、トレーダーBは約10%減になる', '両者ともに損失率は同じで、回数が増えるほど差が出るわけではない', 1, '5%リスクで5連敗すると (0.95)^5 ≒ 0.774、約22.6%の減少です。1%リスクなら (0.99)^5 ≒ 0.951、約4.9%の減少です。資金管理の1〜2%ルールは、連敗時の被害を最小限に抑えるためにあります。', false, 13),
(11, '利確ルールを事前に決めておくべき理由として最も適切なものはどれですか？', '利確ルールを決めておけば、利益が必ず最大化されるから', '利確は損切りより重要であり、エントリーよりも先に決めるべきだから', '税金対策のために利確のタイミングを年度末に合わせる必要があるから', '含み益を見ると「まだ伸びるかも」と欲張ったり「今のうちに確定させよう」と焦ったりするから', 4, '含み益がある状態では感情が揺れ動きやすく、冷静な判断ができません。利確ポイントを事前に決めておくことで、感情に判断を委ねず機械的に実行できます。', false, 14),
(11, '次のルールブックの記述のうち、最も改善が必要なものはどれですか？', '「ダウ理論で明確な上昇トレンドを確認後、押し目でエントリーする」', '「1回の損失は口座資金の2%以内に抑え、損切りラインはエントリー後に動かさない」', '「なんとなく上がりそうな気配を感じたらエントリーする」', '「直近5トレードの勝率が30%を下回った日は、それ以上エントリーしない」', 3, '「なんとなく上がりそうな気配」は曖昧すぎる条件です。エントリー条件は具体的で客観的でなければならず、曖昧さは感情の言い訳を許してしまいます。', false, 15),
(11, '損切りラインを「動かさない」ことが重要な理由はどれですか？', '損切りラインを動かすと手数料が発生するから', '損切りラインは計算で求めたものだから、途中で変更すると計算が合わなくなるから', '損切りラインを動かすと、自動売買のプログラムがエラーを起こすから', '一度動かし始めると「もう少し待てば戻る」と期待して、最終的に被害が拡大するから', 4, '損切りラインを少し下にずらすと、さらに下にずらしたくなります。この「損切りの先延ばし」が口座を壊滅させる最大の原因の一つです。', false, 16),
(11, 'ルールの見直しで「修正を1つだけ加える」とされている理由はどれですか？', '1回の見直しで複数の修正を加えると時間がかかりすぎるから', '複数同時に変えると、どの修正が結果に影響したか特定できなくなるから', 'ルールブックの項目は最大7つまでと決まっているから', '1度に2つ以上変更すると、証券会社のシステムに反映されないから', 2, '一度に複数の条件を変えると、勝率が上がっても「どの変更が効いたのか」が分かりません。1つずつ変更・検証を繰り返すことで、精度の高いルールを構築できます。', false, 17),
(11, 'あなたはルールブックを作成しました。ある日、エントリー条件を満たしてポジションを持ったものの、想定と逆に動き始めました。損切りラインまであと少しのところで、「ここで損切りするより、もう少し様子を見よう」と考えました。この状況で取るべき行動はどれですか？', '損切りラインに到達する前に、より安全な位置にラインを引き下げてから待つ', 'チャートパターンを確認し、反転の兆しがあれば損切りを見送る', '事前に決めた損切りラインに到達した時点で、理由に関わらず損切りを実行する', '同じ方向のポジションを追加して平均取得価格を改善する', 3, '損切りラインは「根拠が崩れる場所」です。到達した時点でエントリーの前提が崩れているため、感情的理由で見送らず機械的に実行します。', false, 18),
(11, 'ルールブックを作る「タイミング」として最も適切なものはどれですか？', 'トレード中に気がついたことをその都度メモして、後で整理する', '大きな損失を出した直後に、反省を込めて一気に書き上げる', 'ポジションを持たず冷静な状態のときに、時間をかけて作成する', 'セミナーに参加した直後に、教わった内容をそのまま書き写す', 3, 'ルールブックは感情が介在しない冷静な状態で作成する必要があります。ポジションを持っている最中や損失直後は感情が高ぶっており、適切なルールを作れません。', false, 19),
(11, '次のうち、ルールブックに含めるべき「トレードしない条件」として最も適切なものはどれですか？', '「利益目標に到達するまでは絶対にエントリーしない」', '「その日の最初のトレードが損失だった場合、午後のセッションはトレードしない」', '「ルールに従って損切りした日は、翌日までエントリーしない」', '「勝っている日は調子に乗らないよう、全くトレードしない」', 2, '「1回負けたら午後はやらない」のような客観的な数字による条件は、負けが連鎖するのを防ぎます。トレードしない条件は感情に左右されない明確な基準で設定します。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(12, '続く人と続かない人の違いを決める最も大きな要因は何ですか？', '生まれつきの意志の強さ', '続けるための仕組みの有無', '一日にかけられる時間の長さ', 'これまでの投資経験の豊富さ', 2, '続く人と続かない人の違いは意志の強さではなく、続けるための仕組みを持っているかどうかで決まります。「気合いは3日、仕組みは3年」と言われるように、仕組み化が継続の鍵です。', false, 1),
(12, '習慣化のプロセスにおいて、最初の21日間はどの段階にあたりますか？', '自動化 — 考えなくても自然にできる段階', '定着 — やらないと気持ち悪くなる段階', '慣れ始める — 一番つらいが完璧を求めず小さく始める段階', '振り返り — これまでの習慣を見直して改善する段階', 3, '最初の21日間は「慣れ始める」段階で最もつらい時期です。この時期は完璧を求めず、小さく始めることが大切です。', false, 2),
(12, '習慣化において「やらないと気持ち悪くなる」状態になるのは何日目以降ですか？', '21日目以降', '40日目以降', '66日目以降', '90日目以降', 4, '90日目以降は「定着」の段階で、やらないと気持ち悪くなる状態になります。この頃には意志力をほとんど使わずに習慣を維持できます。', false, 3),
(12, '習慣化の3段階を正しい順序で並べたものはどれですか？', '慣れ始める → 自動化 → 定着', '自動化 → 慣れ始める → 定着', '定着 → 慣れ始める → 自動化', '慣れ始める → 定着 → 自動化', 1, '習慣化は「慣れ始める（21日）→ 自動化（66日）→ 定着（90日）」の順で進みます。まず一番つらい慣れの段階を小さく乗り越えることで、徐々に自動化・定着へと進みます。', false, 4),
(12, '習慣化の66日目に到達した時点でどのような状態になっていますか？', 'まだ意識的な努力が必要だが、少しずつ習慣になり始めている', '完全に定着し、二度と習慣を崩すことはない', '考えなくても自然にできる自動化の状態になっている', '習慣の効果が数字に現れ始め、大きな成果を実感できる', 3, '66日目は「自動化」の段階です。考えなくても自然に行動できるようになり、習慣を維持するための意志力の負担が大幅に減ります。', false, 5),
(12, 'トレードを続けるためのコツとして推奨されている「小さく始める」行動はどれですか？', '感情を一言メモするだけ（10秒）', '毎朝ニュースサイトを5つ巡回する', '毎日1時間チャート分析をする', '毎日トレード日誌をA4用紙1枚分書く', 1, '「感情を一言メモ」はたった10秒でできる行動です。小さく始めることで続けやすく、完璧を求めない姿勢が習慣化の第一歩になります。', false, 6),
(12, '習慣化の過程で3日間サボってしまった場合、最も適切な対応はどれですか？', '最初からやり直すため、カレンダーのチェックをリセットする', 'サボったことを深く反省し、ペナルティを自分に課す', '習慣化に失敗した証拠なので、別のアプローチに切り替える', '3日サボっても4日目にまた始めればよく、気にしすぎない', 4, '完璧を目指さないことが習慣化のコツです。3日サボっても4日目にまた始めればよく、途切れたことを理由に諦める必要はありません。', false, 7),
(12, '習慣を「見える化」する方法として推奨されているものはどれですか？', 'スプレッドシートに詳細なデータを毎日入力する', '月に一度、詳しいレポートを書く', 'カレンダーにチェックを付ける', 'SNSに毎日の成果を投稿する', 3, 'カレンダーにチェックを付けるだけのシンプルな見える化が推奨されています。手間が少ないからこそ続き、積み重ねが目で見て分かることがモチベーションに繋がります。', false, 8),
(12, '朝のトレードルーティンで「シナリオを1つ書く」のに想定されている時間はどれですか？', '15分', '1分', '10分', '5分', 4, '朝のルーティン全体で10〜15分のうち、シナリオを1つ書くのに5分を想定しています。指標確認（2分）、市場の流れ確認（5分）、シナリオ作成（5分）の構成です。', false, 9),
(12, '日中の過ごし方として推奨されている行動はどれですか？', 'アラートを設定してチャートから離れる', '1時間ごとにチャートを確認して現在値をメモする', '常にチャートを監視してエントリーチャンスを見逃さない', 'トレード関連のニュースを常にストリーミングで流しておく', 1, '日中はチャートに張り付かず、アラートを設定して離れることが推奨されています。張り付きすぎは感情による判断ミスを招きやすくなります。', false, 10),
(12, '夜の振り返りルーティンで「トレードをしなかった日」に行うべき行動はどれですか？', '翌日に必ずトレードする決意を固める', '次の日のエントリーポイントを詳細に分析する', '「やらなかった理由」を一言で書き留める', 'チャートを見直して見逃したチャンスを確認する', 3, 'トレードしなかった日は「やらなかった理由」を一言書くだけで十分です。無理にトレードしなかった自分を責めず、理由を残すことで自分の傾向が分かります。', false, 11),
(12, '夜の振り返りでトレードをした日に日誌に書く分量はどれくらいが推奨されていますか？', '項目数は決まっていないが最低500文字', '10行', '1ページ', '3行', 4, 'トレードをした日は日誌に3行書くだけで十分です。負担を小さくすることで続けやすくなり、継続することで豊富なデータが蓄積されます。', false, 12),
(12, '検証回数と信頼性の関係について、30回の検証でどのような状態になりますか？', '統計的に信頼できる結果が得られる', 'たまたまの可能性が高く、まだ判断材料にならない', '傾向が見え始める', 'パターンを明確に確認できる', 3, '10回ではたまたまの可能性が高く、30回で傾向が見え始め、50回でパターン確認、100回で統計的に信頼できるという段階があります。30回は傾向が見え始める段階です。', false, 13),
(12, 'あるトレード手法の検証を50回行いました。この時点で期待できることはどれですか？', 'パターンを確認できる段階に達している', 'たまたまの可能性が高く、まだ何も判断できない', '統計的に完全に信頼できる結論が出る', '検証は不要になり、すぐに実戦投入できる', 1, '50回の検証でパターンの確認ができる段階です。ただし統計的な信頼性を高めるには100回が目安であり、50回は中間的な確認地点と捉えます。', false, 14),
(12, 'Akiraの3原則の1つ「わかる範囲で、わかることをやる」が意味していることはどれですか？', '自分の理解度に合わせて少しずつ知識を広げていくこと', '理解していないトレードで得た利益は同じ場所で返すため、理解している範囲で取引すること', '初心者のうちは少額の取引だけに絞ること', '難しい分析手法は避けてシンプルな指標だけ使うこと', 2, '理解していないトレードで利益が出ても、同じ理解不足の場面で損失を出すことになります。自分がわかる範囲で取引することが、長期的な安定に繋がります。', false, 15),
(12, 'Akiraの3原則のうち「1つを確実にできる人の方が強い」と説明されているのはどれですか？', 'わかる範囲で、わかることをやる', '完璧を目指さず、小さく続ける', 'できる範囲で、できることをやる', '自分の頭で考える', 3, '「できる範囲で、できることをやる」は、何でもかんでもやろうとするのではなく、1つを確実にできる人の方が強いという原則です。無理な拡張より確実な積み上げを重視します。', false, 16),
(12, 'Akiraの3原則にある「自分の頭で考える」とは、具体的にどのような態度を指していますか？', 'SNSの情報に振り回されず、自分の基準で考える', '他人の意見を一切参考にせず、自分だけで全てを判断する', '常に最新の経済ニュースから自分なりの見解を導き出す', '過去の自分のトレード履歴だけを根拠に判断する', 1, 'SNSには情報があふれていますが、それに振り回されず自分の頭で考えることが重要です。他人の意見は参考にしても、最終的な判断は自分の基準で行います。', false, 17),
(12, 'あなたはトレードを始めて3週間が経ちました。最初の習慣化の段階が一番つらいと知った今、どのように取り組むのが最も適切ですか？', '毎日必ず完璧なルーティンをこなすと決めて、どんなに忙しくても時間を作る', 'この時期はつらいのが当然なので、完璧を求めず小さく続ける', '3週間が一番つらいなら、つらさが減る21日目まで一気に集中して乗り切る', 'つらい期間を短縮するため、複数の習慣を同時に始めて一気に慣れる', 2, '最初の21日間は「慣れ始める」段階で最もつらい時期です。この時期は完璧を求めず小さく続けることが推奨されており、無理な目標設定は挫折の原因になります。', false, 18),
(12, 'あなたはあるトレード手法を20回検証しました。結果は悪くありませんが、実戦で使うべきか迷っています。正しい判断はどれですか？', '20回でも結果が良ければ統計的に十分であり、すぐに実戦投入してよい', 'まだ傾向が見え始める段階なので、少なくとも50回までは検証を続ける', '10回でたまたまの可能性があるため、あと10回追加して判断する', '検証回数に関わらず、自分が納得すればいつでも実戦投入してよい', 2, '20回ではまだ傾向が見え始める段階（30回）にも達していません。パターンを確認するには50回、統計的な信頼性には100回が目安なので、焦らず検証を続けることが重要です。', false, 19),
(12, 'あなたは毎朝のトレードルーティンを始めようとしています。全体で10〜15分のルーティンを構成する3つのステップを正しい順序で選んでください。', 'シナリオを1つ書く → 市場の大きな流れ確認 → 経済指標カレンダー確認', '経済指標カレンダー確認 → 市場の大きな流れ確認 → シナリオを1つ書く', '経済指標カレンダー確認 → シナリオを1つ書く → 市場の大きな流れ確認', '市場の大きな流れ確認 → 経済指標カレンダー確認 → シナリオを1つ書く', 2, '朝のルーティンは「①経済指標カレンダー確認（2分）→ ②市場の大きな流れ確認（5分）→ ③シナリオを1つ書く（5分）」の順です。事実確認から始めて、最後に自分なりのシナリオを構築する流れになります。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(13, 'STRADAという言葉の語源とその意味として正しいものはどれですか？', 'イタリア語で「道」— 大口投資家の注文痕跡を読む技術体系', 'ラテン語で「構造」— テクニカル指標を統合した分析フレームワーク', '英語で「戦略」— 勝率を最大化するための売買アルゴリズム', 'スペイン語で「波」— 相場の波動パターンを分類する理論', 1, 'STRADAはイタリア語で「道」を意味し、チャートに残る大口投資家の注文痕跡を読み取る技術体系を指します。目的地に着くことだけが価値ではなく、道を歩き続けること自体が成長だという思想が込められています。', true, 1),
(13, '大口投資家が大量の買い注文を一度に出せない根本的な理由は何ですか？', '取引所のシステムが大口注文を自動的に分割処理する仕様になっているため', '金融規制上、1回の注文サイズに上限が設けられているため', '一度に大量買いすると価格が急騰し、自身の平均取得単価が悪化するため', '監督官庁への事前報告義務があり、承認を待つ必要があるため', 3, '大口は資金量が膨大なため、一度に大量買いを入れると価格が跳ね上がり、自分自身の平均取得価格を押し上げてしまいます。そのため価格への影響を最小限に抑えながら少しずつ買い集める必要があります。', true, 2),
(13, 'チャートの値動きの正体について、最も正確な表現はどれですか？', 'テクニカル指標のシグナルが蓄積・合成された結果', '買い手と売り手の力関係であり、注文の「数」ではなく「資金量」で決まる', 'トレーダーの心理的サイクルが可視化されたもの', '経済指標に対する市場参加者の理性的な価格発見のプロセス', 2, 'チャートの裏側では常に買い注文と売り注文が飛び交っていますが、相場を動かすのは注文の数ではなく資金量です。個人100人の買いよりも、機関1社の売りの方が相場に与える影響は圧倒的に大きくなります。', true, 3),
(13, '大口投資家と個人投資家の間に存在する「3つの格差」として正しい組み合わせはどれですか？', '資金量・スキル・テクノロジー', '情報・時間・テクノロジー', '資金量・情報・時間', '資金量・情報・スキル', 3, '大口と個人の間には「資金量」「情報」「時間」の3つの格差があります。大口は桁違いの資金と専門チームによる独自データを持ちますが、個人には「時間の自由」という逆転の武器があります。', true, 4),
(13, '個人投資家にだけ与えられた「3つの武器」について、空欄に入る正しい組み合わせを選んでください。  「① ＿＿：大口にはパフォーマンス期限があるが、個人にはない」 「② ＿＿：個人の注文は市場を動かさない。大口にはそれができない」 「③ ＿＿：四半期報告も上司もない。自分のペースで判断できる」', '① 時間の自由　② ステルス性能　③ 待つ権利', '① ステルス性能　② 待つ権利　③ 時間の自由', '① 待つ権利　② 時間の自由　③ ステルス性能', '① 待つ権利　② ステルス性能　③ 時間の自由', 4, '個人の3つの武器は「待つ権利」「ステルス性能」「時間の自由」です。大口には四半期報告やリスク管理規則という制約がありますが、個人は最高の場面だけを選び、気づかれずにエントリーし、自分のペースで動くことができます。', true, 5),
(13, '資金管理の三原則として正しい組み合わせはどれですか？', '1回2%ルール／利益確定を先に決める／証拠金維持率100%以上', '1回5%ルール／損切りはエントリー後に感覚で決める／証拠金維持率200%以上', '1回10%ルール／損切りはエントリー前に決める／証拠金維持率150%以上', '1回2%ルール／損切りはエントリー前に決める／証拠金維持率200%以上', 4, '資金管理の三原則は「1回のトレードで口座の2%以上を賭けない」「損切りはエントリー前に決める（逆指値を入れてからエントリー）」「証拠金維持率を200%以上に保つ」です。この3つを守ることで生存確率が劇的に上がります。', true, 6),
(13, '証拠金維持率について、最低ラインと理想水準の正しい組み合わせはどれですか？', '最低200%／理想300〜500%', '最低100%／理想200%', '最低150%／理想300%', '最低200%／理想500%以上', 1, '証拠金維持率は200%以上を最低ラインとし、理想は300〜500%です。維持率が高ければ、急激な相場変動でも強制ロスカットのリスクを回避でき、冷静な判断を保つことができます。', true, 7),
(13, 'STRADAが「手法ではなく構造を読む力」を重視する理由として最も適切なものはどれですか？', '全てのテクニカル手法は詐欺であり、個人投資家には役立たないから', '特定の手法は市場環境の変化で通用しなくなるが、注文構造を読む力は環境に左右されない基盤になるから', '一つの完璧な手法を見つければそれを永遠に使い続けるべきだから', '手法の開発はプロに任せ、個人投資家はフォロートレードに徹するべきだから', 2, '特定のテクニカル手法は市場環境が変わると機能しなくなりますが、大口の注文痕跡という根本的な構造を読む力は、環境が変わっても通用する基盤です。「手法を探し回る旅を終え、構造を読む力に集中する」ことが核心思想です。', true, 8),
(13, '口座資金50万円のトレーダーが2%ルールを厳守する場合、1回のトレードで許容できる最大リスク額はいくらですか？', '5,000円', '25,000円', '50,000円', '10,000円', 4, '2%ルールでは「1回のトレードで口座の2%以上を賭けない」と定めています。50万円 × 2% = 10,000円が1回の最大リスク額です。口座資金が減ればリスク額も自動的に減るため、破産を防ぐブレーキとして機能します。', true, 9),
(13, '機関投資家が「分割して買い集め、一気に利益を取る」とき、チャートに典型的に現れるパターンはどれですか？', '常にV字型の急反発パターンが連続して現れる', '一定期間のレンジや緩やかな動きの後に、急激な方向性のある動きが現れる', '上昇と下降が等間隔で繰り返す規則的な波動パターン', '出来高が常に一定水準を保ち、ローソク足のサイズが均一になる', 2, '大口は大量買いを一度に出せないため、価格帯を分割して少しずつ買い集めます。この期間はレンジや緩やかな動きとして現れ、買い集め完了後に一気に利益を取りに行くため急激な方向性のある動きが生まれます。', true, 10),
(13, '「ステルス性能」が個人投資家の武器である理由を最も正確に説明しているものはどれですか？', '個人の取引は税務申告の対象になりにくく、利益を隠せるから', '個人の注文は市場規模に対して極めて小さく、価格を動かさずにエントリー・エグジットできるから', '個人は取引所に登録しなくても取引できるため、身分を隠してトレードできるから', '個人はダークプール（非公開取引所）を利用できるため、注文が市場に反映されないから', 2, '個人の注文規模は市場全体に対してごくわずかであり、価格にほぼ影響を与えずに静かにエントリー・エグジットできます。機関投資家は大量注文で価格を動かしてしまいますが、個人はこの「気づかれない」という利点を活かせます。', true, 11),
(13, 'STRADAの学習において、資金管理が最も重視される理由は何ですか？', '資金管理を徹底すれば勝率が自動的に70%を超えるため', '資金管理は税金対策上で最も重要な要素だから', '分析力があっても資金管理が崩壊すれば一発で退場するため', 'プロのトレーダーは全員資金管理ツールを使っているため', 3, '分析力やエントリーテクニックがどれほど優れていても、資金管理が疎かなら1回の大きな負けや連敗で退場に追い込まれます。「生き残る」ことが全ての前提であり、資金管理はその基盤です。', true, 12),
(13, 'STRADAが「感情に頼らない、構造ベースの判断」を重視する理由として最も適切なものはどれですか？', '人間の感情は常に間違っており、感情ベースの判断は絶対に勝てないから', '感情の介入余地を減らすことで結果の一貫性が生まれ、長期的に安定するから', '感情的なトレードは法律で禁止されているため', '構造ベースの判断の方が常に感情的な判断より高い利益率を出せるから', 2, '感情に頼った判断は一貫性がなく、その日の気分や直前の勝敗に左右されやすくなります。構造ベースで判断することで感情の介入余地を減らし、「構造を読む → リスクを管理する → 感情を排除する → 生き残る」というサイクルを安定して回すことができます。', true, 13),
(13, '「待つ権利」が個人投資家にとって強力な武器である理由として、最も的確な説明はどれですか？', '外部からのパフォーマンス義務がなく、「今日はやらない」という選択が自由にできるから', '資金が少ないため、チャンスが来るまで待つしか方法がないから', '個人は機関投資家より忍耐力が高いことが統計的に証明されているから', '取引手数料が安いので、何度でもエントリーし直せるから', 1, '機関投資家には四半期報告や運用方針による制約があり、常にポジションを持つ義務に近い状況があります。一方、個人には外部からの義務がないため、「条件が揃わないからやらない」という選択が自由にできます。これが「待つ権利」の本質です。', true, 14),
(13, 'STRADAが「大口に勝つのではなく、大口の流れに乗る」という立場をとる理由として最も適切なものはどれですか？', '個人の技術力では大口に勝てる可能性がゼロだから', '法律で個人が大口と対抗する取引を行うことが禁止されているから', '大口は常に正しい判断をしていることが統計的に証明されているから', '大口の資金量は個人の何万倍もあり、真っ向から対抗するのは構造的に不可能だから', 4, '大口の資金量は個人の何万倍もあり、真っ向から対抗するのは不可能です。しかし、大口の注文がチャートに残す痕跡を読み、その流れに乗ることは十分に可能です。「勝つ」のではなく「乗る」という発想の転換がSTRADAの出発点です。', true, 15),
(13, '「感覚ではなく設計で動く」とは、具体的にどういう実践を指していますか？', '常に複数の経済指標を確認してからエントリーすること', '全てのトレードを自動売買プログラムに任せること', 'エントリー根拠・損切り位置・ロット数を事前にルール化し、感情が介入する余地を構造的に減らすこと', '毎回同じ通貨ペア・同じ時間帯でしかトレードしないこと', 3, '「設計で動く」とは、エントリー根拠・損切り位置・ロット数などを事前に明確に決め、そのルールに従って機械的に実行することです。感覚でエントリーすると認知バイアスに支配されやすくなり、一貫性が失われます。', true, 16),
(13, '次のシナリオについて、資金管理の三原則に照らして最も適切な判断はどれですか？  「口座資金100万円。証拠金維持率は現在180%。エントリーチャンスを見つけ、逆指値（ストップロス）を設定すればリスクは口座の1.5%に収まる。」', '証拠金維持率が200%を下回っているため、まずポジションを縮小するか入金して維持率を改善させてからエントリーを検討する', 'リスク1.5%は十分に小さいので、逆指値なしでエントリーしても安全である', 'リスクは2%以内に収まっているので、すぐにエントリーして問題ない', '維持率が低いほど利益を出しやすい状態なので、この機会を逃さずエントリーする', 1, '資金管理の三原則の第3条「証拠金維持率200%以上」を下回っています。リスクが2%以内であっても、維持率が基準を満たしていない場合は先にポジション縮小や入金で改善させる必要があります。三原則は全て同時に満たす必要があります。', true, 17),
(13, 'STRADAの全体設計における4つのステップの正しい順序はどれですか？', '武器を知る → 生き残る技術 → チャートを読む → 構造を知る', 'チャートを読む → 武器を知る → 生き残る技術 → 構造を知る', '生き残る技術 → 武器を知る → チャートを読む → 構造を知る', '構造を知る → 武器を知る → 生き残る技術 → チャートを読む', 1, 'STRADAの12週間は「武器を知る（W1-4）→ 生き残る技術（W5-8）→ チャートを読む（W9-10）→ 構造を知る（W11-12）」の順で構成されています。まず自分の強みを知り、次に生き残る術を学び、そして相場の読み方を深めていきます。', true, 18),
(13, '大口投資家が抱える3つの制約として正しい組み合わせはどれですか？', '1銘柄あたりの保有上限／日次の損失報告／監督官庁の承認が必要', 'レバレッジ1倍制限／月次報告の義務／特定銘柄の取引禁止', '大量注文を分割しなければならない／四半期報告の義務／リスク管理規則の遵守', '個人投資家と同じ取引ルールの適用／税申告の義務／取引時間の制限', 3, '大口投資家の制約は「大量注文を分割して出さざるを得ない」「四半期ごとのパフォーマンス報告」「リスク管理規則（ドローダウン制限等）」の3つです。これらの制約がチャートに痕跡として残り、それを読むのがSTRADAのアプローチです。', true, 19),
(13, '口座資金30万円のトレーダーが2%ルールを守る場合、1回のトレードで許容できる最大リスク額はいくらですか？', '3,000円', '30,000円', '15,000円', '6,000円', 4, '2%ルールでは口座資金の2%が1回の最大リスク額です。30万円 × 2% = 6,000円となります。証拠金維持率が十分に高くても、リスク額のルールは変わりません。', true, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(14, 'STRADAのゾーン分析において、「Level（点）」と「Zone（面）」の違いとして正しい説明はどれですか？', 'Levelは抵抗線、Zoneは支持線', 'Levelは過去の価格、Zoneは未来の予想価格', 'Levelはピンポイントの価格、Zoneは幅を持った価格帯', 'Levelは短期足でのみ確認できる、Zoneは長期足でのみ確認できる', 3, 'Levelは交差点のように一点の価格を指し、Zoneは商店街のように幅を持った価格帯を表します。大口の注文は一点に集中するのではなく帯状に分布するため、「面で待つ」ことが重要になります。', false, 1),
(14, 'ZB（Zone Buy）の定義として正しいものはどれですか？', '個人投資家の買い注文が集中した価格帯', 'LSの集合体で形成された売りゾーン', 'フィボナッチ61.8%に位置するサポートライン', 'LBの集合体で形成された買いゾーン', 4, 'ZB（Zone Buy）は、複数のLB（Level Buy＝大口買い注文の痕跡）が集合して形成される買いゾーンです。点（LB）が集まって面（ZB）になるという「点から面への変換」がゾーン分析の基本構造です。', false, 2),
(14, 'LS（Level Sell）が表すものとして正しいものはどれですか？', '個人投資家の損切り注文が並ぶ価格', '大口買い注文の痕跡（点）', '大口売り注文の痕跡（点）', '売りゾーンの全体像（面）', 3, 'LS（Level Sell）は大口の売り注文が残した痕跡をポイント（点）で示したものです。複数のLSが集合することでZS（Zone Sell＝売りゾーン）という面が形成されます。', false, 3),
(14, 'ゾーン分析において「面で待つ」ことが推奨される理由として最も適切なものはどれですか？', '面で待つ方が損切り幅を広く設定でき、負けにくくなるため', '線（点）で待つと価格がちょうどその位置に届かないことが多く、実際の注文は帯状に分布しているため', 'テクニカル指標の精度が面の方が高いため', '上位足の分析では線での判定が技術的に不可能なため', 2, '「線」で待つと価格がその一点に届かずに反転することが多々あります。大口の注文は特定の価格に集中するのではなく帯状に分布しているため、幅を持ったゾーン（面）で待つ方が現実的なアプローチです。', false, 4),
(14, 'ゴールデンゾーンとは何を指しますか？', '過去3回以上サポートとして機能した価格帯', '出来高が過去最多を記録した価格帯', 'フィボナッチ50%〜61.8%のリトレースメントとゾーンが重なるポイント', '200MAと価格が交差する価格帯', 3, 'ゴールデンゾーンは、フィボナッチの50%〜61.8%リトレースメント帯とゾーンが重なるスイートスポットです。複数の分析ツールの結果が一致するため、最も反応しやすい重要なエリアとなります。', false, 5),
(14, '次の記述のうち、LBとZBの関係として正しいものはどれですか？', 'LBが集合してZBを形成する。つまり「点」が集まって「面」になる', 'ZBはLBを上位足で確認し直したもの', 'LBとZBは別々の分析手法で、互いに関連はない', 'LBはZBの中で最も重要な一点だけを抽出したもの', 1, 'LB（Level Buy）は大口の買い注文の痕跡を点として捉え、複数のLBが集合したものがZB（Zone Buy）という買いゾーン（面）になります。同様に、LSが集合してZS（Zone Sell）が形成されます。', false, 6),
(14, 'ゾーンの強さを判定する5要素に含まれないものはどれですか？', '出来高の増減率', '出発の勢い', 'フレッシュさ', '時間軸', 1, 'ゾーンの強さを判定する5要素は「出発の勢い」「フレッシュさ」「時間軸」「合流」「トレンドとの一致」です。出来高の増減率はワイコフ分析の要素であり、ゾーンの強さ判定には含まれません。', false, 7),
(14, 'ゾーンの強さ要素のひとつ「フレッシュさ」が最も高い状態とはどのような状況ですか？', '過去3回価格が到達し、その都度反発を確認したゾーン', '直近の経済指標発表後に形成されたゾーン', 'まだ一度も価格が戻ってきていない、未到達のゾーン', '出来高が直近で最も多く記録されたゾーン', 3, 'フレッシュさとは「まだ価格がそのゾーンに到達していない」ほど高いと評価されます。未到達のゾーンが最強であり、再到達の回数が増えるほどフレッシュさが失われ、ゾーンの効力は低下します。', false, 8),
(14, 'ゾーンの強さにおいて「時間軸」が意味する内容として正しいものはどれですか？', '取引時間帯（東京・ロンドン・NY）のどれで形成されたか', '1日のうち最も出来高が多い時間に形成されたゾーンほど強い', '上位足で確認されたゾーンほど強い', 'ゾーンが形成されてからの経過時間が短いほど強い', 3, 'ゾーンの強さは、それがどの時間軸の足で確認できるかによって大きく変わります。日足や週足などの上位足で確認できるゾーンは、4H足や1H足などの下位足のゾーンより強いと評価されます。', false, 9),
(14, 'S級ゾーンの条件として正しい組み合わせはどれですか？', '日足以上 / フレッシュ / フィボ50〜61.8%合流 / トレンド一致', '週足以上 / 再到達2回以内 / フィボ23.6%合流 / 出来高増加', '4H足 / 再到達1回以内 / フィボ38.2%合流 / レンジ方向と一致', '日足以上 / 再到達3回以内 / フィボ78.6%合流 / トレンド一致', 1, 'S級ゾーンの条件は「日足以上で確認」「フレッシュ（未到達）」「フィボナッチ50%〜61.8%と合流」「トレンド方向と一致」の全てを満たすことです。これら最高条件が揃ったゾーンが最も信頼性が高いとされます。', false, 10),
(14, 'B級ゾーンの特徴として正しいものはどれですか？', '日足で確認でき、フレッシュで、フィボナッチと合流する', '4H足で確認でき、フレッシュで、何らかの合流がある', '上位足で確認でき、トレンドに逆行しているが合流がある', '再到達1〜2回あり、合流なし、下位足のみで確認できる', 4, 'B級ゾーンは「価格の再到達が1〜2回ある」「他ツールとの合流がない」「下位足のみで確認できる」という条件に当てはまります。S級・A級に比べて信頼性が低く、トレードの根拠としては慎重な判断が必要です。', false, 11),
(14, '価格が買いゾーンに到達した際、推奨される正しい対応はどれですか？', 'ゾーン到達と同時に即座に成行買い注文を入れる', 'ゾーン到達後は損切り幅を広く設定してエントリーする', 'ゾーン到達を確認したら、すぐに指値注文を入れて待機する', 'ゾーン到達はあくまで準備エリアであり、ピンバー・包み足等のプライスアクション確認後に判断する', 4, 'ゾーンは「ここで反応する可能性がある」という準備エリアに過ぎません。到達即エントリーはギャンブルと同じであり、ピンバーや包み足などのプライスアクションによる反転確認を待ってから判断するのが正しい手順です。', false, 12),
(14, '次のうち、「効きにくいゾーン」の特徴として正しいものはどれですか？', '価格の再到達が3回以上ある', '出発の勢いが強い', 'フィボナッチ等との合流がある', '上位足で確認できる', 1, '再到達が3回以上あるゾーンは効きにくくなります。その他にも「下位足のみで確認できる」「他ツールとの合流がない」「トレンドに逆行している」などは効きにくいゾーンの特徴です。ゾーンは消化されるほど効力が落ちます。', false, 13),
(14, '次のシナリオを読んで、このゾーンのグレードとして最も適切なものを選んでください。  「日足で確認された買いゾーン。価格はまだ一度もこのゾーンに戻っていない。フィボナッチのリトレースメント58%付近と重なっており、上位足の上昇トレンド方向と一致している。」', 'A級', 'S級', 'B級', 'グレード外（条件不足）', 2, '日足以上で確認（S級条件）、フレッシュ（未到達）、フィボ50〜61.8%と合流、トレンド方向と一致。S級の4条件すべてを満たしています。', false, 14),
(14, '次のシナリオを読んで、このゾーンのグレードとして最も適切なものを選んでください。  「4時間足で確認された売りゾーン。価格はまだ一度も戻っていない。フィボナッチ38.2%付近とは離れているが、直近の高値と重なる。」', 'S級', 'B級', 'グレード判定不能', 'A級', 4, 'A級の条件は「4H足で確認」「フレッシュ」「合流あり」です。このゾーンは4時間足・フレッシュ・直近高値との合流があるためA級に該当します。フィボナッチとの合流がなくても、何らかの合流があればA級条件を満たします。', false, 15),
(14, 'ゾーン分析において「合流」とは何を意味しますか？', '複数のLBが同じ価格帯に集中していること', 'フィボナッチ等の他の分析ツールの結果とゾーンが重なること', '複数の通貨ペアで同じゾーンが確認できること', '東京・ロンドン・NYの全セッションでゾーンが形成されること', 2, '合流とは、フィボナッチリトレースメントやその他の分析ツールで示される水準とゾーンが重なることを指します。複数の分析結果が一致するほど、そのゾーンの信頼性が高まります。', false, 16),
(14, '「出発の勢い」が強いゾーンほど信頼性が高い理由として最も適切な説明はどれですか？', '急騰や急落の背後には大口の大量注文が存在し、その痕跡が濃いほどゾーンとしての根拠が強いため', '急激な動きの後はテクニカル指標が全て買いシグナルを出すため', '勢いが強いほど損切り幅を小さくできるため', '急激な動きの後は必ず反転するという統計的傾向があるため', 1, '急激な価格変動（急騰や急落）は、その背後に大口の大量注文があったことを示唆します。この「出発の勢い」が強いほど大口の関与が濃厚で、残された注文痕跡も明確になるため、ゾーンとしての信頼性が高まります。', false, 17),
(14, '次の記述のうち、トレンドに逆行するゾーンについて正しいものはどれですか？', 'トレンドに逆行するゾーンは逆張りのチャンスとして積極的に狙うべき', 'トレンドに逆行するゾーンは、他の条件を満たしていても効きにくい', 'トレンドに逆行するゾーンは、時間軸が上位であれば信頼性が変わらない', 'トレンドに逆行するゾーンは、出発の勢いが強ければS級になりうる', 2, 'ゾーンの強さ5要素のひとつ「トレンドとの一致」は非常に重要です。他の条件を満たしていても、トレンドに逆行するゾーンは効きにくくなります。トレンド方向に一致するゾーンの方が反応する確率が高くなります。', false, 18),
(14, '次のシナリオについて、最も適切な判断を選んでください。  「15分足で確認された買いゾーンに価格が到達した。このゾーンは過去に2回価格が到達して反発している。フィボナッチ等との合流はなく、直近のトレンドは下降トレンドである。」', '過去2回の反発実績があるため、信頼性は高く即エントリーすべき', '下位足のみ・合流なし・トレンド逆行・再到達済みと条件が弱く、エントリーを見送るべき', '15分足で2回の反発実績はA級以上の根拠になるため、慎重にエントリーを検討すべき', 'フレッシュではないが、反発実績があるため小ロットでエントリーすべき', 2, 'このゾーンは下位足のみ（15分足）・合流なし・トレンドに逆行・再到達2回済みと、効きにくいゾーンの特徴ばかり揃えています。個別の条件が弱いことに加え、複数の弱点が重なっているため見送りが適切です。', false, 19),
(14, 'A級ゾーンの条件として正しい組み合わせはどれですか？', '4H足 / 再到達1回以内 / フィボ38.2%合流 / レンジ相場', '下位足 / 再到達なし / 合流なし / トレンド一致', '日足以上 / フレッシュ / フィボ50〜61.8%合流 / トレンド一致', '4H足 / フレッシュ / 何らかの合流あり', 4, 'A級ゾーンの条件は「4H足で確認」「フレッシュ（未到達）」「何らかの合流がある」の3点です。S級ほど厳しくないものの、実践で十分に機能する信頼性の高いゾーンです。  ---  ## 正解分布 | 選択肢 | 問題番号 | 件数 | |--------|----------|------| | A | Q6, Q7, Q10, Q13, Q17 | 5 | | B | Q4, Q14, Q16, Q18, Q19 | 5 | | C | Q1, Q3, Q5, Q8, Q9 | 5 | | D | Q2, Q11, Q12, Q15, Q20 | 5 |  ## 出題バランス | カテゴリ | 問題番号 | 件数 | |----------|----------|------| | 用語確認 | Q1, Q2, Q3, Q4, Q6 | 5 | | 概念理解 | Q5, Q7, Q8, Q9, Q10, Q11, Q13, Q16 | 8 | | 応用・判断 | Q12, Q14, Q15, Q17, Q18, Q19, Q20 | 7 |', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(15, '推進波の特徴として正しいものはどれですか？', 'トレンドと逆方向に動き、出来高が減少する', 'トレンド方向に動き、ローソク足が大きく角度が急である', 'トレンド方向に動くが、出来高は減少傾向にある', 'トレンドと逆方向に動き、ローソク足が大きい', 2, '推進波はトレンド方向に力強く動き、出来高が増加し、ローソク足が大きく、角度が急になるのが特徴です。これに対し修正波はトレンドと逆方向に弱く動きます。', false, 1),
(15, '修正波の特徴として正しい組み合わせはどれですか？', '出来高増加・ローソク足大きい・角度急', 'トレンド方向・力強い・角度緩やか', '出来高減少・ローソク足小さい・角度緩やか', 'トレンド方向・出来高減少・ローソク足大きい', 3, '修正波はトレンドと逆方向に動き、力が弱く、出来高が減少し、ローソク足が小さく、角度が緩やかになります。これらは推進波と対照的な特徴です。', false, 2),
(15, 'エリオット波動の基本構造として正しいものはどれですか？', '上昇3波＋下降2波の計5波', '推進5波＋修正3波（A-B-C）の計8波', '推進3波＋修正5波（A-B-C）の計8波', '上昇5波＋下降5波の計10波', 2, 'エリオット波動はトレンド方向に進む推進5波（1〜5波）と、トレンドに逆行する修正3波（A・B・C波）の計8波で一つのサイクルを構成します。', false, 3),
(15, 'エリオット波動の第1波の特徴として最も適切なものはどれですか？', '最も値幅が大きく、多くのトレーダーが参入する波', '天井を示唆するダイバージェンスがよく出現する波', '始まりの波だが、ほとんどの人が気づかず後からわかることが多い', '直前のトレンドの反転を確認させる、最も恐怖の強い波', 3, '第1波は新しいトレンドの始まりの波ですが、当時はほとんどのトレーダーが気づかず、後から振り返って「これが1波だった」と判明することが多いのが特徴です。', false, 4),
(15, 'エリオット波動の第2波における「鉄則」とは何ですか？', '3波の起点を割り込んではならない', '5波の高値を超えなければならない', '1波の起点（出発点）を割り込んではならない', 'A波の安値を必ず更新しなければならない', 3, '第2波はふるい落としの波で恐怖がピークに達しますが、1波の起点（出発点）を割り込まないことが鉄則です。起点を割り込んだ場合、エリオット波動のカウント自体が見直しの対象になります。', false, 5),
(15, 'エリオット波動において「本流」と呼ばれ、最も狙うべきとされる波はどれですか？', '第1波 — 最初に動くため最も安全', '第5波 — 最後のひと押しで確実性が高い', '第3波 — 確認済みの流れで最大の値幅を持つ', 'B波 — 偽りの回復だが、順張りのチャンス', 3, '第3波は「本流」と呼ばれ、最も大きな値幅を持ち、出来高が急増します。1波が確認済みであることから参入の根拠が立ちやすく、5波のような天井掴みリスクもないため最も狙いやすい波です。', false, 6),
(15, '第5波の注意点として正しいものはどれですか？', '出来高が最も急増し、1波の起点を割り込むリスクがある', '3波よりも値幅が大きく、最も利益を狙いやすい波', '勢いが鈍り、ダイバージェンスが出現し、天井掴みのリスクが高い', '直前の4波と価格帯が重なるため、エントリーを避けるべき波', 3, '第5波はトレンドの最後のひと押しですが、勢いが鈍っており、オシレーターとのダイバージェンスが出現しやすくなります。天井を掴むリスクが高いため慎重な対応が求められます。', false, 7),
(15, 'エリオット波動の修正波A波・B波・C波について、正しい説明はどれですか？', 'A波は本格的転換、B波はふるい落とし、C波は偽りの回復', 'A波は転換の始まり、B波は偽りの回復で罠、C波は本格的転換でA波の安値を割り込む', 'A波は最も値幅が大きい、B波は押し目確認、C波は新たなトレンドの始まり', 'A波は利確の調整、B波は最後のひと押し、C波は1波の起点への回帰', 2, 'A波は転換の始まりで「ただの押し目」と楽観視されがち、B波は偽りの回復で最も多い失敗パターン、C波は本格的な転換でA波の安値を割り込むという性格を持っています。', false, 8),
(15, '200MA（200日移動平均線）の役割として正しいものはどれですか？', 'エントリーの直接的な根拠となる指標', '短期の売買タイミングを判定するオシレーター', '方向を示すコンパスであり、ゾーンの信頼度を上げる補助ツール', 'フィボナッチリトレースメントと組み合わせるための基準線', 3, '200MAは方向を示すコンパスであり、エントリーの直接的な根拠ではなく、ゾーン分析などと組み合わせて信頼度を高める補助ツールとして使われます。価格が200MAの上にあれば上昇トレンド、下にあれば下降トレンドと判断します。', false, 9),
(15, 'フラクタル構造とはどのような概念ですか？', '同じ時間軸の中で波動が3回繰り返される構造', '上位足の1波の中に下位足の3波構造があるという考え方', '上位足の3波の中に下位足の5波構造があるという考え方', 'すべての時間軸で波動の形が完全に一致するという法則', 3, 'フラクタル構造とは、上位足の3波の中に下位足の5波構造が内包されているという概念です。これにより、上位足で方向を確認し、下位足で起点を見つけるという二段階のアプローチが可能になります。', false, 10),
(15, '推進波と修正波の違いを実践で活かす際、正しいスタンスはどれですか？', '推進波でも修正波でも、エントリーチャンスがあれば積極的に乗る', '推進波に乗り、修正波では待つ。修正波でエントリーすると逆行に巻き込まれる', '修正波は推進波よりリスクが低いため、修正波中心にエントリーする', '推進波は値幅が大きすぎるため、修正波の反発を狙う方が安全', 2, '推進波はトレンド方向に力強く動くため、そこに乗ることが推奨されます。修正波では待つのが正解であり、修正波でエントリーすると逆行に巻き込まれるリスクが高くなります。', false, 11),
(15, '第3波を狙うべき理由として最も適切でないものはどれですか？', '1波がすでに確認済みであり、トレンドの方向性が見えている', '推進波の中で最も値幅が大きく、リスクリワードが良い', '天井掴みのリスクがなく、エントリー後の逆行リスクが最も低い', '出来高が急増しており、多くの参加者が同じ方向に動いている証拠がある', 3, '「天井掴みリスクがない」のは5波と比較した場合の利点ですが、「逆行リスクが最も低い」は言い過ぎです。3波であってもトレードにリスクは伴います。3波を狙う主な理由は、1波が確認済みで流れが見えることと、最大の値幅でリスクリワードが良いことです。', false, 12),
(15, '第4波の特徴として正しいものはどれですか？', '1波の価格帯と重ならない範囲で調整する波', '直前のトレンドの起点を割り込む、恐怖のピーク', '最も値幅が大きく、出来高が急増する波', '偽りの回復で、最も多い失敗パターンを生む波', 1, '第4波は3波での利確による調整の波ですが、1波の価格帯と重ならないのが特徴です。このルールはエリオット波動のカウントを検証する際の重要な基準の一つになります。', false, 13),
(15, 'B波が「最も多い失敗パターン」を生む理由として最も適切な説明はどれですか？', 'B波は値幅が最も大きく、損失が拡大しやすいため', 'B波は新たな上昇トレンドの始まりと錯覚させる偽りの回復であるため', 'B波は1波の起点を割り込むため、カウントが崩壊するため', 'B波は出来高が急増し、多くのトレーダーが参入してしまうため', 2, 'B波は一時的に価格が回復する「偽りの回復」であり、多くのトレーダーが「トレンド再開だ」と錯覚して買い（売り）を入れてしまいます。その後C波で本格的に転換するため、罠にはまったトレーダーが大きな損失を被るのが最も多い失敗パターンです。', false, 14),
(15, '次のシナリオを読んで、現在どの波にいる可能性が最も高いかを選んでください。  「上昇トレンドの途中で、直近の安値が前回の安値を下回らず、押し目から反発し始めた。出来高が急増しており、これまでの波の中で最も勢いがある。」', '第1波', '第5波', '第3波', 'A波', 3, '前回の安値を下回らない押し目（2波の終わり）から反発し、出来高が急増して最も勢いがあるという特徴は、第3波の始まり〜進行中の典型的なパターンです。第3波は推進波の中で最も力強く、出来高が最も増加します。', false, 15),
(15, '200MAを使った相場環境の判断として正しいものはどれですか？', '価格が200MAにタッチしたら、必ず反発する', '価格が200MAの上にあれば上昇トレンド、下にあれば下降トレンドと判断する', '200MAの傾きが上を向いていれば、下降トレンドでも買いでエントリーする', '200MAは短期売買のエントリー・エグジットのシグナルとして使う', 2, '200MAは方向を示すコンパスであり、価格が200MAの上にあれば上昇トレンド、下にあれば下降トレンドと判断します。ただし、これはエントリーの直接的な根拠ではなく、トレンド方向を確認する補助的な役割です。', false, 16),
(15, 'フラクタル構造を活用した実践的なアプローチとして正しいものはどれですか？', '下位足で波を数え、その結果を上位足に当てはめて方向を決める', '上位足で方向を確認し、下位足でエントリーの起点を見つける', '上位足と下位足で完全に同じ波動カウントが一致した場合のみエントリーする', '下位足の波動をすべてカウントし終えてから上位足を確認する', 2, 'フラクタル構造の実践的な活用方法は、まず上位足でトレンド方向を確認し、その後に下位足に切り替えてエントリーの起点を見つけるという二段階アプローチです。上位足の大方向に沿って下位足でタイミングを測ります。', false, 17),
(15, '次のシナリオを読んで、最も適切な判断を選んでください。  「日足で価格が200MAの下にある。4時間足で上昇の5波カウントができ、現在5波付近に達している。オシレーターにダイバージェンスが出現している。」', '200MAが下にあるため下降トレンドであり、5波の上昇は修正波の可能性が高い。買いエントリーは避けるべき', '5波まで上昇している勢いに乗って、追加の買いエントリーをする', 'ダイバージェンスは無視し、200MAのブレイクアウトを待ってからエントリーする', '4時間足の5波は日足の3波の中にある可能性が高く、積極的に買いを入れる', 1, '日足で200MAの下にあれば下降トレンドの可能性が高く、4時間足の5波カウントは下降トレンド中の修正波（上昇）の一部に過ぎない可能性があります。5波付近でダイバージェンスが出ていれば天井掴みリスクも高く、大方向に逆行するエントリーは避けるべきです。', false, 18),
(15, '波動カウントに対する正しいスタンスはどれですか？', 'すべての波を完璧にカウントできないとエントリーしてはならない', '1波から5波まで完璧にカウントできた場合のみ3波を狙う', '完璧なカウントは不要であり、「だいたい3波目あたり」で十分実践に役立つ', '波動カウントは主観的すぎるため、一切参考にすべきではない', 3, '実践では完璧な波動カウントは不要です。「だいたい3波目あたり」という大まかな判断でも、トレンド方向に乗るという目的には十分に機能します。完璧を求めすぎるとエントリーの機会を失います。', false, 19),
(15, '次のシナリオを読んで、最も注意すべきリスクを選んでください。  「上昇トレンドが続いている銘柄で、直近高値をわずかに更新した後、押し目が来た。多くのトレーダーが「押し目買いのチャンス」と言っている。しかし、オシレーターは直近高値時の数値を下回っている。」', '第3波の始まりであり、押し目買いの絶好のチャンスである', 'ダイバージェンスが示唆する第5波の天井圏であり、B波の罠の可能性がある', '第2波のふるい落としが終わった直後であり、3波開始の合図である', 'A波の転換が始まっており、C波で大きく下落する可能性があるため空売りすべき', 2, '直近高値を更新したもののオシレーターがそれを下回っているのはダイバージェンスの発生です。これは第5波の特徴であり、その後の押し目はB波（偽りの回復）の可能性があります。「押し目だ」と楽観視して飛び込むと、C波での本格的転換に巻き込まれる典型的な罠のパターンです。  ---  ## 正解分布 | 選択肢 | 問題番号 | 件数 | |--------|----------|------| | A | Q1, Q4, Q10, Q13, Q18 | 5 | | B | Q3, Q6, Q8, Q11, Q15 | 5 | | C | Q2, Q5, Q9, Q17, Q19 | 5 | | D | Q7, Q12, Q14, Q16, Q20 | 5 |  ## 出題バランス | カテゴリ | 問題番号 | 件数 | |----------|----------|------| | 用語確認 | Q1, Q2, Q3, Q4, Q5 | 5 | | 概念理解 | Q6, Q7, Q8, Q9, Q10, Q13, Q14, Q16 | 8 | | 応用・判断 | Q11, Q12, Q15, Q17, Q18, Q19, Q20 | 7 |', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(16, 'プロスペクト理論が説明する投資家の行動パターンとして正しいものはどれですか？', '人間は利益の喜びより損失の痛みを約2倍強く感じるため、利小損大になりやすい', '人間は損失の痛みより利益の喜びを約2倍強く感じるため、利益を追求しすぎる', '人間は利益と損失を同じように感じるが、損失の確定を先延ばしする傾向がある', '人間は利益が大きいほど冷静になるため、大きな利益を狙う方が合理的である', 1, 'プロスペクト理論は、人間が損失の痛みを利益の喜びの約2倍強く感じることを示しています。このため利益は早く確定（利小）し、損失は先延ばし（損大）する傾向が生まれます。', false, 1),
(16, '確証バイアスとはどのような心理的傾向ですか？', '自分が所有しているものに高い価値を感じて手放せなくなる傾向', '自分の判断に都合のいい情報だけを集め、都合の悪い情報を無視する傾向', '過去に投じたコストを惜しんで合理的な判断ができなくなる傾向', '現状を維持したがるあまり、必要な行動変化を先延ばしする傾向', 2, '確証バイアスは、自分の考えを支持する情報だけを集め、反する証拠を無視する傾向です。自分のポジションに都合のいいニュースだけを見るなど、投資判断を歪める原因になります。', false, 2),
(16, '「ここまで耐えたのだから」と損切りを先延ばしする心理を何と呼びますか？', 'プロスペクト理論', '確証バイアス', 'サンクコスト', '保有効果', 3, 'サンクコスト（埋没費用）は、すでに使ってしまった取り戻せないコストを惜しんで判断が歪む心理です。投資では「ここまで我慢したのだから」と損切りを遅らせ、損失を拡大させる典型的な罠です。', false, 3),
(16, '保有効果の説明として正しいものはどれですか？', '自分の分析が正しいと過信し、反対の証拠を無視してしまう心理', '大きな損失を出した後に取り戻そうとロットを上げてしまう心理', '一度持ったポジションに過大な価値を感じ、手放せなくなる心理', '変化を避けたがるあまり、含み損を放置してしまう心理', 3, '保有効果は、自分が持っているものに実際より高い価値を感じて手放せなくなる心理です。マグカップ実験では、持っているグループが持っていないグループの約2.5倍の値段をつけました。', false, 4),
(16, '「含み損が膨らんでいるのに、何もできない」という状態を引き起こす認知バイアスはどれですか？', 'プロスペクト理論', '現状維持バイアス', '確証バイアス', 'リベンジ心理', 2, '現状維持バイアスは、変化を避けたがる心理です。「何もしない方が安全」と感じるため、損切りすべき状況でも放置（塩漬け）してしまい、損失の拡大を招きます。', false, 5),
(16, '5つの認知バイアスが重なって生まれる負けパターンの流れとして正しいものはどれですか？', '確証バイアス → リベンジ心理 → 利小損大 → 破滅', '利小損大 → 損切り遅延 → 塩漬け → 破滅', '塩漬け → 利小損大 → リベンジ心理 → 確証バイアス', 'リベンジ心理 → 保有効果 → サンクコスト → 利小損大', 2, 'プロスペクト理論による利小損大から始まり、損失回避による損切り遅延、現状維持バイアスによる塩漬けへと連鎖し、最終的に破滅に至るのが典型的な負けパターンです。', false, 6),
(16, '損切りできない脳の正体を説明する3つの心理の連鎖として正しいものはどれですか？', '確証バイアス → 現状維持バイアス → 恐怖', '保有効果 → リベンジ心理 → 確証バイアス', 'サンクコスト → 保有効果 → リベンジ心理', 'リベンジ心理 → サンクコスト → 現状維持バイアス', 3, '損切りできない典型的な連鎖は、まず「ここまで耐えたから」（サンクコスト）、次に「手放したくない」（保有効果）、そして損失拡大後に「取り戻さないと」（リベンジ心理）へと進行します。', false, 7),
(16, '損切りを「保険料」と捉える理由として最も適切なものはどれですか？', '損切りをすることで税金上の優遇措置が受けられるから', '小さな損失を払うことで大きな損失（破産）を防げるから', '損切りの回数を重ねることで自動的に勝率が上がるから', '損切りした金額は後で必ず回収できる仕組みになっているから', 2, '損切りは失敗ではなく、大損を防ぐための保険です。火災保険と同じで、小さな費用（損失）を払うことで、破産級の損失を未然に防ぐことができます。', false, 8),
(16, 'メタ認知の3ステップとして正しい順番はどれですか？', '距離を置く → 気づく → ルールに戻る', '気づく → 距離を置く → ルールに戻る', 'ルールに戻る → 気づく → 距離を置く', '気づく → ルールに戻る → 距離を置く', 2, 'メタ認知は「気づく（今何を感じているか）」「距離を置く（感情と自分を切り離す）」「ルールに戻る（事前に決めたルールに従う）」の順で実行します。', false, 9),
(16, '4つの暴走感情とその正体の組み合わせとして正しいものはどれですか？', '恐怖＝もっと欲しい、欲望＝損を認められない、焦り＝過去に囚われる、後悔＝乗り遅れる恐怖', '恐怖＝乗り遅れる恐怖、欲望＝過去に囚われる、焦り＝損を認められない、後悔＝もっと欲しい', '恐怖＝損を認められない、欲望＝もっと欲しい、焦り＝乗り遅れる恐怖、後悔＝過去に囚われる', '恐怖＝過去に囚われる、欲望＝乗り遅れる恐怖、焦り＝もっと欲しい、後悔＝損を認められない', 3, '恐怖は損を認められない感情、欲望はもっと欲しくなる感情、焦り（FOMO）は乗り遅れる恐怖、後悔は過去に囚われる感情です。これらが連鎖して暴走すると判断力を失います。', false, 10),
(16, '5秒ルール（5問チェック版）の5つの質問として含まれないものはどれですか？', '計画通りのエントリーか？', '損切り位置は決まっているか？', '過去10回の勝率は50%以上か？', '上位足と整合しているか？（逆張りではないか）', 3, '5秒ルールの5問は「計画通りか」「損切りは決まっているか」「RR1:2以上か」「上位足と整合しているか」「夜眠れるロット数か」です。過去の勝率の確認は含まれません。', false, 11),
(16, '保有効果を打破するための「最重要の問いかけ」として正しいものはどれですか？', '「今日の損益はプラスだろうか？」', '「もし今ポジションを持っていなかったら、このレートでエントリーするか？」', '「過去に同じパターンで勝てたか？」', '「この通貨ペアは今上昇トレンドにあるか？」', 2, '「もし今ポジションを持っていなかったら、このレートでエントリーするか？」——答えがNoなら、保有効果にとらわれずそのポジションを手放すべきです。', false, 12),
(16, '「5秒で逃すチャンスは、そもそもあなたのチャンスではなかった」という言葉が意味することとして最も適切なものはどれですか？', 'チャンスは頻繁に来るので、1つ見逃しても気にする必要はない', '5秒の冷静チェックに通らないエントリーは、計画外の感情的なものである', 'エントリーの判断は5秒以内に直感で行うべきである', 'どんなチャンスも5秒で判断しなければ次のチャンスに切り替えるべきである', 2, '5秒ルールのチェックで弾かれるエントリーは、元々計画になかった感情的な飛び乗りです。5秒止まることで防げる損失の方が、逃すチャンスよりはるかに大きいという意味です。', false, 13),
(16, '次のシナリオを読んで、作動している認知バイアスを答えてください。  「USD/JPYの買いポジションを持っている。含み損が-3万円まで膨らんだが、SNSで「ドル円は上昇トレンド」という投稿を3つ見つけて安心し、損切りを見送った。逆に「下落リスク」を指摘する記事は読まなかった。」', 'プロスペクト理論', '確証バイアス', '保有効果', 'サンクコスト', 2, '自分のポジションに都合のいい情報（上昇トレンドの投稿）だけを集め、不都合な情報（下落リスクの記事）を無視しているのが確証バイアスの典型的なパターンです。', false, 14),
(16, '次のシナリオを読んで、最も優先すべき行動を選んでください。  「連敗が続いてイライラしている。「今日中に取り返そう」とロットを2倍に上げてエントリーしようとしている。上位足は下降トレンド、エントリー方向は買い。」', '焦り（FOMO）に対処するため、上位足の下降トレンドに従って売りエントリーに切り替える', 'ロットを2倍にするのではなく、いつものロットで買いエントリーする', 'リベンジトレードの典型パターンなので、エントリーを見送りチャートを閉じる', '「今日中に取り返す」という目的を達成するため、損切り幅を広く設定してエントリーする', 3, '連敗後の「取り返したい」という衝動はリベンジ心理です。上位足に逆行し、ロットを上げ、感情で動いている状態はリベンジトレードの典型であり、エントリーを見送るべきです。', false, 15),
(16, '次のケースで、5秒ルールの5問チェックを適用した場合の判断として正しいものはどれですか？  「日足上昇トレンド中。4時間足のZBに到達し、ピンバーが出た。損切りは決まっている。RR比は1:1.8。ロットは夜眠れるサイズ。計画通りのエントリー。」', '全ての条件を満たしているのでエントリーする', 'RR比が1:2未満なのでNoが1つあり、見送りまたは条件が整うまで待つ', 'ロットが適正ならRR比は関係ないのでエントリーする', 'ピンバーが出ているならRR比の確認は不要なのでエントリーする', 2, '5秒ルールは5つすべてYesでなければエントリー不可です。RR比1:1.8は「RR1:2以上か？」という質問に対してNoとなり、1つでもNoがあれば見送りが正解です。', false, 16),
(16, '次のシナリオを読んで、作動しているバイアスの連鎖として最も適切なものを選んでください。  「含み損-2万円のポジション。「ここまで耐えたのだから」と損切りを見送った。含み損が-5万円に拡大。「自分のポジションを手放したくない」とさらに保有し続けた。ついに-10万円で損切り。「すぐに取り返さないと」とロットを3倍にして再エントリーした。」', 'プロスペクト理論 → 確証バイアス → 現状維持バイアス', '現状維持バイアス → 確証バイアス → プロスペクト理論', 'サンクコスト → 保有効果 → リベンジ心理', '保有効果 → サンクコスト → 確証バイアス', 3, '「ここまで耐えたから」がサンクコスト、「手放したくない」が保有効果、「すぐに取り返さないと」がリベンジ心理です。この3つの連鎖が損切りできない人の典型的な破滅パターンです。', false, 17),
(16, '恐怖（Fear）による暴走を防ぐ対策として最も有効なものはどれですか？', '勝率を上げるために分析をさらに細かくする', 'エントリー前に逆指値注文を入れておき、感情の介入余地をなくす', '小さいロットで何度も練習して恐怖に慣れる', '損失を認めない自信をつけるために勝率の高い手法を探す', 2, '恐怖は「損を認められない感情」です。エントリー前に逆指値（損切り注文）を設定しておけば、損切りラインに達した時点で自動的に決済され、感情の介入余地がなくなります。', false, 18),
(16, '次のシナリオを読んで、メタ認知の3ステップを適用した場合の正しい順番を選んでください。  「チャートを見ていて「乗り遅れる！」と焦ってエントリーしようとした瞬間に立ち止まった。」', '「今、焦り（FOMO）を感じている」と認識する → 「これは一時的な脳の反応だ」と切り離す → 5秒ルールのチェックリストに従う', '5秒ルールのチェックリストに従う → 「今、焦りを感じている」と認識する → 「これは一時的な脳の反応だ」と切り離す', '「これは一時的な脳の反応だ」と切り離す → 5秒ルールのチェックリストに従う → 「今、焦りを感じている」と認識する', 'エントリーしてから感情を分析する → 次回同じ失敗をしないようルールを見直す → 新しいルールを記録する', 1, 'メタ認知は「気づく（感情にラベルを貼る）→ 距離を置く（感情と自分を切り離す）→ ルールに戻る（事前のルールに従う）」の順です。感情に名前をつけるだけで行動の質が変わります。', false, 19),
(16, '次のシナリオを読んで、最も適切な判断を選んでください。  「EUR/USDの買いポジションを持っている。含み益+1.5万円。「まだ上がるかも」と思ったが、同時に「利益が消えたら嫌だ」という不安も感じた。利確目標の+3万円にはまだ届いていない。」', '「まだ上がるかも」という欲望に従い、そのまま保有し続ける', '利益が消える恐怖から、利確目標より早く利益を確定させる', 'プロスペクト理論による利小損大の兆候と気づき、事前に決めた利確目標まで機械的に待つ', '含み益が出ているうちにロットを追加して利益を最大化する', 3, '「利益が消えたら嫌だ」と早く利確したくなるのはプロスペクト理論による反応です。メタ認知で気づき、事前に決めたルール（利確目標+3万円）に戻って機械的に実行するのが正しい対処です。  ---  ## 正解分布 | 選択肢 | 問題番号 | 件数 | |--------|----------|------| | A | Q1, Q6, Q9, Q16, Q19 | 5 | | B | Q2, Q5, Q8, Q12, Q15 | 5 | | C | Q3, Q7, Q10, Q14, Q17 | 5 | | D | Q4, Q11, Q13, Q18, Q20 | 5 |  ## 出題バランス | カテゴリ | 問題番号 | 件数 | |----------|----------|------| | 用語確認 | Q1, Q2, Q3, Q4, Q5 | 5 | | 概念理解 | Q6, Q7, Q8, Q9, Q10, Q11, Q12, Q13 | 8 | | 応用・判断 | Q14, Q15, Q16, Q17, Q18, Q19, Q20 | 7 |', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(17, 'レバレッジ管理における「Conservative（保守的）」スキル段階の実質レバレッジ上限はいくつですか？', '実質レバレッジ1.0倍以下', '実質レバレッジ1.25倍以下', '実質レバレッジ1.5倍以下', '実質レバレッジ2.0倍以下', 2, 'Conservative（保守的）段階では実質レバレッジ1.25倍以下が上限です。初心者や口座が小さい段階では、この低いレバレッジで確実に資金を守ることが最優先になります。', false, 1),
(17, 'レバレッジ管理の3段階フレームワークにおいて、Standard（標準）の実質レバレッジ上限はいくつですか？', '実質レバレッジ1.0倍以下', '実質レバレッジ1.25倍以下', '実質レバレッジ1.5倍以下', '実質レバレッジ2.0倍以下', 3, 'Standard（標準）段階では実質レバレッジ1.5倍以下が上限です。基本的な資金管理が身についているトレーダーが、適度な効率を狙える中間的なレベルです。', false, 2),
(17, 'レバレッジ管理の3段階のうち、Advanced（上級）の実質レバレッジ上限として正しいものはどれですか？', '実質レバレッジ2.0倍以下', '実質レバレッジ3.0倍以下', '実質レバレッジ5.0倍以下', '実質レバレッジ1.5倍以下', 1, 'Advanced（上級）段階でも実質レバレッジ2.0倍以下が上限です。たとえ上級者であっても、レバレッジは抑え目に管理することが長期的な生存の鍵となります。', false, 3),
(17, '証拠金維持率が200%を下回った場合、推奨される対応として正しいものはどれですか？', 'そのままポジションを保有し続ける', '即座にポジションを縮小する', 'レバレッジを上げて早く回復させる', '追加の証拠金を入金してから新規ポジションを取る', 2, '証拠金維持率200%は最低ラインであり、これを下回ったら即座にポジションを縮小する必要があります。維持率が低い状態でポジションを持ち続けると、わずかな逆行で強制ロスカットに追い込まれるリスクが急増します。', false, 4),
(17, 'トレード前の5項目チェックに含まれないものはどれですか？', 'ポジションサイズの計算は完了しているか？', 'リスクは2%以内か？', '現在の口座残高が過去最高を更新しているか？', '連敗中に「特別なこと」をしようとしていないか？', 3, 'トレード前5項目チェックは「①ポジションサイズ計算完了？②リスク2%以内？③維持率200%以上？④レバレッジ推奨範囲内？⑤連敗中に特別なことしてない？」です。口座残高が過去最高かどうかはチェック項目に含まれません。', false, 5),
(17, '口座資金が50%減少した場合、元の資金額に戻すために必要な利回りは何%ですか？', '50%', '75%', '100%', '150%', 3, '損失と回復には非対称性があります。50%の損失を取り戻すには100%の利益が必要です。100万円が50万円になった場合、50万円を100万円に戻すには100%の利回りが必要で、これが「大きく負けないこと」の数学的根拠です。', false, 6),
(17, '口座資金の10%を失った場合、元の金額に戻すために必要な利回りは約何%ですか？', '約15%', '約20%', '約10%', '約11.1%', 4, '10%の損失を回復するには約11.1%の利回りが必要です。100万円が90万円になった場合、90万円から100万円に戻すには10万円／90万円＝約11.1%の利益が必要です。損失が大きくなるほど、回復に必要な利回りは非対称的に増大します。', false, 7),
(17, '「破産確率」の観点から、トレードにおいて最も優先すべきことは何ですか？', '勝率を高めること', '退場しないこと（生存すること）', '取引回数を増やすこと', '1回のトレードで大きく勝つこと', 2, 'トレードにおいて最優先は「退場しないこと」です。どれだけ勝率が高くても、1回の大きな損失で口座が吹き飛べば破産確率は100%になります。生存を確保した上で利益を追求するのが正しい順序です。', false, 8),
(17, 'VIX（恐怖指数）が30を超えた場合のレバレッジ調整として正しいものはどれですか？', 'レバレッジを変更せずそのままにする', '全ポジションを即座に決済する', 'レバレッジを+0.5倍引き上げる', 'レバレッジを-0.5倍引き下げる', 4, 'VIXが30を超えたパニック状態の相場では、ボラティリティが急拡大しているため、レバレッジを0.5倍引き下げる動的調整が推奨されます。例えばStandard段階（1.5倍上限）なら1.0倍まで下げてリスクを抑えます。', false, 9),
(17, '口座資金100万円のトレーダーが2%ルールを厳守する場合、1回のトレードで許容される最大リスク額はいくらですか？', '10,000円', '20,000円', '50,000円', '100,000円', 2, '100万円×2%＝20,000円です。2%ルールは、1回のトレードで失っていい金額を口座の2%に制限するルールで、連敗が続いても口座が急激に減少しない数学的な安全装置です。', false, 10),
(17, '口座資金が90%減少した場合、元の金額に戻すために必要な利回りは何%ですか？', '90%', '200%', '500%', '900%', 4, '90%の損失を回復するには900%の利回りが必要です。100万円が10万円になった場合、10万円を100万円に戻すには10倍（900%増）の利益が必要です。これが「退場しないこと」を最優先すべき圧倒的な理由です。', false, 11),
(17, 'VIXが30を超えている状況で、Standard段階（通常上限1.5倍）のトレーダーが取るべき実質レバレッジの上限はいくつですか？', '1.0倍以下', '1.25倍以下', '1.5倍以下', '2.0倍以下', 1, 'Standard段階の通常上限は1.5倍ですが、VIX30超えの場合は-0.5倍の調整が加わるため、1.0倍以下に抑える必要があります。ボラティリティの高い相場では、通常より保守的なポジションサイズが求められます。', false, 12),
(17, '1%ルールを採用した場合、2%ルールに比べて何が数学的に有利ですか？', '連敗時の口座減少をより緩やかにできる', '勝率が上がる', 'レバレッジを高く設定できる', '利益が2倍になる', 1, '1%ルールは1回のリスクを口座の1%に制限するため、2%ルールよりも連敗時の口座減少が緩やかになります。例えば10連敗した場合、2%ルールでは約82%が残りますが、1%ルールでは約90%が残り、生存確率がさらに高まります。', false, 13),
(17, '証拠金維持率200%以上を保つべき理由として最も適切なものはどれですか？', '急な相場変動でも強制ロスカットのリスクを回避でき、冷静な判断を保てるから', '税金の計算が簡単になるから', 'レバレッジをより高く設定できるから', 'ブローカーの手数料が安くなるから', 1, '証拠金維持率200%以上を保つことで、急激な相場変動が起きても強制ロスカットのリスクを回避できます。また、心理的な余裕が保てるため、冷静な判断が可能になります。維持率がギリギリだと、少しの逆行でパニックに陥りやすくなります。', false, 14),
(17, '連敗時の自動ブレーキにおいて「5連敗」した場合の対応として正しいものはどれですか？', '1週間の休止を取る', 'その日のトレードを終了する', 'その月のトレードを終了する', 'ロットを半分に下げる', 4, '連敗時の自動ブレーキでは、5連敗した場合はロットを半分に下げます。3連敗でその日終了、5連敗でロット半減、10連敗で1週間休止という段階的な安全装置が設けられています。', false, 15),
(17, '「大きく勝つ」ことより「退場しない」ことを優先すべき根拠として最も適切なものはどれですか？', '大きな利益には高い税率がかかるから', 'ブローカーが大きな利益の引き出しを制限するから', '損失と回復には非対称性があり、大きな損失を取り戻すには不相応な利回りが必要だから', '大きく勝つことができるトレーダーは稀だから', 3, '損失と回復の非対称性が「退場しない」ことを優先すべき数学的根拠です。50%の損失には100%、90%の損失には900%の利回りが必要になります。つまり、大きな損失を回避すること自体が、将来の利益の可能性を残すことに直結します。', false, 16),
(17, '口座資金50万円のトレーダーがConservative段階で、損切り幅50銭（0.5円）のUSD/JPYを取引する場合、2%ルールに基づく最大取引量（1万通貨単位）として最も近いものはどれですか？（1銭＝1万通貨あたり100円）', '5万通貨（0.5ロット）', '10万通貨（1.0ロット）', '1万通貨（0.1ロット）', '2万通貨（0.2ロット）', 4, '許容リスク額＝50万円×2%＝10,000円。損切り幅50銭の場合、1万通貨あたりのリスク＝50銭×100円＝5,000円。したがって最大取引量＝10,000円÷5,000円＝2万通貨（0.2ロット）です。', false, 17),
(17, 'トレード前の5項目チェックにおいて「証拠金維持率は200%以上か？」を確認する理由として最も重要なものはどれですか？', '新しいポジションを取るために十分な余裕があるかを確認するため', '過去のトレードの損益を正確に把握するため', '現在のトレンド方向を確認するため', '損切りラインの妥当性を検証するため', 1, '新しいポジションを取る前に維持率200%以上を確認することで、取引後に急な逆行があっても強制ロスカットのリスクを回避できる余裕があるかを確認します。維持率が低い状態での追加ポジションは、生存確率を著しく低下させます。', false, 18),
(17, 'VIXが通常レベル（12〜15）から30を超えた状態に変化した場合、Advanced段階（通常上限2.0倍）のトレーダーが取るべき対応として正しいものはどれですか？', 'レバレッジを変更せず、普段通りにトレードを続ける', 'レバレッジ上限を1.5倍に引き下げ、リスクを抑制する', '全てのポジションを保有したまま、指値で利確を待つ', 'レバレッジ上限を2.5倍に引き上げ、大きく動く相場で利益を狙う', 2, 'VIX30超え時の動的調整により、Advanced段階（2.0倍上限）は-0.5倍されて1.5倍以下に引き下げます。パニック相場では値動きが荒くなるため、通常より保守的なレバレッジで臨むことが生存確率を高めます。', false, 19),
(17, '連敗時の自動ブレーキで「週-6%」に達した場合、その後どうすべきですか？', 'その月のトレードを終了する', '1週間の休止を取る', 'その週のトレードを終了する', 'ロットを半分にしてトレードを続ける', 3, '週で口座の-6%に達した場合は、その週のトレードを終了します。段階的な自動ブレーキは「3連敗→当日終了」「5連敗→ロット半減」「週-6%→週終了」「10連敗→1週休止」「月-10%→月終了」と設定されており、損失の拡大を構造的に防ぎます。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(18, '「2%ルール」とは、1回のトレードで許容できる損失額をどう決めるルールですか？', '総資金に対して2%に相当する金額を最大損失とする', 'エントリー価格の2%分の値幅で損切りを置く', 'レバレッジを常に2%以内に抑える', '利益確定目標をエントリー価格の2%上に置く', 1, '2%ルールは「1回のトレードで失っていい金額 = 総資金の2%」という資金管理の基本ルールです。口座残高が減れば自動的に許容損失額も減るため、連敗時のダメージを構造的に抑える仕組みになります。', false, 1),
(18, '口座資金50万円のトレーダーが2%ルールに従う場合、1回のトレードで許容される最大損失額はいくらですか？', '5,000円', '15,000円', '25,000円', '10,000円', 4, '50万円 × 2% = 10,000円です。2%ルールを守れば、口座が減るにつれて許容損失額も自動的に縮小するため、口座全額を失うリスクを防げます。', false, 2),
(18, '正しいロット計算の手順として適切なものはどれですか？', '総資金の2%でエントリー金額を決めてから、損切り位置を探す', '自信の度合いに応じてロット数を調整し、損切り幅を後から決める', '損切り幅（pips）を先に決め、許容損失額からロット数を逆算する', '利益目標の値幅を先に決め、そこから逆算してロット数を計算する', 3, '正しい手順は「許容損失額（総資金×2%）を決める → 損切り幅（pips）を決める → 許容損失額と損切り幅からロット数を逆算する」という順序です。ロット数は感情や自信ではなく、数学的に導きます。', false, 3),
(18, '2%ルールを厳守して10連敗した場合、残存する資金はおよそ何%ですか？', '約50%', '約65%', '約82%', '約95%', 3, '2%ルールでの10連敗は 0.98^10 ≒ 0.817、つまり資金の約82%が残存します。口座が減るたびにリスク額も減るため、損失のペースが自然に鈍化するのが2%ルールの強みです。', false, 4),
(18, '同じく10連敗した場合、1回あたり10%をリスクした場合の残存率はおよそ何%ですか？', '約35%', '約50%', '約65%', '約75%', 1, '1回10%リスクでの10連敗は 0.90^10 ≒ 0.349、つまり資金は約35%にまで減少します。2%ルールの約82%残存と比較すると、リスク設定の差が結果に与える影響の大きさがわかります。', false, 5),
(18, '連敗時の自動ブレーキにおいて、3連敗した場合の対応として正しいものはどれですか？', 'その日のトレードを終了する', 'ロットを半分に減らす', '1週間のトレードを休止する', 'エントリー前に5秒ルールを必ず実行する', 1, '3連敗した時点で「その日のトレード終了」が自動ブレーキのルールです。連敗が続いている時は感情が乱れている可能性が高く、これ以上のトレードを続けるとリベンジトレードに発展しやすくなります。', false, 6),
(18, '連敗時の自動ブレーキにおいて、5連敗した場合の対応として正しいものはどれですか？', 'その日のトレードを終了する', 'その週のトレードを終了する', '1週間の休止をとる', 'ロットを半分に下げる', 4, '5連敗時の自動ブレーキは「ロットを半分に下げる」ことです。3連敗でその日を終えても翌日さらに負けが続く場合、ロットを減らすことでダメージを抑えながら分析と検証に集中できるようにします。', false, 7),
(18, '1週間で総資金の6%を失った場合、自動ブレーキとしてどうすべきですか？', '次のトレードからロットを半分にする', 'その週のトレードを終了する', '1週間の休止をとる', 'エントリー前に必ず5秒ルールを実行してから再開する', 2, '週で-6%に達した場合は「その週のトレード終了」がルールです。1週間で3回分の2%ルールに相当する損失が出ているため、これ以上続ける前に立ち止まって検証することが求められます。', false, 8),
(18, '10連敗した場合の自動ブレーキとして正しい対応はどれですか？', 'その週のトレードを終了する', 'その月のトレードを終了する', 'ロットを4分の1に減らす', '1週間の休止をとる', 4, '10連敗に達した場合は「1週間の休止」がルールです。ここまで連敗が続くときは、トレードの手法や分析自体に欠陥がある可能性が高く、冷静に振り返るための十分な時間が必要です。', false, 9),
(18, '1ヶ月で総資金の10%を失った場合の自動ブレーキとして正しい対応はどれですか？', '1週間の休止をとる', 'ロットを半分に下げる', '翌月から2%ルールを1%に変更する', 'その月のトレードを終了する', 4, '月で-10%に達した場合は「その月のトレード終了」がルールです。月間で5回分の2%に相当する損失は、分析やメンタルに根本的な問題がある可能性を示しているため、翌月までしっかり振り返ります。', false, 10),
(18, '「自信があるからロットを張る」のではなく、何に基づいてロット数を決めるべきですか？', 'チャートの形状が完璧に見える度合い', '損切りまでの距離が近いかどうか', '直近の勝率の高さ', '経済指標発表の重要度', 2, 'ロット数は「自信」ではなく「損切りまでの距離」で決めます。損切り幅が狭い（距離が近い）ほど、同じ許容損失額でも大きなロットを張れる仕組みです。感情ではなく構造的にロットを算出することが資金管理の核心です。', false, 11),
(18, '口座資金100万円で損切り幅が50pipsのトレードをする場合、2%ルールに従った正しいロット計算の考え方として適切なものはどれですか？（1pipsあたりの損失をロット単位とします）', '100万円の2%である2万円を損切り幅50pipsで割り、ロット数を求める', '100万円を50pipsで割り、その2%をロット数とする', '100万円を一括でエントリーし、2万円下がったら損切る', '50pips動くごとにロットを増やしていく', 1, 'ロット計算の基本は「許容損失額（総資金×2%）÷ 損切り幅（pips）」です。100万円×2%=2万円を損切り幅50pipsで割ることで、逆算された適正ロット数が求まります。', false, 12),
(18, '「夜、ぐっすり眠れるロット数が適正値」という言葉が意味する内容として最も適切なものはどれですか？', 'ポジションを持ったまま寝るべきではないため、デイトレードのみを行えという意味', '利益が出た日は安心して眠れるため、勝率を上げることに集中すべきという意味', '含み損を気にして眠れないような大きなロットは、適正なロット数を超えているという意味', '寝る前には必ず全ポジションを決済すべきという意味', 3, '適正なロット数であれば、ポジションを持っていても精神的な負担は小さく安眠できます。逆に含み損が気になって眠れないなら、それはロットが大きすぎるサインであり、資金管理の観点から縮小が必要です。', false, 13),
(18, 'トレードにおける「期待値」とは何を指す概念ですか？', '1回のトレードで得られる最大利益額', 'トレードを繰り返した際の1回あたりの平均的な損益', '次のトレードが勝つ確率の予測値', '口座資金が増加し続けるための最低勝率', 2, '期待値は「勝率 × 平均利益 ＋ 敗率 × 平均損失」で計算される、トレードを多数繰り返した際の1回あたりの平均損益です。期待値がプラスであれば、長期的に利益を出せることを数学的に意味します。', false, 14),
(18, 'トレーダーの期待値がプラスであるために必要な条件はどれですか？', '勝率が50%を超えること', '平均利益が平均損失より大きいこと、または勝率が十分に高いこと', '毎回同じロット数でエントリーすること', '1日あたりのトレード回数を一定に保つこと', 2, '期待値がプラスになるには「勝率×平均利益 + 敗率×平均損失 > 0」である必要があります。勝率が低くても平均利益が平均損失より十分に大きければプラスになりますし、逆に勝率が高ければ利益目標が小さくても成立します。', false, 15),
(18, '「ロットを張らない勇気」が最も尊い勇気である理由として最も適切なものはどれですか？', 'ロットを張らない期間が長いほど税金の負担が減るため', '条件が揃っていない場面でエントリーを自制できることが、長期的な生存に直結するため', '少ないロットで利益を出す方が技術が高いと評価されるため', '大きなロットを張るよりも小さなロットを何度も張る方が統計的に有利なため', 2, '相場には常にチャンスがあるわけではなく、条件が揃わない場面でエントリーしないこともトレードの重要な判断です。「張らない勇気」を持てることは、感情に抗える自律性の証明であり、長期的な生存に直結します。', false, 16),
(18, '1日の損失上限として推奨される水準は、総資金の何%ですか？', '1%', '2%', '3%', '5%', 3, '1日の損失上限は総資金の3%が目安です。1回のトレードで2%をリスクしても、その日に2回連続で負ければ4%を超えるため、1日のトータル損失を3%に制限することで1日のうちに口座に致命傷を与えることを防ぎます。', false, 17),
(18, '口座資金200万円のトレーダーが、損切り幅20pipsのトレードと損切り幅80pipsのトレードを比較します。2%ルールに従う場合、どちらがより大きなロット数でエントリーできますか？', '損切り幅20pipsの方が大きなロット数でエントリーできる', '損切り幅80pipsの方が大きなロット数でエントリーできる', 'どちらも同じロット数になる', '損切り幅に関係なく、総資金の2%分のロット数で固定される', 1, '許容損失額が同じ（200万円×2%=4万円）場合、損切り幅が狭いほど1pipsあたりの許容損失が大きくなるため、より大きなロット数でエントリーできます。損切り幅20pipsなら4万円÷20pips、80pipsなら4万円÷80pipsで計算されます。', false, 18),
(18, 'トレードの期待値がマイナスであるトレーダーが、トレード回数を増やした場合どうなりますか？', '大数の法則により、次第に期待値がプラスに近づく', '回数を増やすほど1回あたりの損失が減っていく', '期待値がマイナスのまま回数を増やすほど、長期的な累積損失は大きくなる', 'トレード回数と期待値には関係がない', 3, '期待値がマイナスの場合、トレードを繰り返すほど数学的には確実に累積損失が拡大します。回数を増やすことが解決策ではなく、まず期待値をプラスにする（分析方法やリスクリワードの改善）ことが前提です。', false, 19),
(18, '連敗時の自動ブレーキの全体像として、条件と対応が正しく組み合わさっているものはどれですか？', '3連敗→ロット半減、5連敗→1週間休止、10連敗→その月終了', '3連敗→1週間休止、5連敗→その週終了、週-6%→ロット半減、月-10%→1週間休止', '3連敗→その日終了、5連敗→その週終了、週-6%→ロット半減、10連敗→その月終了', '3連敗→その日終了、5連敗→ロット半減、週-6%→その週終了、10連敗→1週間休止、月-10%→その月終了', 4, '連敗時の自動ブレーキは「3連敗→その日のトレード終了」「5連敗→ロット半減」「週-6%→その週のトレード終了」「10連敗→1週間休止」「月-10%→その月のトレード終了」の5段階です。これらをあらかじめルール化しておくことで、感情に流されずに損失を限定できます。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(19, '「ドローダウン」とはトレードにおいて何を指す用語ですか？', '口座の最高残高から最大で何%資産が減少したかを示す指標', '1回のトレードで得た最大利益額', 'レバレッジをかけている際の追加証拠金の必要額', '1日のトレードで許容される損失の上限額', 1, 'ドローダウンは「口座の過去最高残高から最大でどれだけ資産が減少したか」を示す指標です。ドローダウンが大きいほど一度の連敗で口座に致命傷を与えるリスクが高く、資金管理の重要性を測る基準として使われます。', false, 1),
(19, '「スピード出す勇気より、出さない勇気」とは、トレードにおいて何を意味するフレーズですか？', '利益が出ているポジションを早く利益確定させるべきという意味', '高速な注文執行ツールを使わず手動でエントリーすべきという意味', '損切り注文を素早く出す勇気よりも、ポジションを持ち続ける勇気が必要という意味', '条件が揃わない場面でエントリーを控える自制心の方が、攻める勇気より価値があるという意味', 4, '相場では「張る勇気」よりも「張らない勇気」が求められます。条件が整っていない場面でエントリーしない判断こそが長期的な生存に直結し、焦ってエントリーすることは期待値を下げる行動です。', false, 2),
(19, 'エントリーの正しい順番5ステップのうち、第1ステップは何ですか？', '許容損失額を計算する', 'チャート分析をしてエントリーポイントを決定する', 'ロット数を決定する', '逆指値注文の価格を決める', 2, '正しい順番の第1ステップは「チャート分析をしてエントリーポイントを決定する」ことです。まず根拠のあるエントリーポイントがあって初めて損切りラインやロット計算が成り立つため、分析がすべての起点になります。', false, 3),
(19, 'トレードしない日チェックリストに含まれる項目として正しいものはどれですか？', 'その日の経済指標発表がすでに終わっている', '直近3トレードのうち2つが勝ちである', 'SNSの他人のトレードを見て焦っている', '1日の利益目標をまだ達成していない', 3, 'SNSで他人の結果を見て焦っている状態は、感情に基づくエントリーの危険信号です。チェックリストは「自分のルール以外の要因で動こうとしていないか」を確認するためのものであり、該当する項目があればその日はトレードを見送ります。', false, 4),
(19, '「必要なのはギャンブルする勇気ではなく我慢する気持ちです」というフレーズが伝える教訓として最も適切なものはどれですか？', 'トレードは運要素が強いので、冷静に待つことしかできない', '利益を伸ばすにはポジションを長く持ち続ける我慢が必要である', 'エントリーチャンスを待つ忍耐力こそが、トレードで最も求められる資質である', '損切りを我慢してポジションを保有し続けるべきである', 3, 'トレードで求められるのは「ギャンブル的な度胸」ではなく、条件が揃うまでエントリーを待ち続ける「忍耐力」です。自分のルールに合うセットアップが来るまで手を出さないことが、長期的な成績を支えます。', false, 5),
(19, '口座資金100万円のトレーダーが2%ルールに従う場合、1回のトレードで許容される最大損失額はいくらですか？', '5,000円', '10,000円', '50,000円', '20,000円', 4, '100万円 × 2% = 20,000円です。口座資金が増えれば許容損失額も増え、減れば自動的に縮小するため、2%ルールは口座残高に連動した安全装置として機能します。', false, 6),
(19, 'エントリーの正しい順番5ステップのうち、損切りラインを決定するのは何ステップ目ですか？', '第1ステップ', '第2ステップ', '第3ステップ', '第4ステップ', 2, '第2ステップは「根拠が崩れる場所を特定して損切りラインを決定する」ことです。エントリーポイント（第1ステップ）が決まってから、その根拠が否定される価格帯を損切りラインとして設定します。', false, 7),
(19, 'Conservative（保守的）スタイルの推奨レバレッジ上限は何倍ですか？', '1.0倍以下', '1.25倍以下', '1.5倍以下', '2.0倍以下', 2, 'Conservativeスタイルの推奨レバレッジは1.25倍以下です。トレード経験が浅い段階や、資金を守ることを最優先する場合はこのスタイルを採用し、小さなリスクで確実に検証を積むことが推奨されます。', false, 8),
(19, '資金100万円、損切り幅40pipsのトレードにおいて、2%ルールに従ってロット数を計算する際の正しい考え方はどれですか？（1pipsあたりの損失をロット単位とします）', '100万円の2%である2万円を損切り幅40pipsで割ってロット数を求める', '100万円を40pipsで割り、その2%をロット数とする', '100万円の40%をリスク額とし、それを2pipsで割る', '40pipsの2%にあたる0.8pips分のロット数を計算する', 1, 'ロット計算の基本式は「許容損失額（総資金×2%）÷ 損切り幅（pips）」です。100万円×2%=20,000円を40pipsで割ることで、損切りに到達した時の損失がちょうど2万円に収まるロット数が逆算できます。', false, 9),
(19, 'エントリーの正しい順番5ステップのうち、第5ステップは何ですか？', '利益確定の指値注文を入れる', '損切り幅を再計算する', 'チャートの上位足を確認し直す', '即座に逆指値注文を入れる', 4, '第5ステップは「即座に逆指値注文を入れる」ことです。エントリー（第4ステップ）直後に損切り注文を入れることで、感情が介入する隙間をなくし、ルール通りの損切りを構造的に保証します。', false, 10),
(19, 'トレードしない日チェックリストに含まれないものはどれですか？', '方向感がない', '直近の勝率が30%を下回っている', '体調が悪い、寝不足', '連敗が3回続いた', 2, 'チェックリストに含まれるのは「方向感がない」「体調不良・寝不足」「連敗3回」「損切り直後30分以内」「重要指標発表前」「自分のルールに合うセットアップがない」「取り返したい感情」「SNSでの焦り」の8項目です。直近の勝率そのものはチェックリストの項目ではありません。', false, 11),
(19, 'ドローダウンを小さく保つことが重要な理由として最も適切なものはどれですか？', '資金が減ると元の残高に戻るために必要な利益率が非線形的に増大するため', 'ドローダウンが大きいと税金の計算が複雑になるため', 'ドローダウンが大きいとレバレッジが自動的に上がってしまうため', '証券会社の規定でドローダウン率に制限があるため', 1, '資金が10%減ると元に戻すには約11%の利益が必要で、50%減ると100%の利益が必要になります。減少幅が大きくなるほど回復に必要な利益率が急増するため、ドローダウンを小さく抑えることが生存の鍵です。', false, 12),
(19, 'エントリー前に「損切り幅」と「リスク額」の両方を確定させてからロット計算をする理由として最も適切なものはどれですか？', '証券会社の注文画面で両方の入力が必須だから', '利益目標を先に決めるよりも手間が少ないから', '損切り幅だけでは損失額がわからず、リスク額だけではロット数が決まらないから', '損切り幅とリスク額が同じでなければならないから', 3, 'ロット数は「許容損失額 ÷ 損切り幅」で計算されるため、この2つの値が揃って初めて適正ロット数が算出されます。どちらか一方だけではロットを確定できず、適当にロットを決めてから損切りを探すのは本来の手順と逆です。', false, 13),
(19, '損切り直後、再エントリーするまでに最低何分待つべきですか？', '30分', '5分', '10分', '60分', 1, '損切り後は最低30分チャートを閉じる「30分ルール」があります。損失の直後は感情が高ぶっており、リベンジトレードに走りやすい状態のため、冷静さを取り戻すためのクーリングオフ期間が必要です。', false, 14),
(19, 'Standard（標準）スタイルの推奨レバレッジ上限は何倍ですか？', '1.0倍以下', '2.0倍以下', '1.5倍以下', '1.25倍以下', 3, 'Standardスタイルの推奨レバレッジは1.5倍以下です。基本的な資金管理と分析手法が身についている中級者向けの設定であり、Conservativeよりやや積極的ですが、依然として安全性を重視した水準です。', false, 15),
(19, '同じ資金100万円で、損切り幅20pipsのトレードと損切り幅80pipsのトレードを比較します。2%ルールに従う場合、どちらがより大きなロット数でエントリーできますか？', '損切り幅20pipsの方が大きなロット数でエントリーできる', '損切り幅80pipsの方が大きなロット数でエントリーできる', 'どちらも同じロット数になる', '許容損失額が同じなのでロット数に違いはない', 1, '許容損失額（20,000円）が同じ場合、損切り幅が狭いほど1pipsあたりに割り当てられる金額が大きくなり、結果としてより大きなロット数でエントリーできます。20pipsなら20,000÷20=1,000/lot-unit、80pipsなら20,000÷80=250/lot-unitとなり、前者が4倍のロット数になります。', false, 16),
(19, 'Advanced（上級）スタイルの推奨レバレッジ上限は何倍ですか？', '1.25倍以下', '1.5倍以下', '3.0倍以下', '2.0倍以下', 4, 'Advancedスタイルの推奨レバレッジは2.0倍以下です。これは豊富な検証データと実戦経験を持ち、資金管理を自律的に実行できる上級者向けの設定であり、それ以下の経験のトレーダーが安易に採用すべきではありません。', false, 17),
(19, 'トレードしない日チェックリストの項目として、「損切り直後（30分以内）」が含まれている理由は何ですか？', '損切り注文の約定確認に30分かかるため', '30分以内はスプレッドが広がっているため', '証券会社のシステム制限により再注文できないため', '損失直後は感情的になっており、冷静な判断ができないため', 4, '損切り直後は損失の痛みが感情的な判断を引き起こし、リベンジトレードや焦りによるミスエントリーにつながりやすい状態です。30分の待機時間は感情を落ち着かせ、冷静さを取り戻すための安全装置です。', false, 18),
(19, '資金100万円のトレーダーが、損切り幅25pipsのセットアップを見つけました。2%ルールに従った場合、許容損失額20,000円を損切り幅25pipsで割ると、適正ロット単位はいくつですか？', '400', '500', '800', '1,000', 3, '20,000円 ÷ 25pips = 800です。許容損失額を損切り幅で割ることで、損切りに到達した時の損失がちょうど20,000円に収まる適正ロット数が計算できます。計算結果が端数になる場合は、切り下げて安全側に寄せます。', false, 19),
(19, '次のシチュエーションのうち、「トレードしない日チェックリスト」に該当する理由が複数含まれているものはどれですか？シチュエーション：昨晩よく眠れず、朝の経済指標発表前にSNSで他人の大きな利益を見て焦りを感じている。', '該当項目は1個。体調不良のみが該当する', '該当項目は3個。「体調不良」「重要指標発表前」「SNSで焦っている」がすべて該当する', '該当項目は2個。「体調不良（寝不足）」と「SNSで焦っている」が該当する', '該当項目は0個。すべてチェックリスト外の理由である', 2, '「寝不足（体調不良）」「重要な経済指標の発表前」「SNSの他人のトレードを見て焦っている」の3項目がすべてチェックリストに該当します。1項目でも該当すればトレードを見送るべきであり、3項目同時に該当する状況は間違いなくエントリーを避けるべき場面です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(20, '「損切りは保険料」という考え方について、最も適切な説明はどれですか？', '損切り注文を出すと証券会社に手数料が発生するため、保険料と呼ばれる', '損切りを一度もしないトレーダーに対して、口座に保険料が課金される仕組み', '利益が出たトレードの一部を、将来の損切りに備えて積み立てる制度', '小さな損失を支払うことで、大きな損失から口座を守るという考え方', 4, '損切りは「火災保険」と同じ考え方です。家が火事になる前に小さな保険料を払っておけば、全焼という最悪の事態を防げます。同様に、小さな損失を確定させることで口座への致命傷を防ぎます。', false, 1),
(20, '損切りができない心理の変化として、正しい順番はどれですか？', '麻痺 → 否認 → 期待', '期待 → 麻痺 → 否認', '否認 → 期待 → 麻痺', '否認 → 麻痺 → 期待', 3, '含み損を抱えたトレーダーの心理は「否認（まだ大丈夫）」→「期待（きっと戻る）」→「麻痺（どうでもいい）」の3段階で進行します。この連鎖に気づくことが損切り実行の第一歩です。', false, 2),
(20, '「成り行き逆指値」とはどのような注文方法ですか？', '損切りラインに到達した時点で、現在の市場価格で約定させる注文', '損切りラインに到達した時点で、指定した価格で約定させる注文', '利益が一定額に達した時点で、自動的にポジションを閉じる注文', 'エントリーと同時に損切りと利確の両方を設定する注文', 1, '成り行き逆指値は、指定した価格に到達した瞬間に「成り行き」で発注されるため、価格が急変していても確実に約定します。スリッページは発生しますが、損切り未執行のリスクを構造的に排除できます。', false, 3),
(20, '損切りラインを一度決めた後、「まだ大丈夫だろう」と言い訳してラインを不利な方向に動かしてはいけない理由として最も適切なものはどれですか？', '損切りラインの変更には証券会社の承認が必要だから', '損切りラインは法律で一度決めたら変更禁止とされているから', 'ラインを動かすと自動的にロット数が増えてしまうから', '一度動かすと「もう少し待てば」と二度と止まらなくなるから', 4, '損切りラインの後出し変更は「否認→期待→麻痺」の心理連鎖そのものです。一度許容すると「今回だけ」という例外が常態化し、最終的に制御不能な含み損に直面します。', false, 4),
(20, '「30分ルール」とは何をするルールですか？', 'エントリー前に30分間チャートを観察し続けるルール', '1回のトレードで最大30分間しかポジションを保有してはいけないルール', '損切り後、最低30分間チャートを閉じて冷静になるルール', '利確後に30分間は新規エントリーをしてはいけないルール', 3, '損切り直後は感情が高ぶっており、リベンジトレードに走りやすい状態です。最低30分チャートから離れることで感情を落ち着かせ、冷静な判断力を取り戻すための安全装置です。', false, 5),
(20, 'トレードにおいて「逆指値（ストップロス）」をエントリー前に設定すべき理由として最も重要なものはどれですか？', '含み損が拡大してからでは感情的に損切りできなくなる可能性が高いから', 'エントリー前の方がスプレッドが狭いから', '証券会社のシステム上、エントリー後は逆指値を設定できないから', '逆指値を設定しないと税制上の優遇を受けられないから', 1, '含み損が拡大すると「否認→期待→麻痺」の心理が働き、冷静な損切りができなくなります。逆指値を事前に設定しておくことで、感情が介入する隙間を構造的に排除できます。', false, 6),
(20, '次のうち、「指値逆指値」の説明として正しいものはどれですか？', '現在の価格より有利なレートでエントリーする注文', 'ポジションの利益が減少し始めた時点で自動的に決済する注文', '損切りラインに到達した時点で、指定した価格で売買する注文', '毎日決まった時刻に自動的に損切りを執行する注文', 3, '指値逆指値は、トリガー価格に到達した際に「指定した価格」で指値注文を出す方式です。希望価格での約定を狙えますが、急変時には約定しないリスクがあり、確実性では成り行き逆指値に劣ります。', false, 7),
(20, 'ナンピンが危険とされる理由として最も適切なものはどれですか？', 'ナンピンすると証券会社の手数料が倍になるから', 'ナンピンは実質的に損切りラインを不利な方向に動かすことと同じだから', 'ナンピンは法律で禁止されている取引手法だから', 'ナンピンすると自動的にレバレッジが上がってしまうから', 2, 'ナンピンは「平均取得単価を下げる」行為ですが、本質的には損切りラインを後退させることと同じです。損切りラインを動かしてはいけないのと同様に、ポジションを増やすことで含み損のリスクを拡大させます。', false, 8),
(20, '「損切り＝保険料」という比喩において、「家が火事」に相当するものはどれですか？', 'テクニカル分析の失敗', '経済指標の予想外の結果', 'レバレッジの上限到達', '口座資金の大きな減少（ドローダウン）', 4, 'この比喩では、小さな損失（保険料）を支払うことで、口座資金の取り返しのつかない減少（家の全焼）を防ぐという構造を示しています。火災保険と同じく、損切りは「備え」です。', false, 9),
(20, 'トレーリングストップの基本的な考え方として正しいものはどれですか？', '価格が有利に動くにつれて損切りラインも有利な方向に追従させる', '損切りラインを常にエントリー価格の同じ距離に保ち続ける', '損切りラインをランダムに変更して相場の変動に対応する', '利益が出たら損切りラインを外して利益を伸ばし続ける', 1, 'トレーリングストップは、利益が拡大するにつれて損切りラインを利益側に移動させる手法です。利益を守りながらさらなる値幅を狙える一方で、損切りラインを不利方向には決して動かさないのが原則です。', false, 10),
(20, '含み損の拡大を防ぐために最も効果的な仕組みはどれですか？', 'エントリーと同時に逆指値注文を設定しておく', '含み損が一定額に達したらナンピンして平均単価を改善する', '損切りラインを広めに設定して、相場のノイズに耐えさせる', 'ポジションを持ったままチャートを見続け、手動で損切りを判断する', 1, 'エントリー直後に逆指値を設定することで、感情が介入する前に損切りラインを構造的に固定できます。手動での損切り判断は「否認→期待→麻痺」の心理的罠にかかるリスクがあります。', false, 11),
(20, '損切り直後にトレーダーが陥りやすい「リベンジトレード」とはどのような行動ですか？', '損切りしたのと同じ通貨ペアで、逆方向にエントリーすること', '過去の損切りを記録して分析し、次回のトレードに活かすこと', '損切りの精度を上げるために、すぐにデモトレードで検証すること', '損失を取り返そうと、感情の高ぶりの中で衝動的にエントリーすること', 4, 'リベンジトレードは損失の痛みから「取り返さなきゃ」という感情に駆られてエントリーする行動です。30分ルールはこのリベンジトレードを防ぐための安全装置として機能します。', false, 12),
(20, 'エントリーの正しい順番5ステップのうち、第2ステップは何ですか？', '許容損失額からロット数を計算する', '根拠が崩れる場所を特定して損切りラインを決定する', '即座に逆指値注文を入れる', '利益確定の目標価格を設定する', 2, '第1ステップでエントリーポイントが決まった後、第2ステップでは「そのエントリーの根拠が崩れる価格帯」を損切りラインとして決定します。根拠と損切りラインはセットで考えます。', false, 13),
(20, '次のシチュエーションで、最も適切な行動はどれですか？「USD/JPYの買いポジションを持ち、損切りラインを150.00に設定していた。価格が150.00に到達し、損切りが執行された直後である。」', '最低30分間はチャートを閉じ、感情を落ち着かせる', 'すぐにチャートを確認し、反転の兆しがあれば再エントリーする', '損切りの原因を分析するため、直ちに1分足チャートを開く', '損失を取り返すため、ロット数を増やしてすぐに再エントリーする', 1, '損切り直後は「30分ルール」を適用し、最低30分間チャートから離れることが正しい行動です。損失の直後は感情的になっており、冷静な判断ができない状態のため、リベンジトレードを防ぐ必要があります。', false, 14),
(20, '損切りの心理的障害について、「否認」の段階でトレーダーが典型的に考えることは何ですか？', '「もうどうでもいい、全部消えても構わない」', '「きっと明日には戻っているはずだ」', '「まだ損切りするような状況じゃない、一時的な下落にすぎない」', '「早く損切りして次のトレードに進もう」', 3, '否認の段階では、含み損の現実を認めず「まだ大丈夫」「一時的な動きだ」と自分に言い聞かせます。損切りの必要性を頭ごなしに否定するのがこの段階の特徴です。「きっと戻る」は次の「期待」の段階にあたります。', false, 15),
(20, '次のケースのうち、正しいエントリー手順に従っているものはどれですか？', 'まずロット数を決め、次にエントリーポイントを探し、最後に損切りラインを設定した', 'エントリーしてから損切りラインを検討し、利益が出たら逆指値を入れた', 'チャート分析でエントリーポイントを決め、損切りラインを決め、ロットを計算し、エントリー後すぐに逆指値を入れた', 'エントリーポイントと損切りラインを同時に決め、逆指値を入れずにエントリーした', 3, '正しい順番は「①チャート分析→エントリーポイント決定」「②損切りライン決定」「③ロット計算」「④エントリー」「⑤即座に逆指値注文」です。エントリー前にリスクを完全に設計し、エントリー直後に損切りを構造的に固定するのが鉄則です。', false, 16),
(20, '成り行き逆指値と指値逆指値の最大の違いは何ですか？', '成り行きは買い専用、指値は売り専用であること', '成り行きは確実に約定するが価格ズレが生じる、指値は希望価格を指定できるが約定しないリスクがあること', '成り行きは日中のみ有効、指値は翌日も有効であること', '成り行きは手数料無料、指値は手数料が発生すること', 2, '成り行き逆指値は価格ズレ（スリッページ）があっても確実に約定するため、損切りの確実性を重視する場合に適しています。指値逆指値は価格を指定できる分、急変時には約定しないリスクを伴います。', false, 17),
(20, '損切りラインを決定する際に考えるべき「根拠が崩れる場所」とは、具体的にどのような場所を指すのが適切ですか？', 'エントリー価格から一律50pips離れた場所', '直近の高値・安値やサポート・レジスタンスなど、エントリーの前提が否定される価格帯', '自分が許容できる金額の損失に相当する価格帯', 'テクニカル指標の売買シグナルが出る場所', 2, '損切りラインは「エントリーの根拠が崩れる場所」に設定するのが原則です。直近の安値を割る、サポートラインを割るなど、自分のシナリオが否定される価格帯に置くことで、損切りに意味を持たせられます。', false, 18),
(20, '損切りの心理で「麻痺」の段階に達したトレーダーの特徴として最も当てはまるものはどれですか？', 'チャートを頻繁に確認して、1pipsごとの値動きに一喜一憂する', '含み損の金額が大きすぎて感覚が麻痺し、損切りも放置もどちらでもよくなる', '損切りを決意し、冷静に逆指値の価格を再計算する', '過去の類似のチャートパターンを検索して根拠を探し始める', 2, '麻痺の段階では含み損が大きくなりすぎ、「どうせ戻らない」と諦めや「もう関係ない」という無関心に陥ります。ここまで進むと損切りの実行は極めて困難になり、口座に致命的なダメージを与えることが多いです。', false, 19),
(20, '次のシチュエーションで、このトレーダーの最大の問題点は何ですか？「EUR/USDの買いポジションを持っている。損切りラインを1.0800に設定していたが、価格が1.0790まで下落した。しかし『重要な経済指標の発表が控えているから、その後に戻るかもしれない』と考え、損切りラインを1.0750に変更した。」', '経済指標を考慮していない点 — 指標発表前は損切りラインを広げるべきである', '買いポジションを選択した点 — 経済指標前は売りポジションにすべきだった', 'ロット数が小さすぎる点 — 損切りラインを変更するならロットも増やすべきだった', '損切りラインを後出しで変更している点 — 一度動かすと二度と止まらなくなる', 4, '損切りラインを「まだ大丈夫」という理由で不利方向に変更するのは、否認→期待→麻痺の心理連鎖の典型的な兆候です。一度決めた損切りラインは理由を問わず動かさないことが、トレーダーの生存に直結する鉄則です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(21, '「HL（Higher Low）」とはどのような状態を指しますか？', '前の谷よりも高い谷が形成された状態', '前の山よりも低い山が形成された状態', '前の谷よりも深い谷が形成された状態', '前の山よりも高い山が形成された状態', 1, 'HL（Higher Low＝安値切り上げ）は、直近の安値（谷）を下回らず、より高い位置に谷を形成した状態です。上昇トレンドを構成する2つの要素のうちの1つです。', false, 1),
(21, '「LH（Lower High）」の意味として正しいものはどれですか？', '安値切り上げ — 前の谷より高い谷', '高値切り下げ — 前の山より低い山', '安値切り下げ — 前の谷より深い谷', '高値切り上げ — 前の山より高い山', 2, 'LH（Lower High＝高値切り下げ）は、直近の高値（山）を上回れず、より低い位置に山を形成した状態です。下降トレンドを構成する要素の一つです。', false, 2),
(21, 'チャート上でHHとHLが連続して形成されている場合、現在の相場環境はどれですか？', '下降トレンド', 'レンジ相場', '上昇トレンド', 'トレンド転換中', 3, 'HH（高値切り上げ）とHL（安値切り上げ）の連続は、上昇トレンドの定義です。山も谷も切り上がっていることが、買い手が主導権を握っている証拠です。', false, 3),
(21, '下降トレンドを構成する波の組み合わせはどれですか？', 'HHとHLの連続', 'LHとLLの連続', 'HHとLLの交互', 'LHとHLの交互', 2, '下降トレンドは「LH（高値切り下げ）」と「LL（安値切り下げ）」の連続で定義されます。山も谷も切り下がっていくことが売り手優位の環境です。', false, 4),
(21, 'チャート上で高値・安値を見つける際のコツとして推奨されていないものはどれですか？', '明確な反転ポイントだけを拾う', '終値ベースで判断する', '1分足から練習を始める', '日足チャートから練習する', 3, '高値・安値を見つける3つのコツは「明確な反転ポイントだけを拾う」「終値ベースで判断する」「日足から練習する」です。短い時間足はノイズが多く、正しい波の判断が難しいため、まずは日足で練習します。', false, 5),
(21, 'レンジ相場をHH/HL/LH/LLの観点から説明したものとして最も適切なものはどれですか？', 'HHもLLも形成されず、高値と安値が同じ水準で推移する状態', 'HLとLHが交互に現れる状態', 'HHとLLが同時に連続して形成される状態', 'HLだけが連続し、HHが出現しない状態', 1, 'レンジ相場は「HHもLLも出ない」状態です。高値を更新できず、安値も更新できないため、価格が一定の範囲内で行ったり来たりします。', false, 6),
(21, 'ダウ理論の第1原則「トレンドには3段階がある」において、正しい順番はどれですか？', '追随期 → 先行期 → 利食い期', '利食い期 → 先行期 → 追随期', '先行期 → 利食い期 → 追随期', '先行期 → 追随期 → 利食い期', 4, 'トレンドの3段階は「先行期（賢い人が動く）→ 追随期（大衆が参加）→ 利食い期（賢い人が抜ける）」の順です。この流れを理解すれば、今がトレンドのどの段階にあるかを判断できます。', false, 7),
(21, 'ダウ理論の第2原則「出来高がトレンドを確認する」について、正しい説明はどれですか？', '出来高がトレンド方向に増加していることは、トレンドが健全であることを示す', '出来高はトレンド転換時しか意味を持たない指標である', '出来高が減少している時ほどトレンドが強い', '出来高とトレンドの方向には関係がない', 1, 'トレンド方向への出来高増加は、多くの参加者がその方向に同意している証拠です。価格が上昇しているのに出来高が減る場合は、トレンドの衰えを警告するサインとなります。', false, 8),
(21, 'ダウ理論の第3原則として最も適切なものはどれですか？', 'トレンドは必ず3日以内に転換する', 'トレンドの長さは過去の値動きから正確に予測できる', '明確な転換シグナルが出るまでトレンドは継続すると考える', '出来高が減った時点で即座にトレンドが転換する', 3, '第3原則は「疑わしきはトレンド継続」です。明確な転換シグナルが確認できるまでは、現在のトレンドが続くと仮定して行動します。これが逆張りを防ぐ根拠にもなります。', false, 9),
(21, '上昇トレンドから下降トレンドへの「転換」を判断するために必要な2条件として正しい組み合わせはどれですか？', '安値更新の成功 ＋ 戻り高値を上抜く', '高値更新の成功 ＋ 安値更新の成功', '出来高の急減 ＋ 200MAが横ばいになる', '高値更新の失敗 ＋ 押し安値を割り込む', 4, 'トレンド転換の判断には「高値更新の失敗」と「押し安値を割り込む」の2条件が揃う必要があります。片方だけでは転換と断定できず、単なる調整の可能性が残ります。', false, 10),
(21, '次のケースのうち、「調整」ではなく「転換」の兆候として最も適切なものはどれですか？', '出来高が減少し、押し安値は割っていない', '出来高が急増し、上位足が崩れ始め、押し安値を明確に割った', '上位足は上昇トレンドのままで、価格が直近の押し安値近くまで下落した', '出来高が減少し、上位足の方向は変わっていない', 2, '転換の兆候は「出来高急増」「上位足が崩れ始める」「押し安値を明確に割った」の3要素で判断します。出来高が減少している場合や押し安値が保たれている場合は調整の可能性が高いです。', false, 11),
(21, '「200MA＝北極星」という比喩について、価格が200MAの下にある場合の正しい見方はどれですか？', '売り目線でトレードを考えるべき', '買い目線でエントリーを探すべき', '200MAは関係ないので他の指標を使うべき', 'レンジ相場なので様子見が適切', 1, '200MAはトレンドの方向性を示す「北極星」として機能します。価格が200MAの下にあれば売り目線、上にあれば買い目線、200MAが横ばいならレンジとして捉えます。', false, 12),
(21, '価格が200MAの上にあり、200MA自体も右肩上がりの場合、最も適切な目線はどれですか？', '売り目線で戻り売りを探す', 'レンジ目線で両方向のブレイクアウトを待つ', '買い目線で押し目買いを考える', '200MAの傾きに関係なく、常にニュートラル目線', 3, '価格が200MAの上にあり、200MA自体も上向きの場合は明確な上昇トレンドの環境です。買い目線で押し目買いを検討するのが、トレンドに逆らわない順張りの基本です。', false, 13),
(21, 'スイングトレードを行う場合の、推奨されるマルチタイムフレーム分析の組み合わせはどれですか？', '月足 → 週足 → 日足', '週足 → 日足 → 4H足', '日足 → 4H足 → 1H足', '4H足 → 1H足 → 15分足', 2, 'スイングトレードでは「週足（上位足で方向）→ 日足（中位足でシナリオ）→ 4H足（下位足でタイミング）」の組み合わせが推奨されます。トレードスタイルに応じて時間軸の組み合わせを変えます。', false, 14),
(21, '日足で上昇トレンド、1時間足で下降の波が見られる場合、最も適切な判断はどれですか？', '1時間足の下降を重視して売りエントリーする', '日足と1時間足が矛盾するため、両方無視して別の銘柄を探す', '1時間足の下降が終わるまで待ち、反転したら日足に関係なく売りで入る', '日足の上昇トレンドを信じて、1時間足の下降は押し目の可能性が高いと考える', 4, '上位足と下位足が矛盾する場合、上位足の調整（押し目）の可能性が高いです。迷ったら上位足を信じるのが鉄則であり、日足の上昇トレンドが続く前提で対応すべきです。', false, 15),
(21, '次のチャート状況のうち、「上昇トレンドが継続している」と最も自信を持って言えるものはどれですか？', '直近の高値を更新し、直近の安値も切り上がっている', '直近の高値を更新したが、直近の安値も下抜けた', '直近の高値更新に失敗したが、直近の安値は保っている', '直近の高値は更新していないが、直近の安値は切り上がっている', 1, '上昇トレンドの定義は「HH（高値切り上げ）＋ HL（安値切り上げ）の連続」です。高値も安値も切り上がっているAが、上昇トレンド継続を最も明確に示しています。', false, 16),
(21, '次のシチュエーションで、トレンド転換と判断できるものはどれですか？', '上昇トレンド中に高値を更新したが、その後少し下落した', '上昇トレンド中に直近の押し安値を下抜けたが、その後すぐに新高値を更新した', '上昇トレンド中に高値更新に失敗し、さらに直近の押し安値を下抜けた', '上昇トレンド中に高値更新に失敗し、その後も高値を更新し続けている', 3, '転換の2条件「高値更新の失敗」と「押し安値を割り込む」が両方揃った場合にのみ、トレンド転換と判断できます。Aは通常の波、Bはダマシの可能性、Dはトレンド継続です。', false, 17),
(21, 'ダウ理論の限界として指摘されていないものはどれですか？', '転換シグナルが遅れて出ることがある', 'レンジ相場では使いにくい', 'ダマシ（フェイクシグナル）が存在する', '出来高を全く考慮できない', 4, 'ダウ理論の限界は「遅れのシグナル」「レンジ相場で使いにくい」「ダマシがある」の3点です。ダウ理論では出来量を重視しており（第2原則）、むしろ出来高でトレンドの健全性を確認します。', false, 18),
(21, 'デイトレードを行う場合の、推奨されるマルチタイムフレーム分析の組み合わせはどれですか？', '月足 → 週足 → 日足', '週足 → 日足 → 4H足', '4H足 → 1H足 → 5分足', '日足 → 4H足 → 1H足', 4, 'デイトレードでは「日足（上位足で方向）→ 4H足（中位足でシナリオ）→ 1H足（下位足でタイミング）」の組み合わせが推奨されます。長期投資やスイングとは異なる時間軸を使います。', false, 19),
(21, 'ダウ理論に基づくトレードで「最も重要な教訓」とされるものはどれですか？', 'レンジ相場では積極的にスキャルピングする', '出来高が減少したら必ずエントリーする', '200MAに触れたら必ず反転すると仮定する', 'トレンドに逆らう逆張りトレードをしない', 4, 'ダウ理論の最大の教訓は「逆張りをしない」ことです。トレンドが継続している限り、その方向に沿った順張りを心がけることが、ダウ理論を活かしたトレードの基本姿勢です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(22, '市場の4サイクルにおいて、蓄積期（春）の特徴として正しいものはどれですか？', '長い上昇後に高値圏で横ばいになる', '下落一巡後にレンジ相場になり、大口が静かに買い集める', 'LH/LLが連続しパニック売りが起きる', 'HH/HLが連続し出来高が急増する', 2, '蓄積期は長い下落が一巡した後にレンジを形成し、大口が目立たないように少しずつ買い集める期間です。個人はまだ悲観的で、ベアトラップに注意が必要なフェーズです。', false, 1),
(22, '上昇期（夏）のチャート上の特徴として正しいものはどれですか？', 'LH/LLの連続と出来高の減少', '高値圏での横ばいとダブルトップの形成', 'HH/HLの連続と出来高の増加', 'レンジ相場の継続と出来高の激減', 3, '上昇期はHH（高値切り上げ）とHL（安値切り上げ）が連続して形成され、出来高も増加します。大口は保有を継続し、トレンドに沿った押し目買いが有効なフェーズです。', false, 2),
(22, '分配期（秋）に大口がとる行動として正しいものはどれですか？', '静かに買い集めを続ける', '保有ポジションを維持し様子を見る', '積極的に新規の買い注文を入れる', '保有しているポジションを売り抜ける', 4, '分配期は大口が長期間保有してきたポジションを売り抜けるフェーズです。高値圏で横ばいになり、ダブルトップなどの天井パターンが形成されることが多いです。', false, 3),
(22, '下落期（冬）において、個人が最も陥りやすい危険な心理状態はどれですか？', '「もう誰もトレードすべきではない」と完全に諦める', '「きっと戻る」と根拠のない期待を持ち続ける', '「今が底だ」と判断してドルコスト平均法を始める', '「次はショートで稼ごう」と急に売り戦略に切り替える', 2, '下落期で最も危険なのは「きっと戻る」という希望的観測です。LH/LLが連続する中で根拠なく戻りを期待し、損切りを先延ばしすることが大きな損失につながります。底打ちシグナルを確認するまでは待つべきです。', false, 4),
(22, '値動きの正体について正しい説明はどれですか？', '買い手と売り手の力関係であり、資金量の勝負である', 'ニュースの好悪が直接価格を決定する', 'トレーダーの人数が多い方向に価格が動く', 'テクニカル指標の計算結果が価格を決める', 1, '値動きの正体は買い手と売り手の力関係です。トレーダーの「数」ではなく「資金量」が価格を動かします。少数でも巨大な資金を持つ大口の注文が価格に大きな影響を与えます。', false, 5),
(22, '相場全体のうち、レンジ相場が占める割合として最も適切なものはどれですか？', '約3割', '約5割', '約9割', '約7割', 4, 'レンジ相場は相場全体の約7割を占めると言われています。つまりトレンドが出ている時間は3割しかなく、レンジ時に無理にトレードしないこと、「やらない」ことが実力のうちです。', false, 6),
(22, '環境認識3ステップとして正しい順番はどれですか？', '上位足で大方向 → 中位足で4サイクル位置 → 下位足でタイミング', '中位足でタイミング → 下位足で4サイクル位置 → 上位足で大方向', '下位足で4サイクル位置 → 上位足で大方向 → 中位足でタイミング', '上位足で4サイクル位置 → 中位足でタイミング → 下位足で大方向', 1, '環境認識は「上位足でトレンドの大方向を確認→中位足で4サイクルのどのフェーズにいるかを把握→下位足でエントリータイミングを測る」の順で行います。大枠から細部へと絞り込むアプローチです。', false, 7),
(22, 'VIX（恐怖指数）が30を超えた場合の意味として正しいものはどれですか？', '通常の相場環境であり、特別な対応は不要', '軽い警戒レベルで、通常通りのトレードが可能', '強気相場のサインであり、積極的な買いが推奨される', 'パニック状態を示しており、40を超えれば極端な恐怖で底打ちが多い', 4, 'VIXが30以上はパニック状態、40以上は極端な恐怖を示します。歴史的にVIX40以上の極端な恐怖は底打ちのタイミングになることが多く、恐怖のピークが買い場のチャンスになる可能性があります。', false, 8),
(22, 'Fear & Greed Indexが0〜25（Extreme Fear）のとき、一般的にどのような市場状況を示唆していますか？', '買いチャンスが近い可能性があることを示している', 'さらなる下落が確実であり、全てのポジションを手仕舞うべき', 'レンジ相場が長期化する兆候である', '大口が売り抜けを完了したことを意味する', 1, 'Fear & Greed Indexが0〜25のExtreme Fearゾーンは、投資家の恐怖がピークに達している状態で、逆に買いチャンスが近い可能性を示唆しています。一方、75〜100のExtreme Greedは反転の可能性を警告しています。', false, 9),
(22, '4サイクルとダウ理論の接続において、上昇期に相当するダウ理論のパターンはどれですか？', 'HH/HLの連続', 'LH/LLの連続', 'レンジ（HHもLLも形成されない状態）', 'レンジまたは転換の兆候', 1, '4サイクルとダウ理論は次のように接続されます。蓄積期＝レンジ、上昇期＝HH/HLの連続、分配期＝レンジまたは転換の兆候、下落期＝LH/LLの連続です。両者の考え方は互いに補完関係にあります。', false, 10),
(22, '蓄積期（春）に個人が注意すべき「ベアトラップ」とはどのような現象ですか？', 'レンジの上限を一瞬突破してから急反落する現象', '大口が一気に買い上げて個人が乗り遅れる現象', 'レンジの下限を一瞬割り込んで損切りを誘発した後に急反発する現象', '出来高が急増してブレイクアウトが起きる現象', 3, 'ベアトラップはサポート（レンジの下限）を一瞬割り込むことで、売りポジションの損切りや新規の売りを誘発し、その注文を燃料に大口が安値で買い集めた後に急反発する現象です。蓄積期に多く見られる罠です。', false, 11),
(22, '分配期（秋）にニュースが最も楽観的な内容ばかりになる理由として最も適切なものはどれですか？', '企業が意図的に好材料をリリースしているから', '業績が実際に最も良い時期だから', 'メディアが意図的に相場を操作しているから', '大口が高値で売り抜けるために一般投資家を引き寄せるため', 4, '分配期は個人が最も楽観的になるフェーズで、ニュースも最も好意的な内容が並びます。これは大口が高値で売り抜けるために一般投資家の買い注文を必要としているからであり、「ニュース最楽観＝最危険」のシグナルとなります。', false, 12),
(22, 'スイングトレーダーが環境認識3ステップを週足・日足・4時間足で実践する場合、日足で判断すべきことは何ですか？', 'トレンドの大方向', 'エントリーのタイミング', '4サイクルのどのフェーズにいるか', '損切りの正確な価格', 3, '環境認識3ステップでは、上位足（週足）で大方向を確認し、中位足（日足）で現在が4サイクルのどのフェーズにあるかを判断し、下位足（4時間足）でエントリーのタイミングを測ります。日足は中位足にあたります。', false, 13),
(22, '次の状況を確認してください。週足で上昇トレンド、日足で高値圏のレンジが3週間続いており、ニュースが「過去最高値更新」「強気相場継続」と報じている。この相場は4サイクルのどのフェーズに最も近いですか？', '蓄積期（春）', '上昇期（夏）', '分配期（秋）', '下落期（冬）', 3, '長い上昇後に高値圏で横ばいが続くこと、そしてニュースが最も楽観的な内容であることは、分配期（秋）の典型的な特徴です。大口はすでに売り抜けを始めており、ブルトラップに注意すべきフェーズです。', false, 14),
(22, 'VIXが12〜15の範囲にある場合、どのような市場環境と判断すべきですか？', '通常の相場環境であり、極端な警戒は不要', 'パニック状態であり、直ちにポジションを縮小するべき', '極端な恐怖状態であり、歴史的な買い場の可能性がある', '軽い警戒レベルであり、レバレッジを下げるべき', 1, 'VIXが12〜15は通常の相場環境を示しています。20〜25で警戒、30以上でパニック、40以上で極端な恐怖（底打ちが多い）と判断します。12〜15の落ち着いた環境では通常通りの分析とトレードが可能です。', false, 15),
(22, '上昇期（夏）の最も効果的なトレード戦略はどれですか？', '天井を予測して戻り売りを入れる', 'トレンドに沿って押し目買いを狙い、逆張りを厳禁する', 'レンジの上限と下限で逆張りをする', '出来高の減少を確認してからショートを入れる', 2, '上昇期はHH/HLが連続するトレンド環境なので、トレンドに沿った押し目買いが最も有効です。逆張り（戻り売り）は厳禁で、トレンドの方向に沿った順張りが基本となります。', false, 16),
(22, 'ある投資家が下落期（冬）に「今売ったら確定損になる。きっと戻るから保有し続ける」と考えています。この判断の最も危険な点は何ですか？', '税金の計算が複雑になること', 'LH/LLが連続する中で底値の根拠がなく、損失が拡大する可能性が高いこと', '他の銘柄への乗り換えが遅れること', '証拠金維持率が上がってしまうこと', 2, '下落期はLH/LLが連続する環境で、「きっと戻る」という期待にはチャート上の根拠がありません。底打ちシグナル（出来高の急増や下ヒゲの形成など）を確認するまでは保有を続けることで損失が拡大する危険があります。', false, 17),
(22, '分配期（秋）に起きやすい「ブルトラップ」について、正しい説明はどれですか？', '安値を更新した後に急反発し、売り手が損をする現象', '大口が大量の買い注文を入れて個人を圧倒する現象', 'レジスタンスを一瞬突破して買いを誘発した後、急反落する現象', '出来高が激減して価格が動かなくなる現象', 3, 'ブルトラップはレジスタンス（上値の抵抗線）を一瞬超えることで買い注文を誘発し、その買いを利用して大口が売りをぶつけて急反落させる現象です。分配期に多く見られ、天井付近で飛びついた個人を罠にかけます。', false, 18),
(22, '4サイクルとダウ理論の接続において、蓄積期と分配期に共通するダウ理論上の特徴はどれですか？', 'ともにHH/HLの連続が見られる', 'ともにLH/LLの連続が見られる', 'ともに出来高が急増する', 'ともにレンジ的な性質（明確なHH/LLが形成されにくい）を持つ', 4, '蓄積期は「レンジ」、分配期は「レンジまたは転換の兆候」とダウ理論に接続されます。どちらも価格が一定の範囲内で推移しやすく、明確なHH/LLが形成されにくいレンジ的な性質を持ちます。蓄積期は上へのブレイク、分配期は下へのブレイクを待つフェーズです。', false, 19),
(22, '相場の約7割がレンジであるという事実から導かれる、最も実践的な教訓はどれですか？', 'レンジ相場ではスキャルピングで小さく利益を積み重ねるべき', 'レンジ相場で無理にトレードせず、「やらない」ことが重要である', '常にブレイクアウトを狙う逆張りを心がけるべき', 'レンジの期間は短いので、その間に勉強すればよい', 2, '相場の7割がレンジであるということは、トレード可能なトレンド環境は3割しかないことを意味します。レンジで無理にエントリーするのではなく、「やらない」と決めることがトレードの実力です。自分の setups が揃った時だけ参加する姿勢が重要です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(23, 'ワイコフの3法則として正しい組み合わせはどれですか？', '需要と供給、原因と結果、努力と結果', 'トレンドとレンジ、需要と供給、時間と価格', '原因と結果、サポートとレジスタンス、動量と加速度', '需要と供給、投入と産出、膨張と収縮', 1, 'ワイコフの3法則は「需要と供給」「原因と結果」「努力と結果」です。これらは値動きの背後にある需給構造を体系的に読み解くための基本原則です。', false, 1),
(23, 'ワイコフの「原因と結果」の法則が示す関係として正しいものはどれですか？', '出来高が増えれば必ず価格が動く', 'レンジ（原因）が長いほど、その後のトレンド（結果）が大きくなる', 'サポートが厚いほどレジスタンスも厚くなる', '上位足のトレンドが下位足の値動きを決定する', 2, '原因と結果の法則では、レンジ相場が「原因」、その後のトレンドが「結果」にあたります。レンジ期間が長くエネルギーが蓄積されるほど、ブレイク後のトレンドが大きくなるという関係です。', false, 2),
(23, '出来高×価格の4パターンにおいて、「価格上昇＋出来高減少」が示す意味はどれですか？', '健全な上昇トレンドの継続', 'エネルギー蓄積によるブレイク前兆', 'パニック売りの発生による底打ち可能性', '買い手の勢いが衰えている弱気サイン', 4, '価格は上昇しているのに出来高が減少している場合、買い手の参加意欲が低下しており、上昇の勢いが失われつつある弱気サインと判断されます。', false, 3),
(23, 'FXで実出来高の代わりに使われる指標はどれですか？', 'ティックボリューム', 'MACD', 'RSI', 'ボリンジャーバンド', 1, 'FXは取引所を介さないため実出来高が分かりません。その代替として価格変動の回数を測るティックボリュームが広く使われます。', false, 4),
(23, 'FRVP（Fixed Range Volume Profile）の説明として正しいものはどれですか？', '出来高の累積方向を示す指標', '価格変動の回数をカウントする指標', '移動平均線と出来高を組み合わせた指標', '特定期間の価格帯別出来高を可視化するツール', 4, 'FRVPは特定期間の価格帯ごとに出来高を分布表示するツールで、大口がどの価格水準で多く取引したかを特定するのに役立ちます。', false, 5),
(23, 'ワイコフの「努力と結果」の法則において、「出来高は増加しているのに価格がほとんど動かない」状態は何を示唆しますか？', '異変であり、トレンド転換の前兆', '方向感の欠如', '健全なトレンドの継続', '大口の足跡', 1, '努力あり（出来高増加）にもかかわらず結果なし（値動きが小さい）という乖離は、勢力の交代が起きている異変のサインです。現在のトレンドに対する抵抗力が強まっており、転換の前兆と読み取れます。', false, 6),
(23, '出来高が少ないのに大きな値動きが起きた場合、ワイコフの努力と結果の法則ではどう解釈しますか？', 'トレンド転換の前兆である', '方向感がない状態である', '健全な値動りである', '大口の足跡である', 4, '努力なし（出来小）で結果あり（大きな値動き）が起きる場合、少数の巨大な注文によって価格が動いた「大口の足跡」と解釈されます。少量の注文で大きく動くことは、市場の流動性が薄い時間帯や大口の意図的な価格操作を示唆します。', false, 7),
(23, '本物のブレイクアウトの特徴として正しいものはどれですか？', '出来高は平均以下で、ヒゲが長い', '出来高は急増するが、すぐに元のレンジに戻る', '出来高は平均以下だが、上位足と方向が一致する', '出来高は平均の1.5倍以上で、大きな実体を伴う', 4, '本物のブレイクは出来高が平均の1.5倍以上あり、ローソク足に大きな実体が形成され、ブレイク方向への継続性が見られ、上位足の方向とも一致します。', false, 8),
(23, '価格が新高値を更新しているのに出来高が減少している現象を何と呼びますか？', 'ベアトラップ', '出来高ダイバージェンス', 'ブルトラップ', 'エネルギー蓄積', 2, '新高値更新に伴う出来高の減少は「出来高ダイバージェンス」と呼ばれ、買い手の勢いが衰えていることを示すトレンド衰えの警告シグナルです。', false, 9),
(23, '大口の注文が集中する場所として、誤っているものはどれですか？', '移動平均線の交差点', '過去の大量売買があった価格帯', '直近の高値・安値の外側', 'フィボナッチの38.2%、50%、61.8%の水準', 1, '大口の注文が集中する4場所は、直近高値/安値の外側（損切り集中）、過去の大量売買価格帯（FRVP）、キリ番（100ドル等の心理的節目）、フィボナッチ主要水準です。移動平均線の交差点は含まれません。', false, 10),
(23, 'ベアトラップのメカニズムとして正しい順番はどれですか？', '急反発 → 大口が買い → サポート割れ → 損切り発動', 'サポート一瞬割れ → 損切り発動 → 大口が安値で買い → 急反発', '大口が買い → サポート割れ → 急反発 → 損切り発動', '損切り発動 → 急反発 → サポート割れ → 大口が買い', 2, 'ベアトラップは、サポートを一瞬割り込んで売りポジションの損切りを誘発し、その損切り注文を燃料に大口が安値で買い集めた後、急反発する仕組みです。蓄積期に多く見られる大口の罠です。', false, 11),
(23, 'ブルトラップの目的として正しいものはどれですか？', '大口が安値で買い集めるためにサポートを一瞬割る', 'レジスタンスを一瞬超えて買いを誘発し、その買いを利用して大口が売り抜ける', '出来高を減少させてエネルギーを蓄積する', '下落トレンドを加速させてパニックを起こす', 2, 'ブルトラップは、レジスタンスを一瞬突破して個人の買い注文を誘発し、その買い需要を相手に大口が売りをぶつけて急反落させる手法です。分配期に多く見られます。', false, 12),
(23, '蓄積と分配の比較において、蓄積期に特徴的なローソク足の形状はどれですか？', '上ヒゲが目立つ', '大きな陽線が連続する', '下ヒゲが目立つ', '十字線が連続する', 3, '蓄積期は大口が下値で買い集めるため、レンジの下限で買い支えられ、下ヒゲが目立つローソク足が多く形成されます。一方、分配期は上値で売り叩かれるため上ヒゲが目立ちます。', false, 13),
(23, 'プライスアクション×出来高の4統合パターンにおいて、「強い足＋出来高減少」はどう判断すべきですか？', '信頼できるシグナルなので即エントリー', '転換の予兆なので逆張りを検討する', '様子見で何もしないのが唯一の正解', '要注意であり、勢いの持続性に疑問がある', 4, '強い足（大きな値動き）が出ているのに出来高が減少している場合、その値動きを支える参加者の本気度が不足しており、勢いが持続するか要注意と判断します。', false, 14),
(23, '大口の行動を察知するチェックリストに含まれないものはどれですか？', '不自然に長いレンジが形成されていないか', 'ストップ狩りの動きがないか', '移動平均線のゴールデンクロスが発生したか', '出来高と価格の乖離がないか', 3, '大口の行動チェックリストは「不自然に長いレンジ」「ストップ狩りの動き」「出来高と価格の乖離」「ブレイク前のエネルギー蓄積量」の4項目です。移動平均線のクロスは含まれません。', false, 15),
(23, 'ある銘柄が3ヶ月間のレンジを上にブレイクした。出来高は平均の2倍、ローソク足は大きな陽線でヒゲは短い。日足・週足ともに上昇方向を示している。このブレイクはどう評価すべきですか？', 'フェイクブレイクの可能性が高いので戻り売りを検討する', '出来高が多すぎるため逆張りのチャンスである', '本物のブレイクの条件を満たしており、トレンドに沿った順張りを検討できる', '3ヶ月のレンジは短すぎるため、様子見が適切である', 3, '本物のブレイクの4条件（出来高平均1.5倍以上、大きな実体、方向の継続性、上位足との一致）を全て満たしています。3ヶ月のレンジという十分な「原因」の後のブレイクであり、信頼性が高いと評価できます。', false, 16),
(23, 'USD/JPYの4時間足で、150.00円のレジスタンスを一瞬超えて150.30円まで上昇したが、その足の終値は149.80円だった。出来高は平均以下だった。この状況をどう読み取るべきですか？', 'ブルトラップの可能性が高く、フェイクブレイクと判断すべき', '出来高が少ないため大口の足跡の可能性がある', '強い買い圧力による本物のブレイクアウト', '蓄積期の典型的なパターンで、上昇トレンドの始まり', 1, 'レジスタンスを一瞬超えたものの、長い上ヒゲを残して終値がレジスタンス下に戻っており、出来高も平均以下です。これはフェイクブレイクの典型的な特徴であり、ブルトラップの可能性が高いと判断すべきです。', false, 17),
(23, '日足チャートで直近高値を3回連続で更新しているが、その都度出来高が減少している。現在のトレンド方向は上昇だが、OBV（On Balance Volume）は天井を切り下げている。この状況から読み取れる最も適切な判断はどれですか？', '上昇トレンドが強まっており、買い増しを検討すべき', '大口が買い集めている蓄積期であり、ブレイクを待つべき', '出来高ダイバージェンスが発生しており、トレンドの衰えに警戒が必要', 'レンジ相場に入ったため、逆張り戦略に切り替えるべき', 3, '新高値更新に伴う出来高の減少とOBVの天井切り下げは、明らかな出来高ダイバージェンスです。価格は上昇しているものの、それを支える買い手の勢いが低下しており、トレンドの衰えに対する警戒が必要です。', false, 18),
(23, 'EUR/USDが1.0800〜1.0950のレンジを6週間形成後、1.0800を下ヒゲで一瞬割り込んで1.0785まで下落したが、即座に反発して1.0900まで戻った。この下ヒゲの出来高は直近平均の3倍だった。この状況は何を示唆していますか？', '下落トレンドへの本格的な転換', '方向感のないレンジの継続', 'ベアトラップの可能性が高く、大口が安値で買い集めた可能性がある', '大口の足跡によるフェイクブレイクで、さらに下落する', 3, '長いレンジの下限を下ヒゲで一瞬割り込み、高出来高を伴いながら即反発するパターンはベアトラップの典型です。出来高増加（努力あり）にもかかわらず価格が維持できず反発（結果なし→反転）しており、大口が損切り注文を燃料に安値で買い集めた可能性が高いです。', false, 19),
(23, '株式銘柄Aが長い上昇後、高値圏で2ヶ月のレンジを形成している。レンジ上限でのローソク足には上ヒゲが目立ち、出来高は高いが上値が重い。FRVPではレンジ上限付近に大量の売買が集中している。大口の行動チェックリストに照らし合わせた場合、最も適切な判断はどれですか？', '上昇トレンドの一時休止であり、買いを継続すべき', '分配期の特徴が揃っており、ブルトラップに警戒して上値での買いは避けるべき', '蓄積が完了しており、上放れのブレイクアウトを待つべき', '出来高が高いので本物のブレイクの前兆であり、買いエントリーの準備をする', 2, '長い上昇後の高値圏レンジ、上ヒゲの目立ち、高い出来高でも上値が重い、レンジ上限での大量売買集中は全て分配期の特徴です。大口はレンジ上限付近で売り抜けている可能性が高く、ブルトラップに警戒して上値での買い注文は避けるべき判断です。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(24, 'テクニカル分析とファンダメンタルズ分析の関係を「地図」と「天気予報」に例えた理由として正しいものはどれですか？', 'テクニカルが上位でファンダメンタルズが下位であるため', 'どちらも独立した情報であり、両方揃って初めて完整的な判断ができるため', 'どちらか一方があればもう一方は不要であるため', 'ファンダメンタルズの方が常にテクニカルより重要であるため', 2, 'テクニカルは道筋を示す「地図」、ファンダメンタルズは環境変化を知らせる「天気予報」であり、上下関係はなく両方必要です。片方だけでは不十分な判断になります。', false, 1),
(24, 'FRBが最も重視するCPI指標はどれですか？', '総合CPI', '生産者物価指数', 'コアCPI', '輸入物価指数', 3, 'FRBが重視するのは食品・エネルギーを除いたコアCPIです。これらは変動が激しいため、インフレの基調的なトレンドを読むためにコアCPIを重視します。', false, 2),
(24, '金融サイクルにおいて「春」にあたる相場はどれですか？', '業績相場', '逆金融相場', '逆業績相場', '金融相場', 4, '金融相場が「春」にあたります。FRBの利下げによって株が先行上昇し始める時期で、景気はまだ悪いものの成長株・テックセクターが強くなります。', false, 3),
(24, 'NFP（非農業部門雇用者数）の発表において、ヘッドラインの数字に加えて確認すべき項目に含まれないものはどれですか？', '失業率', '平均時給', '世帯調査との乖離', '貿易収支', 4, 'NFPでは失業率、平均時給、世帯調査との乖離を確認します。貿易収支は雇用統計の構成要素ではありません。', false, 4),
(24, 'FOMCの4要素として正しい組み合わせはどれですか？', '声明文、ドットプロット、議長記者会見、議事要旨', '声明文、GDP速報値、議長記者会見、失業率', 'ドットプロット、CPI、議事要旨、財政収支', '声明文、非農業部門雇用者数、ドットプロット、消費者信頼感指数', 1, 'FOMCの4要素は声明文、ドットプロット（年4回）、議長記者会見、議事要旨（3週間後公開）です。これらを総合して金融政策の方向性を読み取ります。', false, 5),
(24, 'CPIの「前月比」と「前年比」の違いとして正しい説明はどれですか？', '前月比はトレンド、前年比は勢いを示す', '前月比は勢い、前年比はトレンドを示す', '前月比と前年比は同じデータの異なる表示方法にすぎない', '前年比の方が常に前月比より重要であり、前月比は参考程度', 2, '前月比はインフレの「勢い」を、前年比は「トレンド」を示します。両方を確認することで、物価の短期的な変化と中長期的な傾向を把握できます。', false, 6),
(24, '市場がCPI発表後に動くきっかけとして正しいものはどれですか？', 'CPIの絶対値が高いか低いかのみで動く', '事前予想値からのズレ（サプライズ）で動く', 'コアCPIが総合CPIを上回った場合のみ動く', '前回のCPI値との差の大きさで動く', 2, '市場は「予想からのズレ」で動きます。絶対値そのものよりも、エコノミストの予想より高いか低いかによって反応が決まります。', false, 7),
(24, 'ファンダメンタルズの3分類として正しい組み合わせはどれですか？', 'ミクロ、マクロ、政治・政策', 'ミクロ、メゾ、マクロ', 'テクニカル、センチメント、マクロ', '企業、家計、政府', 1, 'ファンダメンタルズはミクロ（企業分析・決算・業績）、マクロ（金利・インフレ・雇用）、政治・政策（政府・中央銀行の動き）の3つに分類されます。', false, 8),
(24, '金融サイクルの「秋」（逆金融相場）においてFRBがとる政策と強いセクターの組み合わせとして正しいものはどれですか？', '利下げ／成長株・テック', '据え置き／幅広いセクター', '利上げ／ディフェンシブ', '利下げ（遅い）／現金・債券', 3, '逆金融相場（秋）はFRBが利上げを行う時期で、株価が重くなります。この時期はディフェンシブセクターが相対的に強くなります。2022年がこの局面にあたります。', false, 9),
(24, '利下げの3種類のうち、株に「追い風」となるものはどれですか？', 'リセッションカット', 'パニックカット', '緊急利下げ', '正常化カット', 4, '正常化カットはインフレが落ち着いた後に正常な金利水準に戻す動きで、株に追い風となります。パニックカットは短期不安定の後回復、リセッションカットは株にマイナスです。', false, 10),
(24, 'NFP発表で「良すぎる雇用データ」が株価にマイナスになる理由として正しいものはどれですか？', '雇用が良いと消費が冷え込むため', '雇用が良すぎると金利低下の可能性が遠のくため', '雇用改善は常に株価下落の前兆であるため', '企業が人件費を削減するため', 2, '雇用が良すぎるとFRBの利下げ必要性が薄れ、金利低下の期待が後退します。高い金利は企業業績やバリュエーションにとってマイナスとなるため、株価に悪影響を及ぼすことがあります。', false, 11),
(24, '重要経済指標の発表前後における4ルールとして、誤っているものはどれですか？', '発表前24時間は新規エントリーを控える', '既存ポジションの損切りを再確認する', '発表直後のスパイクに積極的に飛び乗る', '1〜2時間後に再判断する', 3, '発表直後のスパイクに飛び乗ることはルールで明確に禁止されています。スパイクは方向感が定まらない一時的な変動であり、飛び乗ると損失を被るリスクが高いです。', false, 12),
(24, '金融サイクルの「夏」（業績相場）で注意すべきポイントはどれですか？', '楽観のピークに達している可能性', 'FRBの利上げによる下落リスク', '流動性不足によるスプレッド拡大', 'コアCPIの急上昇リスク', 1, '業績相場（夏）は企業業績が改善して安定上昇する時期ですが、楽観がピークに達するタイミングに注意が必要です。ピーク時は「最大の楽観＝最大のリスク」となります。', false, 13),
(24, 'テクニカル分析が上昇を示しているが、ファンダメンタルズが下落リスクを示している場合、適切な判断はどれですか？', 'テクニカルを優先して買いエントリーする', 'ファンダメンタルズを優先して売りエントリーする', 'どちらかのシグナルが強い方に従ってエントリーする', 'エントリーせず見送る', 4, 'テクニカルとファンダメンタルズが矛盾する場合は「何もしない」が正解です。両方が同じ方向を示している時だけエントリーするという統合判断の基本原則に従います。', false, 14),
(24, '金融サイクルの「冬」（逆業績相場）において、強いセクターと投資のヒントとして正しいものはどれですか？', '成長株・テック／景気回復を先取りして買い増し', 'ディフェンシブ／ショートポジションで利益を狙う', '現金・債券／最悪期が買い場の可能性', '幅広いセクター／レバレッジを最大限活用', 3, '逆業績相場（冬）は本格的な下落局面で、現金・債券が強いセクターです。ただし、最悪期こそが長期的な買い場になる可能性がある点も重要です。', false, 15),
(24, 'FOMCのドットプロットについて正しい説明はどれですか？', '毎回のFOMC会合後に公開される各委員のインフレ予想', '年4回公開される各委員の金利見通しをプロットした図', '議長が単独で作成する今後1年間の政策方針図', '市場参加者の金利予想を集計したサーベイ結果', 2, 'ドットプロットは年4回公開されるFOMC委員各人の金利見通しを点で示した図です。委員ごとの見解のバラつきや中央値から、今後の金利方向性を読み取ります。', false, 16),
(24, 'FRBが利下げを発表した。直前まで景気は安定しておりインフレは目標水準に近づいていた。この利下げはどの分類にあたりますか？', '正常化カット', 'パニックカット', 'リセッションカット', '緊急利上げ', 1, '景気が安定しておりインフレが落ち着いている状況での利下げは「正常化カット」に分類されます。インフレ抑制のための高金利から正常な水準へ戻す動きで、株に追い風となります。', false, 17),
(24, 'パニックカット（緊急利下げ）が行われた直後の市場の典型的な反応として正しいものはどれですか？', '即座に強気相場が始まり株価は安定上昇する', '株価は直ちに底打ちしV字回復する', '債券市場だけが反応し株価は無反応である', '短期的に不安定な変動を示した後、回復に向かう', 4, 'パニックカットは緊急事態への対応であるため、直後は市場が混乱して短期的に不安定な変動になります。その後、政策効果が浸透して回復に向かうのが典型的なパターンです。', false, 18),
(24, 'CPI発表を翌日に控えている状況で、テクニカル分析で明確な買いシグナルが点灯している。ファンダメンタルズの方向は不明確である。この場合の適切な対応はどれですか？', '買いシグナルが明確なので即座にエントリーする', 'ファンダメンタルズが不明確でもテクニカルシグナルが強いので小ロットでエントリーする', '重要指標発表前24時間は新規エントリーを控えるルールに従い見送る', '損切りを広めに設定すればエントリーしてもよい', 3, '重要指標の発表前24時間は新規エントリーを控えるというルールがあります。テクニカルシグナルが明確でも、指標発表による予測不能な変動リスクを避けるため見送りが適切です。', false, 19),
(24, 'FOMC声明文はハト派的で利下げを示唆していたが、テクニカル分析では上値が重く下降トレンドが継続している。この状況で「FRBが利下げするから買い」と判断してエントリーした場合、何を無視していることになりますか？', 'テクニカル×ファンダの統合判断において、両方の方向が一致している必要があるという原則', 'FOMC声明文は市場に影響を与えないという事実', '利下げは常に株価上昇につながるという前提', 'テクニカル分析はファンダメンタルズより重要であるという原則', 1, 'ファンダメンタルズは上昇を支持していても、テクニカルが下降を示している場合、両方が同じ方向を示していないためエントリーすべきではありません。片方だけの判断で飛びつくのは統合判断の原則に反します。', false, 20);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(25, '連勝バイアス（オーバーコンフィデンス）の典型的な兆候として、最も早期に現れやすいものはどれですか？', 'エントリー条件の緩和とチェックリストの省略', '全く別の銘柄への乗り換え', 'トレード日記の記述量の増加', '損切りラインの大幅な拡大', 1, '連勝が続くと「自分なら条件が揃っていなくても勝てる」と錯覚し、チェックリストを省略し始めます。これは初期兆候として最も多く見られ、気づきにくいのが特徴です。', false, 1),
(25, '勝率60%のトレーダーが5連勝する確率は約7.8%です。この連勝を「実力」と誤認した場合に最も起こりやすい行動はどれですか？', 'トレードを完全にやめて利益を確保する', '分析手法を根本から見直す', 'ロットを増やして稼ぐチャンスと捉える', '損切りをより厳格に設定する', 3, '5連勝は確率的に起きる事象ですが、本人は「自分が特別な何かを掴んだ」と錯覚し、「勝ている間に稼ごう」とロットを増やす行動に出やすくなります。', false, 2),
(25, '連勝時の対応として「5連勝したら1日休む」というルールが推奨される理由は何ですか？', '5連勝すると体力的に疲労が蓄積しているため', '5連勝は統計的に極めて稀であり、その後の連敗リスクが高まるため', '5連勝した翌日は必ず相場が荒れるため', '5連勝は手法が市場に完全に適合した証拠であり、市場環境が変わる前に対策が必要なため', 2, '5連勝は勝率60%でも7.8%の確率でしか起きない稀な事象です。確率の波が頂点に近い状態であり、冷静な判断力を取り戻すためにクールダウンが必要です。', false, 3),
(25, '連勝バイアスが「口座を壊す起点」になり得る理由として最も適切なものはどれですか？', '連勝による自信過剰がロット増大や損切り先延ばしを引き起こし、1回の負けで連勝分を全て吹き飛ばすため', '連勝すると分析能力そのものが低下するため', '連勝後は相場環境が自動的に悪化するため', '連勝中は必ずエントリータイミングが遅くなるため', 1, '連勝で膨らんだ自信がリスク管理を緩め、普段より大きなロットや甘い損切り設定を許してしまいます。その結果、1回の大きな負けで複数回の利益が一瞬で消えます。', false, 4),
(25, '3連勝した際に推奨される対応として正しいものはどれですか？', '手法が機能している証拠なので、さらに積極的にエントリーする', 'エントリー前チェックリストに「連勝バイアスに支配されていないか？」を追加し、1つでもNOなら見送る', '3連勝ではまだ統計的有意性がないため、5連勝するまで通常通り続ける', '直ちに全ポジションを決済してトレードを終了する', 2, '3連勝は5回に1回程度起きる確率ですが、バイアスが発動し始める水準です。チェックリストを厳格化し、バイアスのサインを自問することで過剰な自信を中和します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(26, '確証バイアスが「分析力が上がるほど強くなる」と言われる理由は何ですか？', '分析力が高いほど損切りの必要性を感じなくなるため', '分析力が上がると他人の意見を聞かなくなるため', '分析力が高いトレーダーほど感情の影響を受けやすい性質があるため', '分析力があるからこそ、自分の仮説を支持する根拠を「上手に」見つけてしまうため', 4, '分析力が高いほど、自分の仮説を正当化する材料を効率よく探し出せるようになります。その結果、反対の根拠に気づきにくくなり、確証バイアスがより強く働きます。', false, 1),
(26, '確証バイアスの4つの症状のうち、「損切りラインを無意識に広げる」行動の根底にある心理はどれですか？', '相場の将来予測に対する過度な自信', '利益を最大化したい欲求', '自分の仮説が間違っていることを認めたくない心理', '損切りラインの計算方法を誤解していること', 3, '損切りラインを広げるのは「自分の判断が間違っていた」という不快感を避けるためです。損切りを認めることは自分の仮説の否定を意味するため、無意識にそれを先延ばしにします。', false, 2),
(26, '「悪魔の代弁者（Devil''s Advocate）」を実践する目的として正しいものはどれですか？', '自分のシナリオを常に否定して安全な判断だけを下すこと', '反対意見を探すことでエントリーを見送る回数を増やすこと', '他人の分析を批判することで自分の分析力を高めること', '反対の根拠も含めた上で判断し、それでもメインシナリオが優勢ならより大きな確信を持つこと', 4, '「反対の根拠を探す」こと自体が目的ではなく、「反対の根拠も含めて判断する」ことが目的です。両方を比較した上でメインシナリオが優勢なら、より確信のあるエントリーができます。', false, 3),
(26, '「悪魔の代弁者」を実践する際、反対の根拠が2つ以上「深刻」と判定された場合に推奨される対応はどれですか？', '反対根拠を無視してメインシナリオでエントリーする', 'エントリーを見送る、またはロットを縮小する', '反対根拠の数だけ増やすまで分析を続ける', 'エントリー方向を反対に切り替える', 2, '反対の深刻な根拠が2つ以上ある場合、メインシナリオの確度が下がっています。見送りかロット縮小でリスクを抑えるのが合理的な判断です。', false, 4),
(26, 'あるトレーダーが「買い」と決めた後、買いの根拠を5つ見つけたが、売りの根拠を1つも探していない。これは確証バイアスのどの症状に該当しますか？', 'チャートの「都合の良い部分」だけ見る', 'SNSで同じ方向の意見だけ見る', '反対方向の根拠を探さない', '損切りラインを無意識に広げる', 3, '自分の方向と反する根拠を意図的に探さないことは、確証バイアスの基本症状の一つです。買いの根拠ばかり集めていると、売りの視点が完全に欠落します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(27, '「前はこの形で勝てた」という思考が危険な理由として最も本質的なものはどれですか？', '過去のトレード記録が不正確である可能性が高いため', '過去の成功パターンは一度しか機能しないため', '他のトレーダーも同じパターンを探しているため', '相場は二度と全く同じ状況にはならないため', 4, '相場環境はボラティリティ、流動性、市場参加者の構成など常に変化しています。過去に成功したパターンが「形」は似ていても、背景となる条件は全く異なることが多いです。', false, 1),
(27, '成功体験への執着が引き起こす「過学習」とは、具体的にどのような状態ですか？', '過去の膨大なデータを分析しすぎて判断が遅くなる状態', '過去の成功パターンに過度に最適化され、条件が揃っていなくても似た形に飛びつく状態', '新しい手法を次々と試して一つも極められない状態', '学習しすぎてシンプルな判断ができなくなる状態', 2, '過去の成功体験が強く印象に残ると、少しでも似たチャートパターンを見ると条件を確認せずにエントリーしてしまいます。「形」への過度な反応が判断を歪めます。', false, 2),
(27, '成功体験への執着に対する対策として「全てのトレードを1回のサンプルとして扱う」習慣の目的は何ですか？', '過去のトレードを全て忘れて常に白紙から始めるため', '1回ごとに異なる手法を試すため', '特定の1回のトレードに特別な意味を持たせず、100回の結果で手法を評価するため', 'トレードの回数を増やすこと', 3, '「あの1回」に過度な意味を持たせることが執着の原因です。統計的なサンプルの1つとして扱うことで、個別の成功体験への感情的な固執を防ぎます。', false, 3),
(27, '月に1回「手法の棚卸し」をする目的として最も適切なものはどれですか？', '先月の勝ちパターンが今月も通用しているか確認し、相場環境の変化に対応するため', '勝率を高めるために毎月新しい手法を導入するため', '月に1回は必ずトレードしない日を作るため', '過去1ヶ月間の全トレードを他人に共有するため', 1, '相場環境は常に変化しており、先月通用した手法が今月も有効とは限りません。定期的な棚卸しで環境変化に気づき、必要に応じて微調整する柔軟性を保ちます。', false, 4),
(27, '「初心者の目」で定期的にチャートを見る習慣が推奨される理由は何ですか？', '初心者の方が分析が正確な場合があるため', '初心者向けの時間足を使うため', '過去の成功体験を一旦リセットし、先入観なしにチャートが語っている情報を読むため', '初心者の頃の謙虚な気持ちを思い出してモチベーションを高めるため', 3, '成功体験が蓄積されるとチャートを見た瞬間に「前と同じだ」という先入観が働きます。まっさらな状態で「今、このチャートは何を語っているか」を読むことで、バイアスを排除できます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(28, '中級者に現れるプロスペクト理論の「第二段階」とは、どのような問題ですか？', '損切りができずに損失が拡大し続ける問題', '連勝後にロットを増やしすぎる問題', '利益を伸ばせず、利確目標より手前で決済してしまう問題', '他人の成績と比較して焦る問題', 3, '初心者段階の「損切りできない」問題を克服した中級者には、「含み益を失いたくない」心理から利確目標に到達する前に決済してしまう問題が現れます。', false, 1),
(28, 'SNSの他人の成績と自分を比較することが危険な理由として最も適切なものはどれですか？', 'SNSのトレーダーは虚偽の情報を投稿している可能性が高いため', 'SNSに流れてくるのは「勝ったトレード」だけで、全体像ではないため', '他人のトレード手法を真似すると一貫性が失われるため', '自分の手法が劣っていると感じて自信を失うため', 2, 'SNSでは勝ったトレードだけが投稿され、負けたトレードは投稿されません。他人のハイライトリールと自分の全体像を比較することで、不当な焦りが生じます。', false, 2),
(28, '「もう十分に稼いだから今月は守りに入ろう」という思考が危険なのはなぜですか？', '「守る」が「条件が揃ってもエントリーしない」に変わり、または逆に「ボーナストレード」と称してリスクの高いトレードに走るため', '守りの姿勢では利益が減り続けるため', '月の後半は相場が必ず荒れるため', '守りに入ると損切りの習慣が崩れるため', 1, '一見合理的に見える「守り」ですが、判断基準が「これまでの損益」に歪められ、本来エントリーすべき場面で見送ったり、逆に普段やらないリスクを取ったりする原因になります。', false, 3),
(28, '「前回の結果」を次のトレードに持ち込まないために重要な認識はどれですか？', '前回のトレードの詳細を完全に忘れること', '過去10回のトレード結果の平均値だけを参考にすること', '前回勝った通貨ペアと同じものを避けること', '毎回のトレードは独立した事象であり、判断基準はその時点の環境認識とシナリオだけで行うこと', 4, '前回勝っても負けても、次の相場には影響しません。毎回のトレードを独立した事象として扱い、現在の環境認識とシナリオだけで判断することがバイアスを防ぎます。', false, 4),
(28, '比較すべき正しい対象として推奨されるものはどれですか？', '同じ手法を使っているSNS上のトレーダー', '1ヶ月前の自分自身', 'プロフェッショナルトレーダーの月間成績', '自分が目標とする年間利回り', 2, '成長の基準は「1ヶ月前の自分」です。環境認識が正確になったか、損切りが計画通りできたか、ルーティンを守れたかなど、自分の中の成長を測ることが重要です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(29, 'バイアス対策において「意志力」ではなく「仕組み」に頼るべき理由は何ですか？', 'バイアスが発動している瞬間は、自分がバイアスに陥っていることに気づけないから', '意志力が強い人ほどバイアスにかかりやすいから', '仕組みを作ることで分析力が向上するから', '意志力には限界がなく、長期的には効かなくなるから', 1, 'バイアスの本質的な恐ろしさは、かかっている本人がそれに気づけない点にあります。だからこそ、チェックリストやルールといった「仕組み」で自動的にストップをかける必要があります。', false, 1),
(29, '心理チェックリストで「1〜2つYES」の場合に推奨される対応はどれですか？', '直ちに全ポジションを決済する', '通常通りのロットでトレードを続ける', '心理状態が回復するまで1週間トレードを休む', '該当項目を意識しつつ、ロットを通常の70%に縮小してトレードする', 4, '1〜2つYESは「注意」レベルです。完全に停止するほどではありませんが、バイアスの兆候があるため該当項目を意識しながらロットを縮小してリスクを抑えます。', false, 2),
(29, '月次メンタル振り返りで「勝った月」の方が「負けた月」より問題が多いと気づける理由は何ですか？', '勝った月はエントリー回数が多すぎるため', '勝っていると油断してチェックリストを省略し、ロットが自然と大きくなり、翌月に大きな負けが来るため', '勝った月は相場環境が特別で、その環境が終わると必ず負けるため', '勝った月は運が良かっただけで実力ではないため', 2, '勝っている時は連勝バイアスや過信が知らず知らずのうちにリスク管理を緩めます。この「勝っている時の油断」が翌月の大きな損失の原因になるパターンを、振り返りで可視化できます。', false, 3),
(29, '心理チェックリストの項目「今日は絶対にトレードしたいと思っていないか？」がYESの場合、どのような判断が適切ですか？', '焦りの原因を分析してからエントリーする', '条件が完全に揃っていればエントリーしてもよい', 'それだけでトレードを休む十分な理由になる', '焦っているなら早くエントリーして落ち着くべき', 3, '「絶対にトレードしたい」という焦り自体が、条件を緩めてエントリーする危険なサインです。この感情がある時点で冷静な判断は期待できないため、休むことが適切です。', false, 4),
(29, '心理チェックリストの8項目のうち「3つ以上YES」の場合の対応として正しいものはどれですか？', 'ロットを半分にして慎重にトレードする', '今日はトレードを休み、翌日にリセットしてから再開する', 'YESの項目だけ意識しながら通常通りトレードする', '心理チェックリストの項目を見直して修正する', 2, '3つ以上YESは「危険」レベルです。複数のバイアスが同時に発動している状態であり、トレードを休んで翌日リセットするのが最も安全な対応です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(30, '5連勝後にロットを2倍にした結果、1回の負けで5連勝分の利益の大半を失った。この事例から読み取れる最も重要な教訓はどれですか？', '5連勝した後は必ず負ける運命にある', '5連勝した銘柄と同じ銘柄ではトレードすべきでないこと', '2倍より3倍に増やしていればリカバリーできた可能性があること', 'ロットを変えていなければ、1回の負けは他の1回の負けと同じ程度の損失で済んだこと', 4, 'ロットを一定に保っていれば、1回の負けは単なる1回の損失で済みます。連勝中のロット変更が、統計的なリスク管理を破壊する最大の要因です。', false, 1),
(30, '「買い」と決めた後に買いの根拠だけを5つ集め、出来高の減少とVIX上昇を見落とした結果、トレンド転換で損切りされた。この失敗を防ぐために有効な対策はどれですか？', '買いの根拠を10個に増やすこと', '出来高とVIXを全く見ないようにすること', '他人の買い意見だけを参考にすること', 'エントリー前にメインの根拠と同数の反対根拠を探す「悪魔の代弁者」を実践すること', 4, '買いの根拠を増やすだけでは確証バイアスを強めます。「悪魔の代弁者」で反対の根拠を意図的に探すことで、出来高減少やVIX上昇などの危険信号を見落とさなくなります。', false, 2),
(30, '過去にS級ゾーンでピンバーが出て大きく取れた経験があるトレーダーが、鮮度3回目のゾーンで合流1層しかないにもかかわらずエントリーして損切りされた。この失敗の根本原因は何ですか？', 'パターンの「形」の類似性だけで判断し、鮮度や合流といった「条件」を確認しなかったこと', 'ピンバーというパターン自体が信頼性に欠けること', 'S級ゾーンでは必ず損切りされる運命にあること', 'エントリータイミングが遅すぎたこと', 1, '成功体験への執着により「形が似ている」だけで飛びつきました。鮮度3回目は注文枯渇、合流1層は根拠不足であり、条件を確認していれば見送りでした。', false, 3),
(30, 'RR1:3の利確目標があるのにRR1:1.5の時点で全ポジションを利確してしまい、その後利確目標に到達した。この問題を構造的に解決する方法として最も適切なものはどれですか？', '利確目標をRR1:1.5に下げる', 'ロットを減らして心理的負担を軽くする', '利確しないで必ずRR1:3まで待つ', '分割利確で33%を先に確保し、残りで目標まで伸ばす', 4, '分割利確で一部の利益を先に確保することで、「利益を失いたくない」心理を満たしつつ、残りのポジションで利確目標まで伸ばす心の余裕が生まれます。', false, 4),
(30, '3日間ノートレードが続き、「何もしていない＝サボっている」と感じて条件が完全には揃っていないのにエントリーした。この「焦りのバイアス」に対する正しい認識はどれですか？', '見送りは立派な投資判断であり、「条件が揃わなかったから正しく見送った」と捉えるべき', '3日間トレードしないのは怠惰であり、即座に改善すべき', 'ノートレードが続く時は条件を緩めてでもエントリーすべき', '3日以上トレードしない場合は強制的にエントリーするルールを作るべき', 1, '「トレードしない＝無駄」という認知の歪みが焦りを生みます。条件が揃わない場面で見送ることも立派な投資判断であり、「何もしなかった」のではなく「正しく見送った」と認識することが重要です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(31, '経済指標を相場への影響度で3段階に分類したとき、Tier 1（最重要）に該当する指標の組み合わせとして正しいものはどれですか？', '政策金利決定、消費者物価指数、雇用統計', 'PMI、中央銀行総裁の講演、貿易収支', '鉱工業生産指数、住宅着工件数、小売売上高', 'GDP速報値、PMI、中央銀行総裁の講演', 1, 'Tier 1は政策金利決定（FOMC等）、CPI、雇用統計（NFP）の3つで、相場の方向を変える可能性がある最重要指標です。最初はこの3つだけ意識すれば十分です。', false, 1),
(31, '経済指標で相場が大きく動く直接の要因は何ですか？', '指標の結果そのものの絶対値が高いこと', '前回の指標値との差の大きさ', '市場の事前予想と実際の結果との差（サプライズ）', '指標が発表された時間帯の出来高の多さ', 3, '相場が動くのは「結果の良し悪し」ではなく「市場予想との差」です。良い結果でも織り込み済みなら反応は限定的で、予想を裏切る結果が出たときに大きく動きます。', false, 2),
(31, '指標の結果が市場予想を上回った場合（ポジティブサプライズ）、基本となる相場の反応として正しいものはどれですか？', '必ず通貨安方向に動く', '通貨高方向に動きやすいが、織り込み済みの場合は逆に動くこともある', '常況に関わらず必ず上昇する', '出来高が減少するまで反応を待つ必要がある', 2, 'ポジティブサプライズは基本的に通貨高方向の動きを生みますが、すでに市場がその結果を織り込んでいる場合は「噂で買って事実で売る」の逆行現象が起きます。', false, 3),
(31, '経済指標の結果が市場予想とほぼ同じだった場合、相場はどう反応しやすいですか？', '予想以上に大きく動くことが多い', '大きな反応はなく、すでに織り込まれていた証拠となる', '必ず翌日にかけて急激なトレンドが発生する', '出来高だけが急増して価格は動かない', 2, '結果が予想通りの場合、市場はすでにその数値を前提にポジションを組んでいるため大きな反応は起きません。これが「織り込み済み」の典型的な状態です。', false, 4),
(31, 'Tier 2（重要）の経済指標に該当するものはどれですか？', '消費者物価指数（CPI）', 'PMI（購買担当者景気指数）', '鉱工業生産指数', '非農業部門雇用者数（NFP）', 2, 'Tier 2はPMIや中央銀行総裁の講演などで、大きな値動きを生むことがあるもののTier 1ほどの方向転換は起こしにくい指標です。CPIとNFPはTier 1に分類されます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(32, 'Tier 1指標の発表を控えている場合、含み益のポジションに対して取るべき対応として最も適切なものはどれですか？', '発表直前にロットを増やして利益を最大化する', '一部利確、トレーリングストップの設定、または建値ストップへの移動を検討する', '指標結果を予測してポジションを維持する', '損切りラインを広げて指標発表の波を乗り切る', 2, '含み益のポジションは、発表前に利益を一部確保するか、トレーリングストップや建値ストップで保護することが基本です。指標次第で利益が消えるリスクを事前に管理します。', false, 1),
(32, '「CPIが良ければ上がるから、発表前に買っておこう」という考え方はなぜ危険ですか？', 'CPIの結果は公開されないことがあるため', '指標の結果は誰にもわからず、結果に賭けるのはトレードではなくギャンブルであるため', 'CPI発表日は取引所が閉まっているため', 'CPIはTier 2指標であり、そもそも相場に影響しないため', 2, '発表前にポジションを取るのは結果への賭けであり、トレードではありません。結果が出た後に対応するのが原則で、事前のポジション整理が重要です。', false, 2),
(32, '経済指標発表前にノーポジションの場合、事前に準備すべき最も重要なことは何ですか？', '発表直後に飛び乗るための指値注文を入れておくこと', '結果がどちらに出ても対応できるIf-Thenシナリオを3パターン準備すること', 'SNSで他のトレーダーの予想を確認すること', '発表日まで全くチャートを見ないこと', 2, 'ノーポジションの場合は、「結果＞予想」「結果＝予想」「結果＜予想」の3パターンのシナリオを事前に準備し、いずれの場合も発表直後のスパイクには飛び乗らないことを決めておきます。', false, 3),
(32, '指標発表前に含み損のポジションがある場合、取るべき対応として正しいものはどれですか？', '損切りラインを広げて様子を見る', '指標結果次第でさらに悪化するリスクを想定し、発表前に損切りを検討する', 'ナンピンして平均取得価格を下げる', '指標発表後に必ず反転すると信じて保有し続ける', 2, '含み損のポジションは指標結果によってさらに悪化するリスクがあります。発表前に損切りを検討するか、少なくとも損切りラインを確認・再設定することが重要です。', false, 4),
(32, '指標前のシナリオ準備テンプレートで、「結果＝予想」の場合の対応として正しいものはどれですか？', '結果にかかわらず直ちにエントリーする', '通貨高方向への強いエントリーを検討する', '大きな動きはないため、通常のテクニカル分析に戻る', '全ポジションを決済して翌日まで待つ', 3, '結果が予想通りの場合は大きな反応がなく、材料はすでに織り込み済みです。テクニカル主体の通常の分析・判断に戻って対応します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(33, 'Tier 1指標の発表直後（0〜5秒）の相場状態と対応として正しいものはどれですか？', '方向が確定しているため即座にエントリーする', '初動スパイクによりスプレッドが急拡大し、この瞬間のエントリーは極めて危険である', '出来高が減少するため安全にエントリーできる', '必ずトレンドの方向に沿った直線的な動きになる', 2, '発表直後の0〜5秒は結果に反応して急激に動き、スプレッドが急拡大します。この瞬間にエントリーするのはリスクが極めて高く、避けるべきです。', false, 1),
(33, '指標発表後の「ウィップソー（往復ビンタ）」が起きやすい時間帯はいつですか？', '発表から0〜5秒', '発表から5秒〜5分', '発表から30分〜2時間', '発表から翌日', 2, '5秒〜5分の間は初動と逆方向に急反転するウィップソーが起きやすく、「上がった→戻った→やっぱり上がった」という乱高下が発生します。', false, 2),
(33, '経済指標発表中のルールとして、発表後どの程度の時間は新規エントリーを禁止すべきとされていますか？', '発表後5分間', '発表後30分間（Tier 1の場合は1〜2時間まで延長推奨）', '発表後10分間', '発表後12時間', 2, '基本ルールは発表前30分〜発表後30分の新規エントリー禁止で、Tier 1指標の場合は発表後1〜2時間まで延長が推奨されます。混乱が落ち着くまで待つことが重要です。', false, 3),
(33, '指標発表直後にチャートを見ることについて正しい態度はどれですか？', 'チャートを見ると感情が揺さぶられるため見ない方がよい', 'チャートを見てもよいが、「見る」と「動く（注文する）」を明確に分離する', 'チャートを見たら必ず何らかのアクションを取るべきである', 'チャートを見る代わりにSNSの反応を確認すべきである', 2, '「見る」と「動く」を分離することが重要です。観察自体は学習になりますが、感情に支配された状態でのエントリーは避けるべきです。', false, 4),
(33, '指標発表中に既存ポジションの損切りが発動した場合、どう対応すべきですか？', 'すぐに損切りを取り消す', '発表前に設定した損切りが発動したのは計画通りであり、手動で変更しない', '損切り価格をさらに広げてポジションを維持する', '同じ方向にすぐさま再エントリーする', 2, '発表前に設定した損切りが発動したら計画通りです。手動で損切りラインを変更したり、損切りを取り消したりするのは感情に支配された判断になり危険です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(34, '指標発表後の再エントリーを検討する5条件に含まれないものはどれですか？', '値動きで上昇/下降の方向が明確になっていること', '指標の結果とテクニカル分析の方向が一致していること', '発表直後のスパイクに乗る形でエントリーできていること', 'スプレッドが通常の水準に戻っていること', 3, '再エントリーの5条件は「方向が明確」「テクニカルとの整合」「出来高の正常化」「スプレッドの正常化」「ゾーン/トリガーの確認」です。スパイクへの飛び乗りは明確に避けるべき行動です。', false, 1),
(34, '指標発表後の再エントリーにおいて、「出来高が落ち着いた」ことを確認する理由は何ですか？', '出来高が多いと約定しにくいため', '異常な出来高の間はノイズが多く、方向が定まっていない可能性が高いため', '出来高が多いとトレンドが終わる兆しであるため', '出来高は価格変動と無関係であるため', 2, '発表直後の異常な出来高の間は市場が結果を消化している最中であり、ノイズも多いです。出来高が通常水準に戻りつつあるタイミングで方向が明確になります。', false, 2),
(34, '「織り込み済み」の典型的なサインとして正しいものはどれですか？', '発表前に大きく動いていなかったのに、発表直後に急激に動いた', '発表前にすでに大きく動いており、結果通りに動いた直後に急反転した', '発表後に出来高が急増して方向が定まった', '指標結果が予想と大きく乖離した', 2, '織り込み済みの典型は、発表前にすでに動いていた（噂で買った）状態で、結果通りの動きをした直後に「事実で売る」反転が起きるパターンです。初動は反射反応、反転が市場の本音です。', false, 3),
(34, '指標発表後の環境認識アップデートの正しい手順として並べたものはどれですか？', 'ステップ1:テクニカル確認→ステップ2:指標結果確認→ステップ3:市場解釈確認→ステップ4:見通し更新', 'ステップ1:指標結果確認→ステップ2:市場解釈確認→ステップ3:テクニカルとの整合確認→ステップ4:見通し更新', 'ステップ1:市場解釈確認→ステップ2:指標結果確認→ステップ3:ポジション構築→ステップ4:見通し更新', 'ステップ1:見通し更新→ステップ2:テクニカル確認→ステップ3:市場解釈確認→ステップ4:指標結果確認', 2, 'まず指標の結果を確認し、次に市場がその結果をどう解釈しているかを確認、テクニカルとの整合を取り、最後に今後の見通しを更新する、という順序が正しい手順です。', false, 4),
(34, 'テクニカルが上昇を示し、ファンダメンタルズも上昇方向の場合、トレードの確度はどう評価されるべきですか？', '低確度 — ファンダメンタルズは無視してよい', '中確度 — ロットを50〜70%に縮小する', '高確度 — 積極的にエントリーを検討できる', '不可能 — テクニカルとファンダが一致することはない', 3, 'テクニカルとファンダメンタルズが同方向を向いている場合は高確度と評価でき、通常のポジションサイズで積極的にエントリーを検討できます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(35, 'FOMC（連邦公開市場委員会）の発表において、金利据え置きが決定された場合でも相場が大きく動く理由として最も適切なものはどれですか？', '金利据え置きは常に相場に悪影響を与えるため', '声明文の文言や記者会見のニュアンスで「将来の金利の方向」が変わるため', '金利据え置きは予想外の出来事であるため', '市場は金利決定そのものには反応しないため', 2, 'FOMCでは金利の変更の有無だけでなく、声明文の文言や議長の記者会見で将来の金利政策のニュアンス（タカ派かハト派か）が変わることで相場が大きく動きます。', false, 1),
(35, 'NFP（非農業部門雇用者数）の特徴として正しいものはどれですか？', '毎月第一月曜日に発表される', '発表直後のボラティリティが非常に大きく、上下に100pips以上振れることもある', 'Tier 2指標であり、特別な対応は不要', '発表前のADP雇用統計と常に同じ方向の結果が出る', 2, 'NFPは毎月第一金曜日に発表され、発表直後のボラティリティが極めて大きいのが特徴です。最もウィップソーが激しい指標で、上下に100pips以上振れることもあります。', false, 2),
(35, 'NFPの発表前に確認しておくと役立つ先行指標は何ですか？', 'CPIの前月比', 'ADP雇用統計（民間版の先行指標）', 'FOMCの議事要旨', 'ドルインデックス（DXY）の週足チャート', 2, 'NFPの週前半に発表されるADP雇用統計は民間版の先行指標として機能し、おおまかな雇用の方向感を把握する参考になります。', false, 3),
(35, 'CPI発表後の対応として正しいものはどれですか？', '初動スパイクに乗って素早くエントリーする', '「結果＞予想＝通貨高」が基本だが、織り込み済みの場合は逆に動くことを前提に見送り、方向が定まってから検討する', 'CPIはTier 2指標なので通常通りのトレードを継続する', '結果に関わらず必ずショートポジションを取る', 2, 'CPIはインフレ動向を示し金利政策に直結しますが、基本の「結果＞予想＝通貨高」が必ずしも当てはまるわけではありません。織り込み済みの場合は逆行するため、初動を見送って方向が定まってから判断します。', false, 4),
(35, 'FOMCの翌日以降にやるべき対応として正しいものはどれですか？', 'FOMCの影響は発表日だけなので翌日からは通常通りでよい', '中長期的な金利の方向性を踏まえて、バイアス（買い目線/売り目線）を修正する', 'FOMC翌日は必ず全ポジションを決済する', 'FOMCの結果を忘れて新しい環境認識をゼロから始める', 2, 'FOMCの影響は発表日だけではありません。翌日以降は声明文や記者会見の内容を踏まえて中長期的な金利の方向性を再評価し、自身の相場バイアスを修正します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(36, 'CPI結果が予想を下回り（インフレ鈍化）、テクニカルも下降トレンド継続中だった場合の評価として正しいものはどれですか？', 'ファンダとテクニカルが逆方向のため見送る', 'テクニカルとファンダが一致しており、高確度のエントリーチャンスになり得る', 'インフレ鈍化は必ず通貨高につながるため買いを検討する', '指標結果が悪い場合はエントリーを禁止するルールがある', 2, 'テクニカルの下降トレンドと、CPI結果による利上げペース鈍化期待の通貨安方向が一致していれば、高確度のエントリーチャンスになります。発表後の値動きが落ち着いたタイミングで検討します。', false, 1),
(36, '雇用統計が予想を大幅に上回る好結果だったにもかかわらず、初動の急上昇後に大幅下落した場合、その原因として最も考えられるものはどれですか？', '雇用統計のデータに誤りがあったため', '発表前の1週間で市場がすでに好結果を織り込んで上昇していた「噂で買って事実で売る」パターンのため', '好結果の雇用統計は常に下落を引き起こすため', '出来高が少なすぎて価格が維持できなかったため', 2, '発表前に市場が好結果を織り込んで上昇していた場合、結果が出た瞬間に「もう上がる材料は出尽くした」と解釈され、利益確定の売りに転じます。初動の上昇は反射反応、反転が市場の本音です。', false, 2),
(36, 'FOMCで金利据え置きが決まったが、声明文が想定よりタカ派だった場合、翌日以降の対応として正しいものはどれですか？', '金利は変わっていないので無視してよい', '金利自体は変わらなくても「将来の金利の方向」が変わったと判断し、環境認識をタカ派寄りにアップデートする', 'タカ派の声明文は必ず株価上昇につながるため即座に買いを入れる', '声明文はテクニカル分析に影響しないため無視する', 2, '金利が据え置かれても、声明文のタカ派的なニュアンスは将来の利上げ確率を高めます。環境認識のマクロ背景をタカ派寄りにアップデートし、通貨高方向のバイアスに修正します。', false, 3),
(36, 'CPI発表前に含み益のスイングロングポジションがある場合の対応として最も適切なものはどれですか？', '全ポジションを一度決済して、発表後に買い直す', '分割利確の第一利確分（33%）をCPI発表前に利確し、残りはトレーリングストップで保護する', '含み益があるならそのまま保有し続けるのが最善', 'ロットを増やして利益を最大化する', 2, '分割利確の考え方を活用し、33%分を事前に利確して利益を一部確保します。残りはトレーリングストップで保護し、発表結果がポジション方向と一致すれば継続、逆方向なら自動的に利確されます。', false, 4),
(36, 'テクニカル的に完璧な押し目買いのセットアップが揃っているが、翌日にTier 1指標の発表を控えている場合、どうすべきですか？', 'セットアップが完璧なら指標前でもエントリーすべきである', '発表前のエントリーは見送り、発表後もセットアップが崩れていなければその時点でエントリーする', '半分だけエントリーして残りは発表後に判断する', '指標発表後にセットアップが消えることはないため、すぐエントリーする', 2, 'どんなに完璧なセットアップでも、Tier 1指標次第で方向が急変するリスクがあります。「逃したチャンス」は「回避したリスク」と捉え、発表後に再評価するのが安全な判断です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(37, '毎週日曜夜に確認すべき週次の指標カレンダーチェックの目的は何ですか？', '週前半にエントリーを集中させるため', 'その週のTier 1・Tier 2指標の日程を把握し、対応メモを作成するため', '経済指標がある週は一切トレードしないため', '指標の結果を予想するため', 2, '週次ルーティンでその週の指標スケジュールを確認し、Tier 1・Tier 2の日程と対応メモを作成することで、指標当日に慌てずに計画的な対応ができます。', false, 1),
(37, '指標発表日の朝のルーティンで確認すべき項目に含まれないものはどれですか？', '指標名と発表時刻の確認', '市場予想の確認', '既存ポジションの整理（利確/損切り/建値移動）', '指標の具体的な数値結果の確認', 4, '発表前の朝のルーティンでは指標名・発表時刻・市場予想・既存ポジションの整理・If-Thenシナリオの準備を行います。指標の具体的な数値結果はまだ発表されていないため確認できません。', false, 2),
(37, '指標発表後1〜2時間のチェック項目として正しいものはどれですか？', '方向が明確になったか、テクニカルとの整合、出来高・スプレッドの正常化、ゾーン/トリガーの確認', 'SNSで他のトレーダーのエントリー状況を確認すること', '発表直後のスパイクに乗り遅れていないかを確認すること', '翌日の指標を調べること', 1, '発表後1〜2時間は再エントリーの5条件（方向の明確化、テクニカルとの整合、出来高の正常化、スプレッドの正常化、ゾーン/トリガーの確認）をチェックし、条件が揃えばエントリーを検討します。', false, 3),
(37, '指標発表当日の終わりにやるべき環境認識のアップデートとして正しいものはどれですか？', 'マクロ背景の更新、今後の金利方向に変化があるか確認、週次ファンダチェックリストの更新', 'その日の損益のみを確認して終わる', '翌日のエントリーポイントをテクニカルだけで決める', '指標結果をメモするだけで分析は不要', 1, '発表当日の終わりには、指標結果を踏まえて環境認識のマクロ背景をアップデートし、金利の方向性に変化がないか確認、週次ファンダチェックリストを更新することで今後の判断精度を高めます。', false, 4),
(37, '経済指標に対する中級者の理想的なスタンスとして正しいものはどれですか？', '指標発表日は一切チャートを見ない', '「前」で整理し、「中」で見送り、「後」で活かすという3段階の立ち回りを身につける', '指標発表前に必ずエントリーして利益を狙う', 'Tier 1指標以外は気にしなくてよい', 2, '中級者にとって経済指標は単に避けるだけの存在ではありません。「前」でポジションを整理し、「中」で混乱を見送り、「後」で値動きが落ち着いてからテクニカルとファンダの一致を確認してエントリーする、この3段階の立ち回りが理想です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(38, '環境認識を5つのレイヤーに分解したとき、「トレンドは加速中か減速中か」を判断するのはどのレイヤーですか？', 'レイヤー1：サイクル位置', 'レイヤー3：トレンド強度', 'レイヤー2：トレンド方向', 'レイヤー4：波動位置', 2, 'レイヤー3「トレンド強度」はMA乖離率やADX、出来高を用いて、トレンドの加速・減速を判定します。同じ上昇トレンドでも加速中と減速中で意味が異なります。', false, 1),
(38, '環境認識の3つの問いのうち、「この相場は誰が動かしているか」を推測するために最も有用な判断材料は何ですか？', '移動平均線のクロス', 'フィボナッチリトレースメント', 'RSIのダイバージェンス', '出来高と価格の関係', 4, '出来高と価格の関係から、大口の仕込みフェーズか、個人の追随フェーズか、利確の撤退フェーズかを推測できます。出来高は「誰が動かしているか」の手がかりです。', false, 2),
(38, '環境認識の5レイヤーのうち、レイヤー4「波動位置」で確認する判断材料として正しいものはどれですか？', '波動カウントとフィボナッチ', 'MA乖離率とADX', 'ダウ理論によるHH/HLの判定', '金利、VIX、経済指標', 1, 'レイヤー4「波動位置」では、波動カウントとフィボナッチを使用して、推進波の途中か修正波の途中かを判定します。', false, 3),
(38, '環境認識の5レイヤーのうち、レイヤー1「サイクル位置」で確認する判断材料として正しいものはどれですか？', '週足構造、出来高推移', 'MA乖離率、ADX、出来高', 'ダウ理論（HH/HL判定）、200MA', '金利、VIX、経済指標', 1, 'レイヤー1「サイクル位置」では、週足構造と出来高推移を確認して、蓄積・上昇・分配・下落のどのフェーズかを推定します。', false, 4),
(38, '「今の波は、上位足のどの部分にあたるか」という問いの重要性を最もよく表している状況はどれですか？', '1時間足のピンバーのヒゲの長さを測るとき', '4時間足の上昇が日足の修正波の中の反発なのか、日足の推進波の本流なのかを判断するとき', '週足で上昇トレンドか下降トレンドかを判定するとき', '出来高が20日平均を上回っているかを確認するとき', 2, '同じ4時間足の上昇でも、それが日足の修正波の中の反発であれば期待値は低く、推進波の本流であれば期待値は高くなります。上位足のどの位置にあるかで判断が変わります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(39, 'MTF分析において「3層構造」が実戦で最も機能する理由として正しいものはどれですか？', '3つの時間足を使えば勝率が必ず上がるから', 'プロのトレーダーが全員3層を使っているから', '3層なら全ての通貨ペアで同じ分析ができるから', '2層だと情報が不足し、4層以上だと判断が遅くなるから', 4, '2層構造では情報が不足し、4層以上では判断が遅くなるため、3層（戦略足・戦術足・執行足）が実戦的なバランスとして最適です。', false, 1),
(39, 'MTF分析の3層構造において、戦略足（Strategic）の役割として正しいものはどれですか？', '具体的なエントリーとエグジットのタイミングを取る', '今のトレンド・レンジの状態と波動位置を判定する', '大きなトレンドの方向とサイクル位置を確認する', '出来高の急変をリアルタイムで検知する', 3, '戦略足（週足）の役割は、大きなトレンドの方向とサイクル位置を確認することです。確認頻度は週に1回で十分です。', false, 2),
(39, '3層構造のサーフィン比喩において、「波のセットを待つ」ことに相当するのはどの層ですか？', '戦略足', '執行足', '全ての層が同時', '戦術足', 4, 'サーフィン比喩では、戦略足が「風向きを見る」、戦術足が「波のセットを待つ」、執行足が「ブレイクが来たらパドルする」に相当します。戦術足（日足〜4時間足）はトレンド・レンジの状態と波動位置の判定を担います。', false, 3),
(39, '日足上昇＋4時間足高値圏の組み合わせは、どのような評価・対応が適切ですか？', '順張りの高確度エントリーとして積極的に買う', '新規エントリーは見送り（追いかけ買いのリスク）', '戻り売りを検討する', 'レンジの上限まで限定的に買う', 2, '日足が上昇でも4時間足がすでに高値圏にある場合、新規エントリーは追いかけ買いのリスクが高いため見送りが適切です。', false, 4),
(39, '執行足（Execution）で使用するトリガーのうち、信頼度「強」とされる条件の組み合わせはどれですか？', 'ピンバー出現、包み足完成、ブレイク＋リテスト', '移動平均線のゴールデンクロス＋出来高平均的', '出来高減少＋コマ足の出現', 'レンジ内での小陽線の連続＋出来高増加', 1, '執行足の信頼度「強」のトリガーは、ゾーンでのピンバー出現、前足を実体で包む包み足の完成、水平線ブレイク後のリテスト確認の3つです。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(40, '時間軸の衝突パターンのうち「最頻出」とされるのはどれですか？', '上位足レンジ中の下位足トレンド', '上位足トレンド中の下位足調整', '上位足トレンド転換の初動', '全時間足がレンジ', 2, '上位足トレンド中に下位足が逆行する現象は、トレンドの中に必ず修正波が含まれるため日常的に発生し、最も頻出する衝突パターンです。フィボ38.2〜61.8%＋MA反発で押し目買いを狙います。', false, 1),
(40, '週足レンジ中に日足が上昇している場合、適切な対応として正しいものはどれですか？', '週足を無視して日足のトレンドに乗る', 'レンジ上限でのブレイクアウトを狙ってフルロットで買う', '利確目標をレンジ上限の手前に設定し、ポジションサイズを50%に縮小する', '日足の上昇が週足に反映されるまで待つ', 3, '上位足がレンジの場合、下位足のトレンドはレンジ上限で止まる可能性が高いため、利確目標を手前に設定し、ポジションサイズを縮小するのが適切です。この局面は「罠が多い」パターンです。', false, 2),
(40, '「どの時間足でも方向感がないのに、スキャルピングならいけるかも」という思考が危険な理由として最も適切なものはどれですか？', 'スキャルピングは上級者しかできない手法だから', '手数料コストが高くなるから', 'スキャルピングはMTF分析と相性が悪いから', '方向感のない相場は、短い時間足でも方向感がないから', 4, '方向感のない相場では、時間足を短くしても方向感は現れません。「短い時間足なら答えが見つかる」という幻想を捨てることが重要です。', false, 3),
(40, '上位足トレンド転換の初動を判断する際、「迷ったら」取るべき行動として正しいものはどれですか？', '小さなロットで逆方向にエントリーする', '日足の200MAが下を向くまで待つ', 'フィボ戻し率、出来高、週足安値の3つの手がかりで判断し、それでも迷えば見送る', '4時間足のトリガーが出たら即座にエントリーする', 3, 'トレンド転換の初動は判断が最も難しい局面です。フィボ戻し率・出来高・週足安値の3手がかりで総合判断し、迷った場合は見送るのが正解です。', false, 4),
(40, '全時間足（週足・日足・4時間足）がレンジの状態になった場合、適切な対応はどれですか？', 'トレードしない（「何もしない」が正解）', 'レンジの上下限でデイトレードを繰り返す', 'レンジ幅が狭くなるのを待ってからエントリーする', '4時間足以下で方向感を探す', 1, '全時間足がレンジの状態は方向感が全くなく、トレードすべきでない局面です。「何もしない」ことが正しい判断です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(41, '環境認識に組み込むべきファンダメンタルズ4要素として正しい組み合わせはどれですか？', '金利の方向、GDP成長率、貿易収支、住宅着工件数', '為替介入、財政収支、消費者信頼感、小売売上高', '金利の方向、インフレ動向、雇用統計、リスクオン/オフ', '政策金利、鉱工業生産指数、PMI、失業保険申請件数', 3, '環境認識に組み込むべきファンダ4要素は、金利の方向、インフレ動向（CPI）、雇用統計（NFP）、リスクオン/オフ（VIX・株式市場）です。これらはテクニカル分析の確度を測る基準になります。', false, 1),
(41, 'テクニカルは明確だがファンダメンタルズが中立・不明の場合、適切なアクションはどれですか？', 'エントリーせず、ファンダが明確になるまで待つ', '通常のポジションサイズで積極的にエントリーする', 'ファンダメンタルズ分析をやめてテクニカルのみで判断する', 'エントリー可だが、ポジションサイズを50〜70%に縮小する', 4, 'テクニカルが明確でもファンダが中立の場合は「中確度」と判定し、エントリーは可能ですがポジションサイズを50〜70%に縮小してリスクを抑えます。', false, 2),
(41, 'テクニカルとファンダメンタルズが逆方向のときの対応として正しいものはどれですか？', 'テクニカルを優先して通常サイズでエントリーする', 'ファンダメンタルズを優先して逆方向にエントリーする', 'ポジションサイズを30%に縮小すればエントリーしてよい', '原則エントリーせず、方向が一致するまで待つ', 4, 'テクニカルとファンダが逆方向の場合は「低確度」と判定し、原則としてエントリーしません。両方が一致するまで待つのが適切です。', false, 3),
(41, '週次ファンダチェックリストに含まれる項目として含まれないものはどれですか？', 'VIXの現在の水準確認', 'ドルインデックス（DXY）の方向確認', '主要中央銀行の直近のスタンス確認', '200週移動平均線の傾き確認', 4, '週次ファンダチェックリストは経済指標の日程、主要中央銀行のスタンス、VIX水準、主要株価指数の方向、DXYの方向、リスクオン/オフの記述の6項目です。200週MAの確認はテクニカル分析の環境認識チェックに含まれます。', false, 4),
(41, 'VIXが「15以下」の水準である場合、一般的な市場の状態として正しいものはどれですか？', '市場がパニック状態にあり、リスクオフが強まっている', 'トレンド転換の直前であり警戒が必要', 'ボラティリティが低く、リスクオンの穏やかな相場環境', '出来高が急増しており、ブレイクが近い', 3, 'VIXが15以下の場合は市場の恐怖感が低く、リスクオンの穏やかな環境を示しています。VIXは30以上でリスクオフの警戒レベル、20〜25で注意レベルとされます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(42, '実戦シナリオ分析のケーススタディで「週足上昇×日足押し目×4H反転」の教科書通りの押し目買いにおいて、損切りの適切な位置はどこですか？', '直近高値のすぐ上', '週足の200MAの下', 'フィボ61.8%の下', '4時間足の直近安値', 3, '5レイヤー全てが買いを支持する高確度の場面では、損切りはフィボ61.8%の下に設定します。この位置は修正波の限界ラインとして機能しやすいためです。', false, 1),
(42, '価格は上昇しているのに出来高が直近3週間で明らかに減少している状況は、何を示唆していますか？', '上昇トレンドがさらに加速する前兆', 'トレンドの「息切れ」のサインで、新規買いは見送りすべき', '大口が新たにポジションを構築している', 'レンジ入りする前に一旦調整が入る合図', 2, '価格上昇に出来高が伴わないのは、上昇への参加者が減っている証拠です。トレンドの「息切れ」サインとして、新規買いは見送り、既存ロングはトレーリングストップで保護するのが適切です。', false, 2),
(42, 'テクニカル的には完璧な押し目買いのセットアップが揃っているが、翌日にCPI発表を控えている場合、適切な対応はどれですか？', '発表前のエントリーは見送り、発表後にセットアップが崩れていなければエントリーする', 'CPI発表前にエントリーし、損切りを広めに設定する', 'セットアップが完璧ならCPI前にエントリーすべき', 'ポジションサイズを50%に縮小してエントリーする', 1, 'Tier 1指標の発表前は、結果次第で方向が急変するリスクがあります。「待つ勇気」を持ち、発表後にセットアップが維持されていればその時点でエントリーするのが適切です。', false, 3),
(42, '日足で直近の押し安値を割り込んだが、週足の200MAはまだ上向きの局面で取るべき対応として最も適切なものはどれですか？', '日足の押し安値割れは売り転換の確定信号なので即ショート', '「わからない」と認めて、週足の直近安値まで待って反発を見るか、別のペアを探す', '週足の200MAが上向きだから買いで問題ない', 'フィボナッチ78.6%までの deeper な調整を待って買い', 2, 'この局面は「最も判断が割れる」トレンド転換の見極め場面です。無理に答えを出さず、「わからない」と認めて、より明確な状況を待つか、別の通貨ペアを探すのが適切です。', false, 4),
(42, '週足レンジ×日足上昇のケースで、日足と4時間足だけを見て「買い継続」と判断した場合の落とし穴は何ですか？', '日足の上昇トレンドがフェイクである可能性が高い', '週足のレンジ上限までの残り距離が近く、上値が限定的であることを見落とす', '4時間足のトリガーが信頼できない', '出来高が常にレンジ相場では機能しない', 2, '下位足だけで判断すると、週足レンジの上限が目前に迫っていることを見落とします。上位足のレンジ上限に到達するまでの距離を考慮せずにエントリーすると、上値が限定的で不利なトレードになります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(43, '環境認識チェックシートの「週次チェック」で確認する5項目に含まれないものはどれですか？', '週足のトレンド方向', '週足のサイクル位置', 'ファンダメンタルズ概況', 'エントリーのトリガー判定', 4, '週次チェックは週足のトレンド方向、サイクル位置、主要水平線、ファンダメンタルズ概況、今週の戦略メモの5項目です。トリガー判定はエントリー前チェック（3分）で行う項目です。', false, 1),
(43, '環境認識チェックシートの「日次チェック」における5番目の項目は何ですか？', 'トレード判断（「本日は〇〇を狙う/やらない」の記述）', '日足のトレンド方向', '4時間足の状態', '本日の経済指標', 1, '日次チェックの5番目は「トレード判断」で、「本日は〇〇を狙う/やらない」を1行で記述します。これによりその日の方向性を事前に明確にします。', false, 2),
(43, 'エントリー前チェック（トリガー出現時）で確認する6項目のうち、リスクリワード比の最低基準はいくつ以上ですか？', '1:1以上', '1:2以上', '1:1.5以上', '1:3以上', 3, 'エントリー前チェックの5番目の項目は「リスクリワード比は最低1:1.5以上あるか」です。この基準を満たさないエントリーは見送ります。', false, 3),
(43, 'エントリー前チェックの6項目で、「1つでもNOがあるなら」取るべき行動はどれですか？', '見送り（エントリーしない）', 'ポジションサイズを50%に縮小してエントリーする', 'NOの項目が重要でなければエントリーしてよい', 'トリガーが強いパターンなら例外としてエントリーする', 1, '6つのチェックすべてに「YES」と答えられるときだけエントリーします。1つでも「NO」がある場合は見送りです。基準を一部緩めることはしません。', false, 4),
(43, '環境認識チェックシートにおいて、エントリー条件の事前設計として記述すべき内容として正しいものはどれですか？', '「今日の損益目標は〇〇円」', '「今週は買い中心でいく」', '「〇〇の水準で〇〇のトリガーが出たらエントリー」', '「ロットを〇〇枚にする」', 3, 'エントリー条件の事前設計では、「〇〇の水準で〇〇のトリガーが出たらエントリー」という具体的な条件を記述します。これにより、トリガー出現時に冷静に判断できます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(44, 'プライスアクションのパターン（ピンバー・包み足など）を単体で判断した場合の勝率は、およそどの程度に留まるか？', '約65%', '約50%', '約30%', '約80%', 2, 'パターンは「結果」であり「原因」ではないため、ピンバーが出たから反転するという判断はコイン投げとほぼ同じ勝率になります。場所と出来高を加えることで65〜70%まで引き上げられます。', false, 1),
(44, '「場所×足×出来高」の三位一体フレームワークにおいて、3要素の優先順位として正しいものはどれか？', '足の形 ＞ 出来高 ＞ 場所', '出来高 ＞ 場所 ＞ 足の形', '場所 ＞ 出来高 ＞ 足の形', '場所 ＞ 足の形 ＞ 出来高', 3, 'どんなにきれいなピンバーでも意味のない場所に出ていれば無視すべきであり、場所が正しくても出来高が伴っていなければ信頼度が半減します。優先順位は場所が最も高く、次いで出来高、最後に足の形です。', false, 2),
(44, '三位一体フレームワークで「WHERE」に分類される判断材料として正しいものはどれか？', 'ヒゲの長さと実体の大きさ', '20日平均との出来高比較', '直前の足との出来高の変化', 'S級ゾーン内とフィボナッチ合流', 4, '「WHERE（場所）」の判断材料は、S級ゾーン内、フィボナッチ合流ポイント、200MA付近、週足の水平線上など、パターンが「意味のある場所」に出ているかを確認するものです。', false, 3),
(44, '三位一体の判断基準を導入した結果として、多くのトレーダーに共通して起こる変化はどれか？', 'エントリー回数が増え、勝率も上がる', 'エントリー回数が減り、勝率も下がる', 'エントリー回数が増え、勝率は変わらない', 'エントリー回数が減り、勝率が上がる', 4, '3要素すべてが揃ったときだけエントリーする基準を守ることで、エントリー回数は減りますが、1回あたりの期待値は大幅に上がります。回数を減らして質を上げるのが三位一体の効果です。', false, 4),
(44, '三位一体フレームワークの「HOW MUCH（出来高）」で確認すべきこととして正しいものはどれか？', '20日平均との比較と直前の足との出来高の変化', '直近1時間のティック数', '前日の終値との乖離率', 'ボリンジャーバンドの幅', 1, '「HOW MUCH」の判断では、パターンに出来高が伴っているかを確認します。具体的には20日平均との比較と、直前の足との出来高の変化を見ることで、その動きに参加者が集まっているかを判断します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(45, 'プライスアクションが「効く」5つの場所として含まれないものはどれか？', 'S級/A級ゾーンの端', 'フィボナッチ50%〜61.8%とゾーンが重なるゴールデンゾーン', '日足または週足の200MA付近', '直近5日間の移動平均線のクロスポイント', 4, 'プライスアクションが効く場所は、ゾーンの端、フィボナッチ合流ポイント、200MA付近、週足・日足の明確な水平線、デュクシ後のゾーン内です。移動平均線のクロスポイントは場所の判定には含まれません。', false, 1),
(45, 'デュクシ（フェイクアウト）後にゾーン内へ戻った場面が高確度とされる理由は何か？', 'トレンドが長く続いた後に反転するから', '出来高が必ず減少するから', 'レンジが必ずブレイクアウトするから', '大口がストップ狩りを完了し、本来の方向に動き出すタイミングだから', 4, '重要ラインを一瞬割った後にゾーン内に戻るデュクシは、大口がストップ狩りで個人の損切りを刈り取った後の動きです。大口がポジションを構築した直後であるため、高確度のエントリーポイントになります。', false, 2),
(45, 'プライスアクションが「効かない」場所に該当するものはどれか？', '週足の明確な水平線上', '日足の200MA付近', 'どのゾーンにも属していないチャートの「途中」', 'フィボナッチ61.8%合流ポイント', 3, 'ゾーンにもフィボナッチ水準にも属していない「何もない場所」に出たパターンは、ただのノイズです。意味のある場所でなければ、どんなにきれいな足の形でも機能しにくくなります。', false, 3),
(45, '上位足が下降トレンドの最中に、4時間足のサポートで買いのピンバーが出た場合の適切な判断は何か？', '上位足より下位足のシグナルを優先して買いエントリーする', '上位足のトレンドに逆行しているため見送る', 'ピンバーの形だけで即座にエントリーする', 'ロットを2倍にしてエントリーする', 2, '上位足のトレンドに逆行する場所で出たパターンは機能しにくいです。たとえ4時間足で反転しても、日足の戻り売りに飲まれるリスクが大きいため、基本的には見送ります。', false, 4),
(45, 'すでに3回到達済みのゾーン内でパターンが出た場合に見送るべき理由は何か？', '複数回到達したゾーンは注文が枯渇しており反転力が不足している可能性が高いから', 'ゾーンに到達するたびにパターンが小さくなるから', '3回目は必ずブレイクアウトするから', '出来高が必ず急増するから', 1, '同じゾーンに複数回到達している場合、その水準にあった注文はすでに消化されています。注文が枯渇しているゾーンでパターンが出ても、反転に必要な売買圧力が不足している可能性が高くなります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(46, '高品質なピンバーの特徴として正しいものはどれか？', 'ヒゲが実体の3倍以上で、反対側のヒゲがほぼない', '実体と同じ長さのヒゲがあり、反対側にもヒゲがある', '実体が足の中央付近に位置し、終値と始値がほぼ同じ', '前の足のレンジ内に完全に収まっている', 1, '高品質なピンバーは、ヒゲが実体の3倍以上あり、反対側のヒゲがほぼないか極めて短いことが条件です。また、前の足の安値（買いの場合）を一旦割ってから戻していると信頼度がさらに上がります。', false, 1),
(46, '高品質な包み足の特徴として正しいものはどれか？', '前の足とほぼ同じ大きさの実体で、ヒゲが長い', '前の足の2倍以上の実体を持ち、前の足が小さいコマ足か十字線である', '1時間足以下で確定し、前の足も大きな実体である', '前の足のレンジ内に収まる小さな実体である', 2, '高品質な包み足は、前の足の2倍以上の実体を持ち、前の足が小さなコマ足や十字線であることが理想です。「迷いの後の決着」という文脈があり、日足または4時間足で確定したものが信頼性が高いです。', false, 2),
(46, 'はらみ足のブレイク方向を判断するために使用すべき情報は何か？', 'はらみ足自身の実体の色（陽線か陰線か）', '上位足のトレンド方向と出来高', 'はらみ足の連続する本数だけ', 'はらみ足のヒゲの長さ', 2, 'はらみ足自体は方向を教えてくれないパターンです。ブレイク方向は上位足のトレンドと出来高で判断します。上位足が下降トレンドなら下方向のブレイクを待つというように、文脈から方向を予測します。', false, 3),
(46, '高品質なはらみ足の特徴として、「エネルギー蓄積」を示すのはどれか？', '大きな実体の母足が1本だけ出現する', '2〜3本連続してはらみ足が出現する', '小さな実体の母足が1本だけ出現する', '母足の後にすぐ大きな実体の足が出現する', 2, 'はらみ足が2〜3本連続して出現することは、売りと買いが激しくぶつかり合いながらエネルギーが蓄積されている状態を示します。1本だけでは一時的な停滞の可能性がありますが、連続するほど信頼度が上がります。', false, 4),
(46, 'ピンバーの「質」を判定する際、前の足との関係で高品質とされる条件は何か？', '前の足のレンジ内に完全に収まっていること', '前の足の安値（買いの場合）を一旦割ってから戻していること', '前の足と同じ方向に実体が伸びていること', '前の足より実体が大きいこと', 2, '前の足の安値（買いの場合）を一旦割ってから戻しているピンバーは、その水準で売り圧力を吸収した証拠です。レンジ内に収まっているだけのピンバーは、売り圧力をテストしていないため信頼度が下がります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(47, '強い反転足が出たのに出来高が減少している場合、最も適切な対応はどれか？', '見た目が強いので直ちにエントリーする', '出来高が減るのは反転の前兆なので逆方向にエントリーする', '出来高は関係ないので無視してエントリーする', 'エントリーは保留し、次の足を確認してから判断する', 4, '強い反転足に出来高が伴っていない場合、見た目は強くても参加者が少ない「見せかけの反転」の可能性があります。次の足で出来高を伴った続伸・続落を確認してから判断することで、フェイクを回避できます。', false, 1),
(47, 'ゾーン到達時に出来高が急増（20日平均の2倍以上）した場合、何を示唆しているか？', '大口がそのゾーンで注文を執行しており、反転の可能性が高い', '個人投資家がパニック売りしている', 'レンジが継続する可能性が高い', 'トレンドが加速してゾーンを突破する', 1, 'ゾーン到達時の出来高急増は、大口機関投資家がその水準で大量の注文を執行した証拠です。彼らの注文が価格を反転させる原動力になるため、反転の可能性が高まります。', false, 2),
(47, 'ブレイク時に出来高が急増しているかどうかを確認する重要性は何か？', '出来高が多いほど利益が大きくなるから', '出来高を伴わないブレイクはフェイクブレイクの可能性が高いから', '出来高が多いほど損切り幅が小さくなるから', '出来高はスプレッドに影響するから', 2, '本物のブレイクは出来高の急増を伴います。出来高が伴わないブレイクはフェイクブレイクの可能性が高く、すぐに元のレンジ内に戻ることが多いため、出来高で本物か見せかけかを見極めることが重要です。', false, 3),
(47, 'トレンド中に出来高が急増した直後に反転足が出た場合、何が起きている可能性が高いか？', 'トレンドの再加速', '新たなレンジの形成', '大口の利確または新規ポジション構築によるクライマックス（転換点）', '個人投資家の参入によるトレンド継続', 3, 'トレンド中の出来高急増＋反転足は、クライマックス（転換点）の可能性を示唆しています。大口が利確のためにポジションを解消しているか、逆方向に新規ポジションを構築しているサインです。', false, 4),
(47, '弱い足（コマ足）に出来高が増加している場合、どのような判断をすべきか？', '方向感がないため直ちにトレードしない', '出来高が増えているのでエントリーする', 'コマ足は無意味なので完全に無視する', '必ず上方向にブレイクする', 1, '弱い足に出来高が増加している場合は、売りと買いが激しくぶつかり合っている状態です。次の動きは大きい可能性がありますが、方向がまだ確定していないため、上位足のトレンドからブレイク方向を予測して待機します。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(48, 'S級ゾーン内でフィボ61.8%と合流し、長い下ヒゲのピンバー（実体の4倍のヒゲ）が出現し、出来高が20日平均の2.3倍だった場合の適切な判断は何か？', '三位一体のうち2つ揃っているので、ロットを半分にしてエントリーする', '出来高が多すぎるため見送る', 'さらに1週間待ってから判断する', '三位一体すべてA評価なので、迷わずエントリーする', 4, '場所（S級ゾーン＋フィボ合流）、足（実体の4倍のヒゲ・反対側ヒゲなし）、出来高（20日平均の2.3倍）の3要素すべてが最高評価の場合、三位一体の全条件が充足されており高確度のエントリーポイントです。', false, 1),
(48, '4時間足のA級ZBで教科書通りのピンバーが出たが、出来高が平均以下だった場合の適切な対応はどれか？', '場所と足は合格だが出来高が欠けているため、次の足で出来高を伴った続伸を確認してからエントリーする', 'ピンバーがきれいなので通常通りエントリーする', '出来高は無視してピンバーだけで判断する', '出来高が低いので逆方向にエントリーする', 1, '三位一体のうち場所と足は合格でも、出来高が欠けていると「見せかけの反転」のリスクがあります。次の足で出来高を伴った続伸を確認することで、フェイクを回避しつつエントリーの精度を上げられます。', false, 2),
(48, 'どのゾーンにも属していない「チャートの途中」にきれいなピンバーが出た場合の判断として正しいものはどれか？', 'ピンバーの形が完璧ならエントリーしてよい', '出来高が平均以上ならエントリーしてよい', '場所が不合格なので見送る', 'より下位の時間足で確認してからエントリーする', 3, '「何もない場所のきれいなパターン」は最も多いノイズです。三位一体の優先順位で最も高い「場所」が不合格の場合、足の形や出来高にかかわらず見送るのが正解です。', false, 3),
(48, 'デュクシ発生後の反転足で、ヒゲ突破時は出来高が低く、戻り時に出来高が急増していた場合、何を示しているか？', '本物のブレイクが起きた', '個人投資家が追随している', '大口のストップ狩り後の反転であり、高確度のエントリーポイント', 'レンジが継続する', 3, '出来高の「低→高」の変化は、突破時には大口以外の参加が少なく（フェイク）、戻り時に大口が本気で反転方向に注文を入れた証拠です。デュクシの裏付けとして信頼性の高いパターンです。', false, 4),
(48, '日足のZS上限付近で大きな陰線の後にはらみ足が3本連続し、出来高が徐々に減少している場合、どのような戦略が適切か？', '直ちに買いエントリーする', 'はらみ足の方向性が不明なため見送る', '上位足が下降トレンドなら下方向のブレイクを待ち、ブレイク足の出来高急増でエントリーする', 'レンジ取引として上限と下限で往復トレードする', 3, 'はらみ足3本連続＋出来高減少はエネルギー蓄積中のサインです。はらみ足自体は方向を示しませんが、上位足が下降トレンドであれば下方向のブレイクが想定され、ブレイク時に出来高が急増したらエントリーします。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(49, '三位一体チェックシートで「8つ全てYES」の場合の適切なアクションはどれか？', '通常のポジションサイズでエントリーする', 'ロットを2倍にしてエントリーする', 'さらに2時間待ってから判断する', '見送って次のチャンスを待つ', 1, '8つ全てYESは最高確度のシグナルです。三位一体の全条件が揃っているため、通常のポジションサイズで積極的にエントリーします。ロットを増やすのは連勝バイアスのサインなので避けます。', false, 1),
(49, '三位一体チェックシートで「5つ以下YES」だった場合の適切な判断は何か？', 'ロットを50%に縮小してエントリーする', '確度不足として見送り、次のチャンスを待つ', 'YESの数が半分以上あるのでエントリーする', 'YESの項目だけを条件にエントリーする', 2, '5つ以下YESは確度不足と判定します。無理にエントリーするより見送って次の高確度のチャンスを待つ方が、長期的な損益を改善します。6〜7つYESなら70%サイズでエントリー、5つ以下なら見送りが基準です。', false, 2),
(49, '三位一体チェックシートの項目に「上位足のトレンド方向と一致しているか」が含まれる理由は何か？', '上位足の分析だけで勝てるから', '上位足のトレンドは常に正しいから', '下位足のパターンは意味がないから', '上位足のトレンドに逆らうパターンは機能しにくいから', 4, '日足が下降トレンド中に4時間足のサポートで買いのピンバーが出ても、上位足の戻り売りに飲まれるリスクが大きいです。上位足と同方向のパターンだけを拾うことで、順張りの確度を高められます。', false, 3),
(49, '三位一体チェックシートを使い始めた結果として報告されている変化はどれか？', '月間トレード回数が増加し、勝率も上昇した', '月間トレード回数が減少し、勝率が大幅に低下した', '月間トレード回数が減少したが、勝率と月間損益が改善した', 'トレード回数と勝率は変わらず、損益だけが改善した', 3, 'チェックシートの基準を満たす場面だけに絞ることで、月間のトレード回数は大幅に減少しますが、エントリーの質が上がるため勝率と月間損益が改善します。「たくさんトレードすること」と「たくさん稼ぐこと」は別物です。', false, 4),
(49, '三位一体チェックシートにおいて「重要経済指標の発表30分前ではないか？」という項目が含まれている理由は何か？', '指標結果で全てがリセットされる可能性があり、パターンの信頼度が極端に下がるから', '指標発表前はスプレッドが広がりエントリーに不利だから', '指標発表前は必ずトレンドが発生するから', '指標発表前は出来高が必ず減少するから', 1, '経済指標の発表結果によって相場環境が一変する可能性があります。どんなに三位一体が揃っていても、指標発表直前は結果次第でパターンが無効になるリスクが高いため、エントリーを避けるべきです。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(50, '大口投資家がダマシを仕掛ける構造的理由として最も適切なものはどれか？', '個人投資家の注目を集めて取引量を増やすため', '大きな注文を一度に執行すると価格が動いてしまうため、損切り注文を「燃料」として流動性を確保するため', 'テクニカル指標を意図的に歪めてチャートパターンを崩すため', '中央銀行の政策判断に影響を与えるため', 2, '大口は何十億円もの注文を一度に執行すると自分の注文で価格が動いてしまうため、個人投資家の損切り注文を「天然の流動性プール」として利用します。', false, 1),
(50, 'ダマシのパターンが過去も現在も未来も繰り返される理由として正しい組み合わせはどれか？', '大口の構造的制約、個人投資家の心理的癖、教科書通りのトレードを逆手に取れること', 'アルゴリズム取引の普及、高頻度取引の増加、投資信託の拡大', 'テクニカル分析の進化、SNSの普及、グローバル化の進展', '中央銀行の政策変更、通貨制度の変更、取引所の規制変更', 1, '大口の大きな注文は分散執行の必要があり、個人は直近の高値・安値のすぐ外側に損切りを置く傾向があり、「サポート割れで売り」等の定石を逆手に取れるため、この構造は永遠に変わりません。', false, 2),
(50, 'ストップ狩り（Stop Hunt）の際に大口が狙う場所として、最も標準的な水準はどれか？', '移動平均線の交差ポイント', 'ボリンジャーバンドの中央線', '直近の明確な高値または安値のすぐ外側', 'フィボナッチ23.6%リトレースメント', 3, '直近の明確な高値・安値のすぐ外側には多くの投資家の損切り注文が集中しており、大口にとって最も「狩りやすい」流動性プールになります。', false, 3),
(50, 'ベアトラップ（Bear Trap）の説明として正しいものはどれか？', 'サポートを一瞬割り込んで売りを誘ってから急反転し、その売り注文で買い集める動き', '上位足のトレンドに逆行して下落を加速させる動き', '出来高を伴わないまま支持線を徐々に下抜けていく動き', 'レジスタンスを一瞬超えてから急反落し、買いを誘ってから売り抜ける動き', 1, 'ベアトラップはサポート割れで個人に「下落開始」と思わせて売らせ、その売り注文を燃料に買いポジションを構築する大口の仕掛けです。名前に「ベア（弱気）」とありますが、実際は大口が買いを入れる局面です。', false, 4),
(50, 'ストップ狩りか本物のブレイクかを見極める際、最も信頼度が高いシグナルの組み合わせはどれか？', 'ボリンジャーバンドの拡大＋RSIの乖離', '実体での突破＋直近3本のローソク足が同方向', 'ヒゲでの突破＋突破時の出来高が少ない', '出来高の急増＋上位足のトレンドとの一致', 3, 'ヒゲだけで高値・安値を超え、実体は元のレンジ内にあり、突破時の出来高が少ない場合、ストップ狩りの可能性が高いです。本物のブレイクは出来高の急増（20日平均の1.5倍以上）を伴います。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(51, 'リアルタイムでストップ狩りを検知する5つの特徴のうち、「即座の反転」が意味するものはどれか？', '突破後、1〜3本の足以内に元の方向に戻る', '突破後、新しいレンジを形成してから戻る', '突破後、損切りラインに向かって一気に進む', '突破後、10本以上のローソク足をかけてゆっくり戻る', 1, 'ストップ狩りでは、損切りを刈り取った直後に本来の方向に戻るため、1〜3本の足以内に反転が起きます。本物のブレイクは突破後も方向を維持する点が決定的に異なります。', false, 1),
(51, 'ストップ狩りが起きやすい時間帯として挙げられるのは、日本時間でどの時間帯か？', '12:00〜13:00（昼休み）', '3:00〜5:00（欧米市場クローズ直後）', '16:00前後と22:00前後（ロンドンオープン・NYオープン）', '6:00〜9:00（東京オープン直後）', 3, 'ロンドンオープン（16:00 JST前後）とNYオープン（22:00 JST前後）は流動性が急激に変化する時間帯で、大口のストップ狩りが起きやすくなります。', false, 2),
(51, 'ストップ狩りの判定基準で「5つのうち3つ以上該当＝ストップ狩りの可能性大」とされるが、これはなぜ全て該当を求めないのか？', '実戦では全ての条件が同時に揃うことは稀であり、3つ以上で十分に高い確度が得られるため', '条件が多すぎると判断が遅くなりエントリーチャンスを逃すため', '大口は常に3つの条件だけを満たすように仕掛けるため', '5つ全て該当することは統計的にあり得ないため', 1, 'リアルタイムの相場で5つの条件が全て同時に揃うことは稀ですが、3つ以上揃えば「ストップ狩りの可能性が高い」と実用的に判断できます。特にヒゲ突破＋出来高不足の組み合わせが信頼度を高めます。', false, 3),
(51, '毎朝の環境認識でストップ狩りが起きそうな場所を事前にマークする意味として最も適切なものはどれか？', 'マークした場所で必ずストップ狩りが起きることを確認するため', '大口の注文の正確な規模を推定するため', 'その場所でのみエントリーを許可するため', '構えていれば狩りに引っかかるのではなく、狩りの後の反転を狙えるため', 4, '事前に「狩り場」をマークしておけば、価格が接近したときに「狩りが来るかも」と構えられます。準備があることで、狩りの犠牲になるのではなく、狩りの後の反転を利益に変えられます。', false, 4),
(51, 'ストップ狩りが起きやすい場所として「キリ番のすぐ外側」が挙げられる理由は何か？', 'キリ番は中央銀行が介入する水準だから', 'キリ番では自動売買システムが停止するため', 'キリ番は過去の高値・安値と必ず一致するため', '多くのトレーダーがキリ番の数pips外側に損切りを置く傾向があるため', 4, '100円、145円などのキリ番は多くのトレーダーが意識する水準であり、その数pips外側に損切りを集める傾向があります。大口はその集まった損切り注文を狙ってヒゲで一瞬だけ突き抜けます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(52, 'デュクシ・エントリー（Dukcy Entry）とは具体的にどのような手法か？', '重要な水準を実体で割り込んだ後に、新しい安値を更新してからエントリーする手法', '重要な水準をヒゲで一瞬割った後、反転の足が確定した瞬間にエントリーする手法', 'レンジの中央付近で価格が反転した瞬間にエントリーする手法', '出来高が急増した瞬間に順張りでエントリーする手法', 2, 'デュクシ・エントリーは、大口がストップ狩りを完了し、本来の方向に動き出すタイミングに乗る手法です。重要水準をヒゲで一瞬割った後の反転足の確定を待つのがポイントです。', false, 1),
(52, 'デュクシ・エントリーの5ステップで、反転の足が確定する前にエントリーしてはならない理由は何か？', 'ヒゲで戻しただけでは本物の反転かフェイクか判別できず、二重ダマシのリスクがあるから', '約定価格がスリップする可能性が高いから', 'スプレッドが広がってコストが高くなるから', '大口の注文がまだ完了していない可能性があるから', 1, 'ヒゲで戻しただけでは一時的な反動なのか本物の反転なか判断できません。反転方向のローソク足（ピンバーや包み足）が「確定」して初めて、反転の意思が確認できます。', false, 2),
(52, 'デュクシ・エントリーの最大のメリットとして正しいものはどれか？', '常に大きなポジションサイズでエントリーできる', '損切り幅が非常に小さく抑えられるため、RR比が有利になる', 'エントリー後の損切りがほぼ不要になる', 'どの時間軸でも同じ精度で機能する', 2, 'ストップ狩りのヒゲの先端が「これ以上は行かなかった」ことを証明しているため、その少し外側に損切りを置けばよく、損切り幅が非常に小さくなります。結果としてRR比が2:1、3:1と有利になりやすいです。', false, 3),
(52, 'デュクシ・エントリーで損切りを「ストップ狩りのヒゲの先端の5〜10pips外側」に設定する理由は何か？', '5〜10pipsが一般的なスプレッドの幅だから', 'ヒゲの先端が「大口が到達させた最大値」であり、そこを超えたら本物のブレイクの可能性が高いから', '大口は常に5〜10pips刻みで注文を出すから', '過去の統計で5〜10pipsが最も損切りされにくい幅だから', 2, 'ヒゲの先端は大口が到達させた最大値を示しており、そこを超えた場合はストップ狩りではなく本物のブレイクである可能性が高くなります。そのため、ヒゲ先端の少し外側が合理的な損切り位置です。', false, 4),
(52, 'デュクシ・エントリーの手順で、価格が「狩り場」に接近したことを知るために設定するものは何か？', 'マークした水準での指値注文', '出来高の監視アラート', 'マークした水準の5〜10pips手前に設定したアラート', '移動平均線のクロスアラート', 3, '事前にマークした水準の5〜10pips手前にアラートを設定しておくことで、価格が狩り場に接近したことを逃さず検知でき、その後の突破→反転の動きを落ち着いて確認できます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(53, 'ベアトラップを逆利用して買いエントリーする際の条件として正しいものはどれか？', '割り込み時の出来高が多く、戻り時の出来高が少ない', '上位足のトレンドが下降方向で、逆張りで入る', 'サポートをヒゲで割り込んだ後、終値でZB内に戻り、戻り時の出来高が割り込み時より大きい', 'サポートを実体で明確に下抜けてから反転を待つ', 3, 'ベアトラップ逆利用の条件は、ヒゲで割り込み後に終値でZB内に戻っていること、割り込み時の出来高が少なく（フェイクの証拠）、戻り時の出来高が多い（反転の本気度）ことなどが揃うことで高確度になります。', false, 1),
(53, 'ブルトラップ（Bull Trap）において、大口が仕掛ける狙いは何か？', 'レジスタンスを超えて個人に「ブレイクした」と思わせて買わせ、その買い注文で売り抜けること', 'サポートを割って売りを誘い、その売り注文で買い集めること', '安値を更新してパニック売りを誘発すること', '出来高を急増させてトレンドを加速させること', 1, 'ブルトラップはレジスタンスを一瞬超えて「ブレイク」と錯覚させ、個人に買わせた後に急反落します。大口はその買い注文を燃料に売りポジションを構築・利確します。', false, 2),
(53, '二重ダマシ（ストップ狩り→反転→もう一度割り込み）に対する対策として正しいものはどれか？', '1回目の反転時に大きなロットで一気に利益を取る', '2回目の割り込み後にエントリーすればより確実', '損切りは1回目のヒゲの先端の外側に置き、1回のリスクを資金の1%以内に抑える', '二重ダマシは予測可能なので事前に回避できる', 3, '二重ダマシは完全に避けることはできませんが、損切りを1回目のヒゲ先端の外側に置き、1回のリスクを資金の1%以内に抑えることで、損失を管理可能な範囲に収められます。', false, 3),
(53, 'トラップの逆利用エントリーで「5つの条件のうち4つ以上該当」を基準とする理由として最も適切なものはどれか？', '3つ以下では大口の仕掛けではないことが確定するから', '条件を満たす数が多いほど、その動きが大口の仕掛けである確度が高まり、エントリーの根拠が強くなるから', '条件が多いほどエントリー回数を増やせるから', '全ての条件が揃うまで待つとチャンスを逃すから', 2, 'ヒゲでの突破、出来高の不一致、即座の反転、上位足との一致などの条件が多く揃うほど、ストップ狩りである確度が高まります。4つ以上で高確度のエントリーとして扱います。', false, 4),
(53, 'ベアトラップ逆利用とブルトラップ逆利用の共通点として正しいものはどれか？', 'どちらも出来高の「低→高」の変化と上位足のトレンドとの一致を確認する点が共通している', 'どちらも逆張りで入る点が同じである', 'どちらも日足レベルでしか機能しない', 'どちらも分割利確が必須である', 1, '両トラップとも、フェイク時の出来高が少なく反転時の出来高が大きいこと、上位足のトレンド方向と反転方向が一致していることが条件に入っており、この「出来高の質的変化」と「上位足との整合」が共通の判断基準です。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(54, 'ロンドンオープン直後にレンジ下限を一瞬割り込み、直後に急反転して上昇したケースの分析として最も適切なものはどれか？', 'ロンドンの traders が意図的にレンジを拡大しようとした', '東京時間のレンジ下限にアジア勢の損切りが集中しており、ロンドン勢がそれを刈ってから本来の方向に動いた', '経済指標の発表がたまたま重なっただけの偶然', 'アジア市場の流動性が低すぎてスリップしただけ', 2, '東京時間に形成されたレンジの下限にはアジア勢の損切り注文が集中しています。ロンドンオープン時に大口がそれを刈り取ってから上昇に転じるのは、典型的なロンドンフェイクアウトのパターンです。', false, 1),
(54, '3週間のレンジ上限を日足のヒゲで一瞬超えた翌日に大陰線で急落したケースで、大口が狙ったものは何か？', 'レンジ中央での流動性確保', 'レンジ上限の外側に蓄積した「ブレイクアウトの買い注文」と「ショートの損切り注文」の一掃', '下位足のテクニカルパターンの破壊', '中央銀行の政策への影響', 2, '3週間のレンジが続くと、上限のすぐ外側にブレイクアウトを狙う買い注文と、ショートの損切り注文が大量に蓄積します。大口はこれを一瞬のヒゲで一掃し、その買い注文を燃料に売りに転じます。', false, 2),
(54, 'FOMC発表直後に上下に大きく振れた後、発表前のレンジ内に戻ったケースの正しい対応はどれか？', '初動の方向にすぐ乗る', '反対方向にすぐエントリーする', '発表後1〜2時間は一切手を出さず、値動きが落ち着いてから方向を確認する', '出来高が多い方の方向に乗る', 3, 'FOMC直後は流動性が一時的に薄くなり、大口のストップ狩りが起きやすく、上にも下にもヒゲを出してから方向が決まるパターンが多いため、1〜2時間は手を出さずに落ち着きを待つのが正解です。', false, 3),
(54, 'デュクシ・エントリーが10回中7回成功し3回損切りになっても、トータルでプラスになる条件は何か？', '勝率が70%以上あれば RR比に関係なくプラスになる', 'RR比が1:2以上確保できていれば、損失額より利益額が上回るため', '1回の損失額を利益額の半分以下に抑えること', '全ての勝ちトレードで利確目標を2倍に引き上げること', 2, 'RR比1:2の場合、1回の勝ちでリスクの2倍の利益を得られます。7回勝てば14単位の利益、3回負けても3単位の損失で、トータルで+11単位になります。損切り幅が小さいデュクシ・エントリーならRR比1:2以上を確保しやすいです。', false, 4),
(54, '二重ダマシで損切りになった後、「2回目にもう一度エントリーしたくなる」衝動を抑えるために有効な方法はどれか？', '直ちに相反する方向にエントリーする', '5秒ルールを使ってリベンジを防止する', 'ロットを倍にして損失を取り返す', 'チャートを閉じて翌週まで見ない', 2, '二重ダマシで損切り後の再エントリー衝動は典型的なリベンジ心理です。5秒ルールを使って自分の感情に気づき、1回の損失が資金の1%以内に抑えられていればダメージは限定的だと認識することで冷静さを取り戻せます。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(55, '朝のルーティンで「ストップ狩りポイントのマーキング」を行う際、マークすべき場所として含まれないものはどれか？', '直近のスイングハイ/ローのすぐ外側', 'レンジの上限/下限のすぐ外側', 'キリ番のすぐ外側', '移動平均線の現在の値位置', 4, 'ストップ狩りが起きやすい場所は、直近のスイングハイ/ロー、レンジの上限/下限、キリ番、フィボナッチ水準のすぐ外側など、損切り注文が集中しやすい場所です。移動平均線の現在値はストップ狩りのターゲットではありません。', false, 1),
(55, 'リアルタイムのストップ狩り検知チェックで「5つ中2つ以下YES」の場合の判定として正しいものはどれか？', 'ロットを50%に縮小してエントリー検討', '高確度のデュクシ・エントリーとして実行する', '損切り幅を広げて様子を見る', 'ストップ狩りではなく本物のブレイクの可能性があるため見送る', 4, '5つのチェック項目で2つ以下しか該当しない場合、その動きはストップ狩りではなく本物のブレイクである可能性が高いです。この場合はデュクシ・エントリーではなく見送りが正しい判断です。', false, 2),
(55, 'ストップ狩り検知時に確認する「ヒゲだけで突破し、終値は元のレンジ内か」というチェック項目が意味するものはどれか？', '実体での突破は本物のブレイクである可能性が高い', 'ヒゲでの突破はフェイクであり、終値が戻っているなら実体としての支持・抵抗ラインは維持されている', 'ヒゲと実体の両方で突破していれば信頼度が高まる', '終値の位置は関係なく、ヒゲの長さだけで判断すべき', 2, '終値が元のレンジ内にあるということは、実体としてのラインは維持されており、ヒゲだけが一瞬突き抜けたに過ぎません。これは損切りを刈るためのフェイク突破の典型的な特徴です。', false, 3),
(55, '大口の仕掛けに対する認識を「恐れる対象」から「利益の源泉」に変えるために最も重要な考え方はどれか？', '大口の仕掛けを逆利用するのではなく、大口と同じ方向に乗ること', '全てのダマシを正確に見抜こうとすること', '常に大口より早くエントリーすること', '大口が使用するアルゴリズムを解読すること', 1, '大口のダマシは「大口に勝つ」のではなく「大口と同じ方向に乗る」ためのシグナルです。ストップ狩りが起きた直後は大口がポジションを構築したばかりのタイミングであり、その方向に付くことが利益に繋がります。', false, 4),
(55, '朝のルーティンで「どちら方向の狩りが起きそうか」を予測する際に最も重視すべき情報は何か？', 'SNSでのセンチメントの強さ', '出来高の直近3日間の推移', '前日のエントリーの損益結果', '上位足のトレンド方向と逆の方向に狩りが起きやすい傾向', 4, 'ストップ狩りは上位足のトレンド方向と逆の方向に起きやすい傾向があります。上昇トレンド中なら下方向への狩り（ベアトラップ）が起きやすく、その後に上昇する流れに乗れるため、上位足の方向性が予測の重要な手がかりになります。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(56, 'トレードにおいて、単一のシナリオだけで相場に臨むことの最も大きな欠点は何か。', '相場がシナリオ通りに動かなかった場合、感情的な判断に陥りやすくなる', 'エントリーのタイミングが遅くなり、利益を取り逃がしやすくなる', '分析に使える時間が短くなり、環境認識が不正確になる', 'ポジションサイズの計算が複雑になり、リスク管理が崩れやすくなる', 1, '単一シナリオは想定通りの展開でのみ機能し、外れた場合は焦りから感情的な判断を引き起こす。複数シナリオを用意しておけば、「想定内の別ケース」として冷静に対応できる。', false, 1),
(56, 'プロトレーダーが常に複数のシナリオを用意する理由として最も適切なものはどれか。', 'エントリー回数を増やして利益の機会を最大化するため', 'テクニカル指標の信頼性を補うため', '一つのシナリオの損切り幅を小さくするため', '相場には常に「AかBか」の分岐点が存在するため', 4, '相場には常に複数の展開が可能であり、事前にどちらになるかは分からない。だからこそ両方の分岐に対する「if-then」を準備するのが複数シナリオの本質である。', false, 2),
(56, 'シナリオの中に「はず」という言葉が入ったとき、それは何を意味するか。', '分析ではなく願望に変わっているサイン', '過去の類似パターンからの統計的推論', '環境認識のレイヤーが十分に統合されている状態', '分析が確率的に十分に裏付けられている状態', 1, 'シナリオに「はず」が入った瞬間、それは客観的分析から主観的な願望へと変質している。メタ認知で「分析しているのか、願望を持っているのか」を常に確認する必要がある。', false, 3),
(56, '複数シナリオ（メイン＋サブ）を用意した場合と単一シナリオの場合を比較したとき、準備時間はどう変わるか。', '約30分追加で必要になる', '約5分程度追加で必要になる', '準備時間は変わらない', '環境認識が不要になる分、むしろ短くなる', 2, 'メイン＋サブの設計は単一シナリオに比べて+5分程度の追加で済むが、その5分が日中の迷いを排除し、感情的な判断を防ぐ効果は非常に大きい。', false, 4),
(56, '「相場はあなたのシナリオ通りに動く義務がない」という認識がもたらす最も重要な実践的意味は何か。', 'どのような値動きが来ても対応できる準備をしておくべきということ', 'シナリオ構築そのものに意味がないということ', 'エントリー後に損切りラインを広げてもよいということ', '直感や経験に基づく判断の方がシナリオより信頼できるということ', 1, '相場は予言通りに動かない前提に立つからこそ、すべての分岐に対する準備（メイン＋サブ＋無効化条件）が意味を持つ。シナリオは「予言」ではなく「準備」である。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(57, 'メインシナリオとはどのようなものか。', '過去に最も利益を出したトレードパターンに基づくシナリオ', 'テクニカル分析のみに基づき、ファンダメンタルズを排除したシナリオ', '現在の環境認識から「最も確度が高い」と判断したシナリオ', 'リスクリワード比が最も有利になる方向のシナリオ', 3, 'メインシナリオは、上位足のトレンド方向と一致し、ゾーンの合流もあり、ファンダメンタルズとも整合している「最も確度が高い」シナリオとして定義される。', false, 1),
(57, 'サブシナリオを設計する上で最も重要な原則は何か。', 'メインシナリオと同じゾーンで逆方向のエントリーを狙うこと', 'メインシナリオが崩れてから慌てて考えること', 'メインシナリオと同時に設計しておくこと', '常に売り方向に設定しておくこと', 3, 'サブシナリオは「メインが崩れてから考える」のではなく「メインと同時に設計しておく」ことが原則。事前に設計しておかないと、リアルタイムの感情が判断を歪める。', false, 2),
(57, 'メイン＋サブの設計テンプレートにおいて、「無効化条件」とは何を定義するものか。', 'エントリー後に損切りラインを変更する条件', 'ポジションサイズを半分にする条件', '利確目標を早める条件', 'メインもサブも成立しない状況を定義し、完全にノートレードにする条件', 4, '無効化条件は「メインもサブも成立しない状況」を事前に定義するもの。この条件に達したら全シナリオを破棄し、その通貨ペアから離れることが求められる。', false, 3),
(57, '日足上昇トレンド中に4時間足のZBに向けて調整が進んでいる場面で、メインシナリオが「買い」のとき、サブシナリオとして適切な設計はどれか。', '4H足の終値でZBの下限を下抜けた場合、より深い位置の新しいZBで改めて買いを検討する', '日足のトレンドが上昇なのでサブシナリオは不要', 'レンジ上限まで戻ったら利確する', '同じZBで売りエントリーを狙う', 1, 'サブシナリオは「メインのZBが機能しなかった場合」の代替を定義する。より深い位置に別のZBを設定し、そこでトリガーを待つか、ノートレードにするのが適切な設計。', false, 4),
(57, 'サブシナリオの発動条件として、最も客観的で感情が介入しにくい書き方はどれか。', '「チャートの雰囲気が変わったら発動」', '「下落の勢いが強くなったと感じたら発動」', '「出来高がなんとなく増えたら発動」', '「〇〇の水準を4H足の終値で割り込んだ場合に発動」', 4, '切り替え条件は「〇〇の水準を〇〇足の終値で割ったら」といった客観的・定量的な表現で定義する必要がある。主観的な表現は感情による判断の余地を残してしまう。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(58, 'シナリオの切り替え条件を「リアルタイムで判断」するときに最も起こりやすい問題は何か。', 'エントリーのタイミングが遅れること', 'スプレッドが広がってエントリーしにくくなること', '感情が介入し、「もう少し待てばメインが復活するかも」と損失を拡大すること', '出来高が減少して判断材料が不足すること', 3, 'リアルタイムでの判断には必ず感情が介入し、「かも」という希望が損失を拡大させる。だからこそ切り替え条件は事前に定義し、機械的に実行する必要がある。', false, 1),
(58, '「5つの切り替えトリガー」のうち、VIXが30を超えて急上昇した場合の対応として正しいものはどれか。', '通常通りメインシナリオを実行する', 'サブシナリオに切り替えて逆方向にエントリーする', '全シナリオを一時停止し、VIXが落ち着くまで待機する', 'ロットを半分にしてエントリーする', 3, 'VIXが30超で急上昇した場合、市場環境が急変しており通常のテクニカルが効きにくくなる。全シナリオを一時停止し、落ち着くまで待機するのが正しい対応。', false, 2),
(58, '切り替えトリガーのうち、「価格がZBを終値で下抜けた」場合のアクションとして正しいものはどれか。', '損切りラインを広げてポジションを維持する', '即座に逆方向にエントリーする', 'エントリー条件を見直してロットを増やす', 'サブシナリオのZB（より深い位置）に移行する', 4, 'メインのZBが終値で下抜けた＝ゾーンが機能しなかったことを意味する。ここではメインを破棄し、サブシナリオで設定したより深い位置のZBに移行する。', false, 3),
(58, '「計画的な切り替え」と「リベンジトレード」の最も本質的な違いは何か。', 'エントリーする方向が同じか逆かの違い', '事前に定義した条件に基づいているか、損切り後の感情に基づいているかの違い', 'ポジションサイズの大小の違い', '使用する時間足の違い', 2, '切り替えは事前に定義した条件に基づく計画的な方向転換であり、リベンジは損切り後の感情的な方向転換。見た目は似ていても本質は全く異なる。書き出していない条件で方向を変えたらリベンジの可能性が高い。', false, 4),
(58, 'ゾーンに到達したがトリガーが出ないまま価格が反対方向に動いた場合、適切な対応はどれか。', 'ゾーンに到達した事実だけでエントリーする', '即座に逆方向にエントリーする', 'トリガーなしの見送りに切り替え、次のゾーンまで待機する', '損切りラインを広げて待機を続ける', 3, 'ゾーン到達だけでトリガーが出ない場合は「待つ→見送り」に切り替える。トリガーなしにエントリーすれば確度の低いトレードになる。次の機会を待つのが正しい判断。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(59, 'If-Then-Elseの条件分岐構造をトレードに応用する最大のメリットは何か。', '「想定外」がなくなり、どんな値動きにも冷静に対応できること', 'エントリー回数を最大化できること', 'テクニカル指標の種類を減らせること', '利確目標を自動的に計算できること', 1, 'If-Then-Elseで全ての分岐を事前に定義しておけば、どんな値動きが来ても「これはIf-Aのケースだな」「これはElseのケースだな」と冷静に対応でき、「想定外」がなくなる。', false, 1),
(59, '3段階のIf-Then-Elseにおいて、「If D：サブシナリオのZBも下抜けた」に該当した場合の正しいアクションはどれか。', '新しいゾーンを探して第3のシナリオを作る', 'ロットを縮小してもう一度エントリーを試みる', '損切りラインを大幅に広げて待機する', '全シナリオを無効化し、その通貨ペアは当日トレードしない', 4, 'メインもサブも機能しなかった場合、全シナリオを無効化する。無理に新しいシナリオを作ろうとすると焦りからバイアスのかかった分析になる。その日は休むのが最も賢い判断。', false, 2),
(59, '「Else：上記のいずれにも該当しない状態」に該当した場合、どのようなアクションが適切か。', 'チャートを閉じてトレードを完全にやめる', 'アラートを設定して待つ——まだ何も起きていない状態', '直感でエントリーする', 'ロットを増やしてエントリーの機会を逃さない', 2, 'どのIf条件にも該当しない＝まだ何も起きていない状態。アラートを設定して待機するのが適切。分岐図のElseは「待つ」という立派な判断を明示的に定義している。', false, 3),
(59, 'If-Then-Elseの分岐図をノートに書くべき理由として最も重要なものはどれか。', '日中の判断を全て「計画の実行」に変え、地図なしで歩く状態を避けるため', 'SNSで共有して他者の意見を聞くため', '過去のトレード記録として保存するため', 'エントリーのタイミングを秒単位で指定するため', 1, '分岐図をノートに書くことで、日中のすべての判断が「計画の実行」になる。分岐図がない状態は「地図なしで知らない街を歩く」のと同じであり、感情に流されやすくなる。', false, 4),
(59, '「If B：価格がZBに到達したが、トリガーが出ない」の場合、見送りに切り替える具体的な目安はどれか。', '10本のローソク足が経過してもトリガーが出ない場合', '2本のローソク足以内にトリガーが出ない場合', '1時間経ってもトリガーが出ない場合', '出来高が減少し始めた場合', 2, 'ゾーン到達後に2本のローソク足以内にトリガーが出なければ見送りに切り替える。いつまでも待ち続けると「待つ」ことが「執着」に変わるため、明確な期限を設定する。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(60, 'ケーススタディで、メインシナリオ通りの展開（If A）になった場合の対応として正しいものはどれか。', '利確目標を延ばしてさらに利益を狙う', 'メインシナリオの利確目標を手前に変更して確実に利益を確保する', 'メインシナリオ通りにエントリーし、計画通りの損切り・利確を実行する', 'サブシナリオも同時にエントリーする', 3, 'If A（価格がZBに到達＋トリガーが出た）は最も理想的な展開。メインシナリオを計画通りに実行し、損切り・利確も事前に設計した通りに処理する。', false, 1),
(60, 'ケーススタディで、ZBに到達したがトリガーが出ずに価格が反対方向に動いた（If B）場合、やってはいけないことはどれか。', 'トリガーなしにゾーン到達だけでエントリーすること', '次のゾーンまで待機すること', 'アラートを再設定すること', '見送り判断を下すこと', 1, 'If Bの場合、「トリガーなしにゾーン到達だけでエントリー」してはならない。三位一体の確認（場所×足×出来高）を満たさないエントリーは確度が低く、損失の原因になる。', false, 2),
(60, 'メインのZBを下抜け→サブに移行（If C）したケーススタディにおいて、サブシナリオでトリガーが出なかった場合の正しい対応はどれか。', 'サブシナリオの損切りラインを広げる', 'ノートレードにする', '別の時間足でトリガーを探す', '逆方向にエントリーする', 2, 'サブに移行した後もトリガーが出なければノートレードにする。無理にエントリーを探すと感情が介入し、判断の質が下がる。「やらない」という選択も立派なトレード判断。', false, 3),
(60, '全シナリオが無効化（If D）された場合のケーススタディで、「撤退」が賢い判断とされる理由は何か。', '損失が確定するので税金対策になるから', '全シナリオが無効化されることは通常1年に1回しか起こらないから', '無理に新しいシナリオを作ると焦りからバイアスのかかった分析になるから', '撤退すれば必ず翌日に大きな利益のチャンスが来るから', 3, '全シナリオが無効化されたときに無理に新しいシナリオを作ろうとすると、焦りから確証バイアス等が働き、質の低い分析になりやすい。その日は休んで翌日に冷静に再スタートするのが最善。', false, 4),
(60, 'FOMCの結果が想定と大きく異なり、市場が急変したケーススタディでの対応として正しいものはどれか。', '直後にメインシナリオを修正して即座にエントリーする', '値動きが落ち着く（1〜2時間後）まで待ち、環境認識を再構築してから判断する', 'FOMCの結果に関わらず、もとのシナリオをそのまま実行する', '損切りラインを外してポジションを維持する', 2, '重要指標でファンダメンタルズの前提が変わった場合、全シナリオを一時停止し、値動きが落ち着いてから環境認識を再構築する。慌てて飛び乗るのは最も危険な対応である。', false, 5);
INSERT INTO quizzes (chapter_id, question, choice_1, choice_2, choice_3, choice_4, correct_answer, explanation, available_for_light, sort_order) VALUES
(61, 'シナリオ管理シートにおいて、メインシナリオとサブシナリオはどのタイミングで設計すべきか。', 'メインシナリオが崩れてからサブを設計する', 'エントリー後にサブを設計する', '週に1回、週次レビューのときに設計する', '朝のルーティンで同時に設計する', 4, 'ルール1として、メインとサブは必ず「同時に」設計する。メインだけ先に作ってサブを後回しにすると、結局リアルタイムでサブを考えることになり感情が介入する。', false, 1),
(61, 'シナリオ管理の3つのルールのうち、「エントリー後にシナリオを変更しない」理由は何か。', '変更すると税金の計算が複雑になるから', '変更するとスプレッドが広がるから', 'エントリー後の変更は100%感情によるものだから', '変更するとブローカーのシステムエラーが起きるから', 3, 'エントリー後に条件が変わったように見えても、それはポジションを持った心理状態による認知の歪みの可能性が高い。エントリー後のシナリオ変更は100%感情に由来すると考えてよい。', false, 2),
(61, 'シナリオ管理シートで1日に管理すべきシナリオの上限はいくつか。', '10通貨ペアまで', '5通貨ペアまで', '制限はない', '最大2通貨ペアまで', 4, '1日に管理するシナリオは最大2通貨ペアまで。3つ以上になると管理が行き届かなくなり、判断の質が下がる。少ないペアに集中することで精度の高いトレードが可能になる。', false, 3),
(61, 'シナリオ管理シートの朝のルーティンに必要な追加時間はどの程度か。', '約5分', '約1時間', '約30分', '追加時間は不要', 1, '朝のルーティンに5分追加するだけで、メイン＋サブの「2本立て」シナリオが完成する。この5分が日中の迷いを全て消し、判断を「計画の実行」に変えてくれる。', false, 4),
(61, 'シナリオ管理シートを1週間続けるとどのような変化が起きると期待されるか。', 'エントリー回数が3倍に増える', 'チャートを開いた瞬間に「今日のIf-Aはここ、If-Cはここ」と頭に浮かぶようになる', 'すべてのトレードで勝てるようになる', '環境認識が不要になる', 2, '1週間続けると、シナリオの分岐構造が身体に染み込み、チャートを開いた瞬間に条件分岐が自然と思い浮かぶようになる。これは準備が習慣化された証拠である。', false, 5);
